-- Generated by scripts/build-questions-seed.mjs
-- Idempotent: deletes existing rows before insert.
begin;
delete from practice_questions;
insert into practice_questions (external_key, subtest, topic_id, difficulty, stem, choices, correct_index, explanation, active, status) values
  ('GS-1', 'GS', 'gs.life-science', 2, 'Which organ is primarily responsible for filtering waste products from the blood and producing urine?', '["Liver","Kidney","Pancreas","Spleen"]'::jsonb, 1, 'The kidneys filter nitrogen-rich waste and excess water from the blood and excrete them as urine. Each kidney contains roughly a million nephrons that do this filtering work. The liver also processes blood, but its job is detoxifying chemicals, breaking down old red cells, and metabolizing nutrients into bile and proteins, not making urine. The pancreas produces digestive enzymes and the hormone insulin. The spleen filters old red blood cells and stores immune cells but does not produce urine. Urine production is the kidney''s defining function.', true, 'trusted'),
  ('GS-2', 'GS', 'gs.physical-science', 2, 'Water (H₂O) is best classified as which of the following?', '["An element","A compound","A mixture","An isotope"]'::jsonb, 1, 'A compound is two or more different elements chemically bonded in a fixed ratio, which is exactly what H₂O is: hydrogen and oxygen locked at 2 to 1 by covalent bonds. An element contains only one kind of atom, so water cannot qualify because it holds two. A mixture is a physical blend whose components keep their own identities and can be separated by physical means, like salt water or air, but the H and O in water cannot be separated that way. An isotope describes versions of one element with different neutron counts, not a multi-element substance.', true, 'trusted'),
  ('GS-3', 'GS', 'gs.earth-space-science', 2, 'Which layer of Earth''s atmosphere contains the ozone layer that absorbs most of the sun''s ultraviolet radiation?', '["Troposphere","Mesosphere","Stratosphere","Thermosphere"]'::jsonb, 2, 'The stratosphere sits roughly 10 to 50 kilometers above the surface, and within it the ozone layer absorbs most incoming UV radiation. The troposphere is the bottom layer where weather happens and airliners cruise; it lacks the ozone concentration. The mesosphere is above the stratosphere and is where meteors burn up. The thermosphere is higher still and hosts auroras and the International Space Station, but it does not hold ozone. Pairing ozone with the wrong neighboring layer (mesosphere or troposphere) is the typical slip.', true, 'trusted'),
  ('AR-1', 'AR', 'ar.rate-distance-time', 2, 'A car travels at 55 miles per hour. How many miles will it travel in 3 hours and 30 minutes?', '["165 miles","182.5 miles","192.5 miles","198 miles"]'::jsonb, 2, '3 hours 30 minutes = 3.5 hours. Distance = 55 × 3.5 = 192.5 miles.', true, 'trusted'),
  ('AR-2', 'AR', 'ar.percent', 2, 'A store marks up an item by 40% from its wholesale cost of $35. What is the retail selling price?', '["$14.00","$45.50","$49.00","$52.50"]'::jsonb, 2, 'Markup = 40% × $35 = $14. Retail price = $35 + $14 = $49.00.', true, 'trusted'),
  ('AR-3', 'AR', 'ar.ratio-proportion', 2, 'A recipe calls for flour and sugar in a ratio of 5:2. If you use 20 cups of flour, how many cups of sugar are needed?', '["4 cups","6 cups","8 cups","10 cups"]'::jsonb, 2, 'Set sugar/flour = 2/5, so sugar = (2/5) × 20 = 8 cups. Choice 4 cups uses the difference between ratio parts (5 − 2 = 3) and applies it loosely, then halves the answer. Choice 6 cups assumes the ratio means 2 cups of sugar for every 6 of flour, misreading the colon as a one-step gap rather than a multiplicative ratio. Choice 10 cups halves the 20 cups of flour, ignoring the 5:2 relationship and treating the ratio as if it were 2:1.', true, 'trusted'),
  ('AR-4', 'AR', 'ar.percent', 2, 'A soldier earns $2,400 per month and saves 15% of that amount. After 6 months, how much has the soldier saved?', '["$1,440","$2,160","$2,400","$3,600"]'::jsonb, 1, 'Monthly savings = 15% × $2,400 = $360. Over 6 months: $360 × 6 = $2,160.', true, 'trusted'),
  ('WK-1', 'WK', 'wk.synonyms', 1, 'ARID most nearly means:', '["Damp","Stormy","Dry","Fertile"]'::jsonb, 2, 'Arid means extremely dry, with little or no rainfall, as in ''the arid desert of southern Arizona received only four inches of rain last year.'' Damp is the direct antonym, naming wetness rather than dryness. Stormy is a sound-association trap, drawing on the weather frame but referring to active turbulent weather, not the absence of moisture. Fertile is a secondary antonym, since arid land is typically infertile, but fertility is about productivity, not water content directly. Only Dry captures the core meaning of arid.', true, 'trusted'),
  ('WK-2', 'WK', 'wk.synonyms', 2, 'PRUDENT most nearly means:', '["Reckless","Cautious","Generous","Stubborn"]'::jsonb, 1, 'Prudent means showing careful thought and good judgment about future consequences, as in ''it was prudent to refuel before crossing the desert.'' Reckless is the direct antonym, naming heedless risk-taking. Generous overlaps with prudence as a positive trait but describes giving freely, a separate virtue. Stubborn is a register trap: a prudent person holds firm on careful reasoning, but stubbornness refuses to budge regardless of reasoning. Cautious is the dominant synonym, sharing both the forward-looking concern and the avoidance of risk.', true, 'trusted'),
  ('WK-3', 'WK', 'wk.synonyms', 1, 'CONCISE most nearly means:', '["Wordy","Unclear","Brief","Detailed"]'::jsonb, 2, 'Concise means expressing information in a small number of well-chosen words, as in ''her concise summary fit on one index card.'' Wordy is the direct antonym, naming excess language. Unclear is a register trap, since concise writing is often very clear, not muddled. Detailed is a partial-overlap trap: a concise message can include essentials, but detailed implies thoroughness and length, the opposite of concise compression. Brief is the dominant synonym, sharing the core idea of short and to the point.', true, 'trusted'),
  ('WK-4', 'WK', 'wk.synonyms', 2, 'OMINOUS most nearly means:', '["Cheerful","Threatening","Ordinary","Surprising"]'::jsonb, 1, 'Ominous means giving the impression that something bad is about to happen, as in ''the ominous clouds rolling in promised a violent storm.'' Cheerful is the direct antonym, naming brightness rather than dread. Ordinary is a register trap, since ominous signals warn of the unusual and dangerous, not the routine. Surprising is a partial-overlap trap: an ominous event may startle, but the defining quality is foreboding menace, not novelty. Threatening is the dominant synonym, sharing the sense of impending harm.', true, 'trusted'),
  ('PC-1', 'PC', 'pc.main-idea', 2, 'Read the following passage and answer the question.

"Solar panels convert sunlight directly into electricity using photovoltaic cells. Unlike fossil fuels, solar energy produces no emissions during operation, making it one of the cleanest energy sources available."

What is the main idea of this passage?', '["Fossil fuels are harmful to the environment.","Solar panels require no maintenance.","Solar energy is a clean electricity source that uses photovoltaic cells.","Photovoltaic cells are expensive to manufacture."]'::jsonb, 2, 'Both sentences work together to make one point. The first defines how solar panels operate ("convert sunlight directly into electricity using photovoltaic cells"), and the second adds the clean-energy claim ("no emissions during operation, making it one of the cleanest energy sources available"). Choice C captures both halves. Choice A treats the brief mention of fossil fuels as the topic when fossil fuels appear only as a comparison point. Choice B invents maintenance, which the passage never discusses. Choice D introduces cost, which is also absent. Both wrong-direction choices add information the text does not provide.', true, 'trusted'),
  ('PC-2', 'PC', 'pc.inference', 2, 'Read the following passage and answer the question.

"The base commander issued new physical fitness standards requiring all personnel to complete a 2-mile run in under 18 minutes. Soldiers who fail to meet the standard will be enrolled in a remedial training program."

What can be inferred about soldiers who complete the run in exactly 18 minutes?', '["They will receive an award.","They will be enrolled in remedial training.","They have exceeded the standard.","They will be exempt from future tests."]'::jsonb, 1, 'The standard is "under 18 minutes," and "soldiers who fail to meet the standard will be enrolled in a remedial training program." Exactly 18:00 is not under 18:00, so the runner fails the standard and lands in remedial training. Choice A invents an award the passage never mentions. Choice C reverses the math by treating a tie as exceeding the standard. Choice D goes beyond what the passage supports, since nothing in the text discusses exemptions from future tests. Only B follows from the passage''s wording without adding information.', true, 'trusted'),
  ('PC-3', 'PC', 'pc.detail-recall', 2, 'Read the following passage and answer the question.

"Dehydration impairs both physical and cognitive performance. Even a 2% loss of body water can reduce a person''s ability to concentrate and make decisions. Military personnel operating in hot climates must monitor fluid intake closely."

According to the passage, what effect does mild dehydration have?', '["It causes permanent cognitive damage.","It has no effect below 5% fluid loss.","It reduces the ability to concentrate and make decisions.","It only affects physical performance, not mental performance."]'::jsonb, 2, 'The passage states directly that "even a 2% loss of body water can reduce a person''s ability to concentrate and make decisions." Choice C reproduces that wording almost verbatim. Choice A overreaches by adding "permanent," a claim the passage never makes. Choice B contradicts the passage outright, since 2% is below 5% and the text confirms an effect at that level. Choice D contradicts the opening line, which says dehydration impairs both physical and cognitive performance. The keyed answer is the only one the text actually supports.', true, 'trusted'),
  ('MK-1', 'MK', 'mk.geometry', 2, 'A rectangular room measures 14 feet long and 9 feet wide. What is the area of the room?', '["46 square feet","92 square feet","126 square feet","132 square feet"]'::jsonb, 2, 'Area of a rectangle = length × width = 14 × 9 = 126 square feet.', true, 'trusted'),
  ('MK-2', 'MK', 'mk.algebra-linear', 1, 'Solve for x: 3x − 7 = 14', '["x = 3","x = 5","x = 7","x = 9"]'::jsonb, 2, 'Isolate the variable in two steps. Add 7 to both sides to undo the subtraction: 3x = 21. Divide both sides by 3 to undo the multiplication: x = 7. The choice x = 3 comes from dividing the original 14 by 3 and ignoring the −7 entirely. The choice x = 5 comes from subtracting 7 from 14 first (14 − 7 = 7), then dividing the wrong direction. The choice x = 9 comes from sign confusion, treating −7 as +7 and computing (14 − 7)÷3 backwards or 21÷3 with an extra add.', true, 'trusted'),
  ('MK-3', 'MK', 'mk.exponents-polynomials', 1, 'What is the value of 2⁵?', '["10","16","25","32"]'::jsonb, 3, 'An exponent counts how many times the base multiplies itself. 2⁵ = 2 × 2 × 2 × 2 × 2 = 32. Build it stepwise: 2×2 = 4, ×2 = 8, ×2 = 16, ×2 = 32. The choice 10 comes from confusing exponentiation with multiplication and computing 2 × 5. The choice 16 is 2⁴, one factor short. The choice 25 comes from swapping base and exponent and computing 5² instead of 2⁵.', true, 'trusted'),
  ('MK-4', 'MK', 'mk.fractions-decimals', 2, 'What is ³⁄₄ divided by ³⁄₈?', '["½","1","2","9⁄32"]'::jsonb, 2, 'Dividing by a fraction means multiplying by its reciprocal: ³⁄₄ × ⁸⁄₃ = 24⁄12 = 2.', true, 'trusted'),
  ('EI-1', 'EI', 'ei.ohms-law-power', 2, 'A circuit has a voltage of 12 volts and a resistance of 4 ohms. According to Ohm''s Law, what is the current flowing through the circuit?', '["0.33 amperes","3 amperes","8 amperes","48 amperes"]'::jsonb, 1, 'Ohm''s Law solves for current as I = V / R. Plug in: I = 12 V / 4 Ω = 3 A. The answer is 3 amperes. Choice A (0.33 A) inverts the formula and computes R / V = 4 / 12. Choice C (8 A) subtracts instead of dividing (12 minus 4). Choice D (48 A) multiplies V by R, which is the calculation for a totally different relationship and ignores that current is voltage divided by resistance, not the product.', true, 'trusted'),
  ('EI-2', 'EI', 'ei.circuit-types', 2, 'In a series circuit with three light bulbs, one bulb burns out. What happens to the other two bulbs?', '["They burn brighter.","They continue operating normally.","They also go out.","They flicker but stay on."]'::jsonb, 2, 'A series circuit has one continuous loop, so current must pass through every bulb. When one filament opens, the loop breaks and current stops everywhere. All remaining bulbs go dark. Choice A (brighter) confuses series with parallel, where losing one branch can shift current. Choice B (normal operation) describes parallel wiring, where each bulb sits on its own independent path. Choice D (flicker but stay on) imagines a partial connection, but an open filament is a hard break, not an intermittent contact.', true, 'trusted'),
  ('EI-3', 'EI', 'ei.components-devices', 1, 'What unit is used to measure electrical resistance?', '["Volt","Ampere","Watt","Ohm"]'::jsonb, 3, 'Resistance is measured in ohms, symbol Ω. The four core electrical units pair one-to-one: volts measure voltage (electrical pressure), amperes measure current (flow rate of charge), watts measure power (energy per second), and ohms measure resistance (opposition to flow). Choice A (volt) confuses resistance with the driving voltage from Ohm''s Law. Choice B (ampere) confuses it with the current that resistance opposes. Choice C (watt) measures power dissipated in a resistor, not the resistance itself.', true, 'trusted'),
  ('AS-1', 'AS', 'as.hand-tools', 2, 'Which tool is best suited for tightening a bolt that is in a recessed or hard-to-reach location?', '["Open-end wrench","Socket wrench with extension","Adjustable pliers","Torque screwdriver"]'::jsonb, 1, 'A socket wrench accepts extensions and universal joints, letting you reach a bolt buried inside a recess where a straight-handled tool cannot sit square on the head. An open-end wrench needs side clearance to slide onto the flats and room to swing, which a recessed bolt does not give you. Adjustable pliers grip by squeezing the head and will round off the corners under any real torque. A torque screwdriver is for screw heads with a driver bit and is meant for measuring torque on small fasteners, not for reaching into deep cavities.', true, 'trusted'),
  ('AS-2', 'AS', 'as.vehicle-systems', 2, 'What is the primary function of a vehicle''s radiator?', '["Filter engine oil","Regulate fuel mixture","Dissipate heat from the engine coolant","Reduce exhaust emissions"]'::jsonb, 2, 'The radiator is a heat exchanger. Hot coolant pumped from the engine flows through narrow tubes and fins, and air moving across those fins carries the heat away before the coolant returns to the block. Filtering oil is the oil filter''s job in the lubrication system, which is a separate circuit from the cooling system. Fuel mixture is metered by the injectors or carburetor, not by the cooling components. Exhaust emissions are cleaned by the catalytic converter downstream of the engine, again a different system entirely.', true, 'trusted'),
  ('AS-3', 'AS', 'as.shop-safety', 1, 'Before operating a power saw in a shop, you should FIRST:', '["Test the blade on scrap wood","Put on appropriate eye protection","Plug in the saw and let it warm up","Check the sharpness of the blade by touch"]'::jsonb, 1, 'Eye protection goes on before anything else because flying chips, sawdust, and a thrown blade tooth can reach your face the instant the saw spins up. Testing the blade on scrap and checking for a sharp blade are reasonable steps later in the sequence, but they expose your eyes to hazards if you do them with no PPE on. Letting a corded saw "warm up" plugged in is not a real practice and leaves a live tool unattended. The rule is gear up first, then handle the tool.', true, 'trusted'),
  ('MC-1', 'MC', 'mc.levers-pulleys', 2, 'A 10-pound weight is placed 6 feet from the fulcrum of a lever. To balance it, how far from the fulcrum must a 15-pound weight be placed on the opposite side?', '["2 feet","4 feet","6 feet","9 feet"]'::jsonb, 1, 'Lever balance requires equal torques on both sides of the fulcrum: W1 x D1 = W2 x D2. Plug in: 10 lb x 6 ft = 15 lb x D2, so 60 = 15 x D2, and D2 = 4 feet. Choice A (2 feet) divides 6 by 3 instead of using the torque equation. Choice C (6 feet) keeps the same distance and ignores that the heavier weight needs a shorter arm. Choice D (9 feet) puts the heavier weight farther out, which would unbalance the lever further since 15 lb x 9 ft = 135 lb-ft, more than double the 60 lb-ft on the other side.', true, 'trusted'),
  ('MC-2', 'MC', 'mc.gears-wheels', 3, 'If a small gear with 10 teeth meshes with a large gear with 40 teeth, and the small gear rotates at 200 RPM, how fast does the large gear rotate?', '["25 RPM","50 RPM","100 RPM","800 RPM"]'::jsonb, 1, 'Meshing gears conserve linear tooth speed, so RPM is inversely proportional to tooth count: RPM_large = RPM_small x (teeth_small / teeth_large) = 200 x (10/40) = 50 RPM. Choice A (25 RPM) divides by 8 instead of 4, doubling the reduction. Choice C (100 RPM) only halves the speed, applying a 2:1 ratio instead of the actual 4:1. Choice D (800 RPM) inverts the formula and multiplies 200 by 4, treating the large gear as the faster one when in fact the larger gear always turns slower than the smaller one it meshes with.', true, 'trusted'),
  ('MC-3', 'MC', 'mc.forces-friction', 2, 'A 200-pound crate is resting on a flat surface. If you push it horizontally with a force of 50 pounds and it does not move, what is the force of friction acting on the crate?', '["0 pounds","50 pounds","150 pounds","200 pounds"]'::jsonb, 1, 'Newton''s Second Law: if an object does not accelerate, the net force is zero. The crate is stationary, so static friction adjusts to exactly cancel the applied push. Friction = 50 pounds, opposite to the push. Choice A (0 pounds) ignores that something must be canceling the 50-pound push. Choice C (150 pounds) confuses friction with the difference between weight and applied force. Choice D (200 pounds) uses the full weight as the friction force, but weight acts vertically and is canceled by the normal force, not by horizontal friction. Static friction only equals what is needed to prevent motion, up to its maximum.', true, 'trusted'),
  ('AO-1', 'AO', 'ao.3d-visualization', 3, 'A flat piece of material is cut into four identical right triangles, each with legs of equal length. If all four triangles are arranged so their right-angle corners meet at a center point, what shape do they form?', '["A circle","A rectangle","A square","A hexagon"]'::jsonb, 2, 'Each right triangle has two equal legs and a hypotenuse. With the right angles meeting at a center, the four 90 degree corners account for the full 360 degrees around the point, and the equal legs line up edge to edge along four straight rays. The outer boundary is four equal hypotenuses meeting at right angles, which is a square. ''A circle'' tempts anyone picturing pie slices, but straight hypotenuses cannot trace a curve. ''A hexagon'' would require six pieces, not four. ''A rectangle'' is technically true but incomplete: equal sides make this the special-case rectangle called a square.', true, 'trusted'),
  ('AO-2', 'AO', 'ao.paper-folding-nets', 1, 'A rectangular piece of paper is folded in half along its longest axis, then folded in half again along the same axis. When unfolded, how many equal sections does the paper have?', '["2","3","4","6"]'::jsonb, 2, 'Folding in half once produces 2 layers, leaving 1 crease and 2 sections. Folding the same axis again doubles the layer count to 4 and adds a second crease parallel to the first, splitting each prior section in two. When unfolded the paper shows 3 parallel creases and 4 equal strips. Choosing ''2'' counts only the first fold. Choosing ''3'' counts creases instead of sections (a classic off-by-one). Choosing ''6'' confuses doubling with adding, as if each fold added 3 new sections. Doubling, not adding, is the rule for parallel folds along the same axis.', true, 'trusted'),
  ('AO-3', 'AO', 'ao.spatial-counting', 4, 'A cube is painted red on all six faces and then cut into 27 equal smaller cubes (a 3×3×3 grid). How many of the small cubes have paint on exactly two faces?', '["6","8","12","24"]'::jsonb, 2, 'Two-face cubes sit along the edges of the large cube but not at the corners (corners would be three-face) and not at the centers of faces (one-face). A cube has 12 edges. In a 3x3x3 grid, each edge has 3 small cubes along it: 2 corners plus 1 middle. Only that middle position counts as a two-face cube, giving 12 edges times 1 cube each = 12. The choice ''8'' is the corner count (three-face cubes), a common substitution. ''6'' is the count of face centers (one-face cubes). ''24'' double-counts edges or confuses with the 24 edge-positions on the surface.', true, 'trusted'),
  ('GS-4', 'GS', 'gs.earth-space-science', 2, 'Which type of rock is formed when molten magma cools and solidifies?', '["Sedimentary","Metamorphic","Igneous","Organic"]'::jsonb, 2, 'Igneous rock forms when magma (underground) or lava (surface) cools and crystallizes. Granite is the classic slow-cooled intrusive example; basalt is the fast-cooled extrusive one. Sedimentary rock forms from pressed and cemented sediments like sandstone or limestone and never involves melting. Metamorphic rock starts as another rock that is reshaped by heat and pressure without fully melting, producing slate or marble. Organic is not one of the three official rock-cycle categories, which makes it a distractor designed to look plausible next to the real three.', true, 'trusted'),
  ('GS-5', 'GS', 'gs.life-science', 2, 'Which of the following best describes the function of red blood cells?', '["Fight infection by producing antibodies","Transport oxygen throughout the body","Regulate blood clotting","Produce hormones"]'::jsonb, 1, 'Red blood cells carry hemoglobin, an iron-rich protein that grabs oxygen in the lungs and releases it to tissues, then carries some carbon dioxide back. Producing antibodies is the job of white blood cells, specifically B lymphocytes. Clotting is handled by platelets along with clotting factors in plasma. Hormones come from endocrine glands like the thyroid, adrenal, and pituitary, not from blood cells. Confusing red cells with white cells or platelets is the standard trap because all three live in blood and look similar at first glance.', true, 'trusted'),
  ('GS-6', 'GS', 'gs.physics-mechanics', 2, 'Newton''s Third Law of Motion states that for every action there is:', '["An equal but delayed reaction","A greater and opposite reaction","An equal and opposite reaction","A proportional and parallel reaction"]'::jsonb, 2, 'Newton''s Third Law says forces come in pairs that are equal in magnitude and opposite in direction, acting on two different bodies. Push on a wall and the wall pushes back on you with the same force. A rocket pushes exhaust gas down and the gas pushes the rocket up by the same amount. The forces act at the same instant, never delayed, which rules out the first choice. They are equal, never greater, which kills the second. Parallel and proportional confuses Third Law with the F=ma scaling of the Second Law.', true, 'trusted'),
  ('AR-5', 'AR', 'ar.word-problems', 3, 'A tank holds 500 gallons of water. It drains at a rate of 25 gallons per minute and fills at 10 gallons per minute simultaneously. Starting with a full tank, how many minutes will it take to empty?', '["20 minutes","25 minutes","33 minutes","50 minutes"]'::jsonb, 2, 'Net drain rate = 25 − 10 = 15 gal/min, so time = 500 ÷ 15 ≈ 33.3 minutes, which rounds to 33. Choice 20 minutes divides 500 by 25, using the drain rate alone and ignoring the simultaneous inflow. Choice 25 minutes splits the difference between the two rates without combining them into a net rate. Choice 50 minutes divides 500 by 10, using only the fill rate as if the tank were filling, the exact opposite of the scenario.', true, 'trusted'),
  ('AR-6', 'AR', 'ar.arithmetic-fundamentals', 1, 'A platoon of 40 soldiers must carry 480 pounds of equipment equally. How many pounds does each soldier carry?', '["10 pounds","12 pounds","14 pounds","16 pounds"]'::jsonb, 1, 'Divide total load by soldiers: 480 ÷ 40 = 12 pounds each. Choice 10 pounds rounds 480 down to 400 to avoid the long division. Choice 14 pounds estimates between 10 and 16 without doing the division. Choice 16 pounds divides 480 by 30 instead of 40, miscounting the platoon size.', true, 'trusted'),
  ('AR-7', 'AR', 'ar.percent', 2, 'A shirt originally priced at $60 is on sale for 25% off. What is the sale price?', '["$15","$40","$45","$50"]'::jsonb, 2, 'Discount = 25% × $60 = $15. Sale price = $60 − $15 = $45.', true, 'trusted'),
  ('AR-8', 'AR', 'ar.word-problems', 4, 'Two workers can paint a room in 6 hours working together. If one worker can complete the job alone in 10 hours, how long would the second worker take alone?', '["12 hours","15 hours","16 hours","20 hours"]'::jsonb, 1, 'Worker 2''s rate = combined rate − Worker 1''s rate = 1/6 − 1/10 = 5/30 − 3/30 = 2/30 = 1/15, so Worker 2 alone takes 15 hours. Choice 12 hours averages 6 and 10 incorrectly, splitting the difference between team and Worker 1 times. Choice 16 hours adds the two stated times (10 + 6) instead of subtracting rates. Choice 20 hours simply doubles 10, assuming Worker 2 is half as fast without using the combined-rate equation.', true, 'trusted'),
  ('WK-5', 'WK', 'wk.synonyms', 2, 'TENACIOUS most nearly means:', '["Fragile","Persistent","Timid","Generous"]'::jsonb, 1, 'Tenacious means holding firmly to a purpose, position, or grip, as in ''the tenacious investigator refused to drop the cold case.'' Fragile is the direct antonym, describing a weak hold rather than a firm grip. Timid names a trait about willingness to engage with risk, which is orthogonal to tenacity (a timid person can still be tenacious about a goal they care about quietly). Generous is unrelated to grip or persistence; it names willingness to share. Persistent is the dominant synonym, sharing the core idea of refusing to let go of a goal or effort over time.', true, 'trusted'),
  ('WK-6', 'WK', 'wk.synonyms', 2, 'AMBIGUOUS most nearly means:', '["Certain","Unclear","Ambitious","Honest"]'::jsonb, 1, 'Ambiguous means having more than one possible meaning, as in ''his ambiguous answer could be read as yes or no.'' Certain is the direct antonym, naming single clear meaning. Ambitious is a sound-alike trap that shares the first four letters but comes from a different root (ambi-/ambit, going around for goals), not from ambi-/ambig (driving both ways). Honest overlaps with clarity as a virtue but refers to truthfulness, not whether the statement has one interpretation. Unclear is the dominant synonym.', true, 'trusted'),
  ('WK-7', 'WK', 'wk.synonyms', 1, 'VALIDATE most nearly means:', '["Deny","Confirm","Improve","Replace"]'::jsonb, 1, 'To validate means to establish or check that something is accurate, sound, or legitimate, as in ''the supervisor validated the inspection report before signing.'' Deny is the direct antonym, naming rejection rather than verification. Improve is a partial-overlap trap, since validation can lead to improvements, but the act itself is confirming current accuracy, not upgrading quality. Replace is a register trap, suggesting swapping out rather than approving. Confirm is the dominant synonym, sharing the meaning of certifying that something holds up.', true, 'trusted'),
  ('WK-8', 'WK', 'wk.synonyms', 2, 'AUSTERE most nearly means:', '["Luxurious","Severe","Colorful","Warm"]'::jsonb, 1, 'Austere means stern, plain, and lacking comfort or ornament, as in ''the austere monastery had bare walls and cold floors.'' Luxurious is the direct antonym, naming richness and indulgence. Colorful is a partial antonym focused on visual decoration; austere settings are typically muted. Warm is a register trap, since austere implies emotional coldness and physical sparseness alike. Severe is the dominant synonym, sharing the connotation of unforgiving strictness in style, tone, or living conditions.', true, 'trusted'),
  ('PC-4', 'PC', 'pc.inference', 2, 'Read the following passage and answer the question.

"The bald eagle was removed from the Endangered Species List in 2007, a success story for wildlife conservation. Once nearly extinct due to hunting and pesticide use, the population rebounded after DDT was banned in 1972 and legal protections were enacted."

What was the primary cause of the bald eagle''s recovery?', '["Captive breeding programs introduced thousands of new birds.","A ban on DDT and legal protections allowed the population to rebound.","Bald eagles adapted to living in urban environments.","Congress funded a national eagle relocation program."]'::jsonb, 1, 'The passage attributes recovery to two specific causes: "the population rebounded after DDT was banned in 1972 and legal protections were enacted." Choice B names both. Choice A invents captive breeding, which is never mentioned. Choice C invents urban adaptation, also absent. Choice D invents a relocation program. Each wrong choice introduces a plausible-sounding conservation mechanism that the passage simply does not discuss, while B reflects the exact causal pair the text provides.', true, 'trusted'),
  ('PC-5', 'PC', 'pc.detail-recall', 2, 'Read the following passage and answer the question.

"Hypothermia occurs when the body loses heat faster than it can produce it, causing core body temperature to fall below 95°F. Symptoms progress from shivering and confusion to loss of coordination and, eventually, unconsciousness. Immediate warming and medical attention are critical."

According to the passage, which symptom appears first?', '["Unconsciousness","Loss of coordination","Shivering and confusion","Cardiac arrest"]'::jsonb, 2, 'The passage lays out a sequence: "Symptoms progress from shivering and confusion to loss of coordination and, eventually, unconsciousness." Shivering and confusion sit at the start of that progression. Choice A names the final stage. Choice B names the middle stage. The wrong choices paraphrase real passage details but answer the wrong question, picking later stages instead of the first. Choice D invents cardiac arrest, which the text never lists. Only C matches the symptom the passage places at the beginning of the progression.', true, 'trusted'),
  ('PC-6', 'PC', 'pc.detail-recall', 1, 'Read the following passage and answer the question.

"A convoy must maintain a 100-meter interval between vehicles at all times. Closing the gap increases the risk of collision if the lead vehicle stops suddenly. Drivers are responsible for maintaining their own interval regardless of road conditions."

Who is responsible for maintaining the correct vehicle interval?', '["The convoy commander","The lead vehicle driver","Each individual driver","The vehicle navigator"]'::jsonb, 2, 'The passage states plainly that "drivers are responsible for maintaining their own interval regardless of road conditions." That phrasing places the duty on every driver individually. Choice A picks a military role the passage never assigns. Choice B uses a real passage element (the lead vehicle) but treats it as the responsible party when the text says following drivers maintain the gap. Choice D invents a navigator, who is not mentioned at all. C is the only choice that reflects the assignment of responsibility the passage actually makes.', true, 'trusted'),
  ('MK-5', 'MK', 'mk.geometry', 1, 'What is the perimeter of a square with a side length of 11 inches?', '["22 inches","33 inches","44 inches","121 inches"]'::jsonb, 2, 'Perimeter of a square = 4 × side = 4 × 11 = 44 inches.', true, 'trusted'),
  ('MK-6', 'MK', 'mk.algebra-linear', 2, 'Solve for y: 5y + 3 = 2y + 18', '["y = 3","y = 5","y = 7","y = 9"]'::jsonb, 1, 'Subtract 2y from both sides: 3y + 3 = 18. Subtract 3: 3y = 15. Divide: y = 5.', true, 'trusted'),
  ('MK-7', 'MK', 'mk.geometry', 2, 'A right triangle has legs measuring 6 cm and 8 cm. What is the length of the hypotenuse?', '["7 cm","10 cm","12 cm","14 cm"]'::jsonb, 1, 'By the Pythagorean theorem: c² = 6² + 8² = 36 + 64 = 100. c = √100 = 10 cm.', true, 'trusted'),
  ('MK-8', 'MK', 'mk.fractions-decimals', 1, 'What is 15% of 240?', '["30","36","40","42"]'::jsonb, 1, 'Convert the percent to a decimal and multiply: 15% = 0.15, so 0.15 × 240 = 36. Cross-check by computing 10% of 240 = 24, then 5% = 12, sum = 36. The choice 30 comes from using 12.5% (an off-by-one in the percent). The choice 40 comes from misreading 15% as 1/6 of 240. The choice 42 comes from adding 12 + 30 or other small slips in mental math.', true, 'trusted'),
  ('EI-4', 'EI', 'ei.components-devices', 2, 'Which component in an electrical circuit allows current to flow in only one direction?', '["Resistor","Capacitor","Diode","Transformer"]'::jsonb, 2, 'A diode is a semiconductor with a p-n junction that conducts when forward-biased and blocks current when reverse-biased, giving it one-way behavior. Rectifier bridges use this to turn AC into DC. Choice A (resistor) opposes current in both directions equally and is not polarity-sensitive. Choice B (capacitor) stores charge on plates and passes AC while blocking steady DC, but it has no preferred direction. Choice D (transformer) steps AC voltage up or down through induction and does not rectify direction at all.', true, 'trusted'),
  ('EI-5', 'EI', 'ei.ohms-law-power', 2, 'A 60-watt light bulb operates on a 120-volt circuit. What is the current drawn by the bulb?', '["0.25 amperes","0.5 amperes","2 amperes","7,200 amperes"]'::jsonb, 1, 'Use P = I × V and solve for current: I = P / V = 60 W / 120 V = 0.5 A. The bulb draws 0.5 amperes. Choice A (0.25 A) divides by 240 or applies the formula twice. Choice C (2 A) inverts the division and computes V / P = 120 / 60. Choice D (7,200 A) multiplies power by voltage (60 × 120), which has no physical meaning here because the power formula calls for division when current is unknown, not multiplication.', true, 'trusted'),
  ('EI-6', 'EI', 'ei.components-devices', 2, 'What is the purpose of a fuse in an electrical circuit?', '["Increase voltage to components","Store electrical charge","Protect the circuit by breaking if current exceeds a safe level","Regulate alternating current frequency"]'::jsonb, 2, 'A fuse contains a thin metal strip rated for a specific current. When current exceeds that rating, the strip melts and opens the circuit, cutting power before wires overheat or components burn. Choice A (increase voltage) describes a transformer or boost converter, not a protective device. Choice B (store charge) describes a capacitor, which holds energy on plates. Choice D (regulate AC frequency) describes oscillator or inverter circuitry. A fuse only opens; it does not modify voltage, store energy, or shape waveforms.', true, 'trusted'),
  ('AS-4', 'AS', 'as.vehicle-systems', 2, 'What does a vehicle''s alternator do while the engine is running?', '["Starts the engine by cranking it","Recharges the battery and powers electrical systems","Controls fuel injection timing","Regulates engine coolant temperature"]'::jsonb, 1, 'While the engine runs, a belt off the crankshaft spins the alternator, which generates electricity to recharge the battery and run the lights, ignition, fans, and accessories. Cranking the engine is the starter motor''s job, and it only operates for the few seconds it takes to fire the engine. Fuel injection timing is controlled by the engine control module reading crank and cam sensors. Coolant temperature is regulated by the thermostat and the cooling fan, not by anything in the charging system.', true, 'trusted'),
  ('AS-5', 'AS', 'as.hand-tools', 1, 'Which type of screwdriver is designed to fit a screw head with an X-shaped slot?', '["Flathead screwdriver","Torx screwdriver","Phillips screwdriver","Hex screwdriver"]'::jsonb, 2, 'A Phillips screwdriver has a cross-shaped tip that seats into the X-pattern recess on a Phillips screw head, giving four points of drive contact and resisting slip better than a flat blade. A flathead (slotted) screwdriver fits a single straight slot and will cam right out of a Phillips head. A Torx driver has a six-pointed star tip for Torx screws found on automotive trim and electronics. A hex driver, sometimes called an Allen key, fits the six-sided socket of a hex-head screw. Each tip belongs to its own screw family.', true, 'trusted'),
  ('AS-6', 'AS', 'as.maintenance-repair', 2, 'When should a vehicle''s engine oil be replaced most regularly, according to general maintenance practice?', '["Only when the oil pressure warning light activates","At every fuel fill-up","At intervals recommended by the manufacturer, typically based on mileage or time","Once per year regardless of mileage"]'::jsonb, 2, 'Manufacturers publish oil change intervals based on engineering tests of the oil, filter, and engine, and they express the interval as miles or months, whichever comes first. Waiting for the oil pressure warning light means the engine is already starving for lubrication and damage is happening. Changing oil at every fuel fill-up is wasteful and unnecessary. A flat once-a-year rule ignores how much the car was actually driven, so a high-mileage driver would run far past the safe interval. Following the owner''s manual schedule is the practical standard.', true, 'trusted'),
  ('MC-4', 'MC', 'mc.gears-wheels', 2, 'A wheel and axle system has a wheel with a radius of 12 inches and an axle with a radius of 3 inches. What is the mechanical advantage of this system?', '["2","3","4","6"]'::jsonb, 2, 'Mechanical advantage of a wheel-and-axle equals the wheel radius divided by the axle radius: MA = 12 / 3 = 4. The effort applied at the wheel''s rim travels a larger circle, while the axle moves a smaller circle with greater force. Choice A (2) halves the correct ratio, possibly confusing radius with diameter on only one side. Choice B (3) uses the axle radius alone as the answer. Choice D (6) appears to add the radii (12 + 3) and halve them, or otherwise mix dimensions. Only the radius ratio gives the correct mechanical advantage.', true, 'trusted'),
  ('MC-5', 'MC', 'mc.levers-pulleys', 2, 'A fixed pulley changes the direction of force but does NOT change the amount of force required. Which statement about a fixed pulley is correct?', '["It reduces the force needed by half.","It multiplies the force by the number of rope segments.","It redirects the force without any mechanical advantage.","It eliminates the effect of gravity on the load."]'::jsonb, 2, 'A fixed pulley has only one rope segment supporting the load, so its mechanical advantage equals 1. Its only function is to change the direction of the applied force, not its magnitude. Choice A (reduces force by half) describes a single movable pulley, which has MA = 2. Choice B (multiplies by rope segments) describes a block-and-tackle with multiple supporting strands. Choice D (eliminates gravity) is physically impossible; pulleys redistribute or redirect force but never cancel weight. Only choice C correctly identifies that the load still requires a pulling force equal to its weight.', true, 'trusted'),
  ('MC-6', 'MC', 'mc.forces-friction', 2, 'Which of the following changes would increase the pressure exerted by a block resting on a table?', '["Tilting the block at a 45-degree angle","Increasing the surface area in contact with the table","Placing the block on a smaller face so less area contacts the table","Moving the block to the center of the table"]'::jsonb, 2, 'Pressure equals force divided by contact area: P = F / A. With weight held constant, shrinking the area concentrates the same force onto fewer square inches and raises pressure. Choice A (tilting at 45 degrees) actually reduces the normal force on the table because part of the weight vector shifts off-axis, lowering pressure. Choice B (increasing surface area) spreads force over more area and decreases pressure, the opposite of what is asked. Choice D (moving the block) changes location only; both area and weight stay the same, so pressure is unchanged. Only reducing the contact face increases pressure.', true, 'trusted'),
  ('AO-4', 'AO', 'ao.paper-folding-nets', 2, 'A square piece of cardboard has a small square cut from each of its four corners. When the sides are folded up along the cut lines, what shape is formed?', '["A pyramid","An open-top box","A cylinder","A cone"]'::jsonb, 1, 'Cutting a small square from each corner separates the base from four side flaps. Folding the flaps up along the cut lines produces vertical walls on all four sides with the original middle square as the floor and no piece left to cap the top. That is the definition of an open-top box. ''A pyramid'' is the trap of imagining the flaps converging to a point, but square flaps fold up parallel to each other, never meeting at an apex. ''A cylinder'' and ''a cone'' require curved surfaces, which flat cardboard cannot produce by folding along straight lines.', true, 'trusted'),
  ('AO-5', 'AO', 'ao.3d-visualization', 2, 'A solid cylinder is sliced straight down through its center from top to bottom (a vertical cut through the axis). What shape is the cross-section?', '["Circle","Ellipse","Rectangle","Triangle"]'::jsonb, 2, 'A vertical cut through the axis of a cylinder slices it lengthwise, producing a flat face whose horizontal span equals the diameter and whose vertical span equals the height. That face is bounded by two straight parallel edges (the cut sides) and two straight parallel edges where the top and bottom circles were divided. Four straight sides at right angles make a rectangle. ''Circle'' is the cross-section of a horizontal cut perpendicular to the axis, not a vertical one. ''Ellipse'' is produced by an oblique slanted cut. ''Triangle'' has no path through a cylinder of any orientation.', true, 'trusted'),
  ('AO-6', 'AO', 'ao.spatial-counting', 3, 'Three identical equilateral triangles are placed so that one vertex of each meets at a common center point and the triangles do not overlap. What is the total interior angle at the center point?', '["180 degrees","240 degrees","270 degrees","360 degrees"]'::jsonb, 0, 'Each equilateral triangle has interior angles of 60 degrees. Three vertices meeting at the center contribute 3 times 60 degrees = 180 degrees of swept angle, which means the triangles cover only half of the space around the point. The remaining 180 degrees is uncovered. Selecting ''360 degrees'' applies the angles-around-a-point rule incorrectly; that total only applies when shapes fully tile the area around the point, and 60 degree corners cannot do that with just three pieces. ''240 degrees'' would require four triangles, not three. ''270 degrees'' has no geometric basis, possibly mixing in a right angle by mistake.', true, 'trusted'),
  ('GS-7', 'GS', 'gs.life-science', 2, 'Photosynthesis in plants primarily uses which two resources to produce glucose?', '["Oxygen and nitrogen","Carbon dioxide and water","Glucose and oxygen","Nitrogen and phosphorus"]'::jsonb, 1, 'Photosynthesis takes carbon dioxide pulled in through leaf stomata and water drawn up from the roots, then uses solar energy captured by chlorophyll to build glucose and release oxygen. Glucose and oxygen are the products, not the inputs, so picking them reverses the equation. Nitrogen and phosphorus matter for plant growth, but they are soil nutrients used in proteins and DNA, not the raw materials for sugar. The simple equation worth memorizing: 6CO₂ + 6H₂O + light → C₆H₁₂O₆ + 6O₂.', true, 'trusted'),
  ('GS-8', 'GS', 'gs.earth-space-science', 1, 'Which planet in our solar system is largest by diameter?', '["Saturn","Neptune","Jupiter","Uranus"]'::jsonb, 2, 'Jupiter is the largest planet at roughly 143,000 km in diameter, more than 11 Earths wide and over 300 Earths in mass. Saturn comes in second and is often confused for the biggest because of its prominent rings, which make it look visually huge in photos, but Saturn is actually smaller and far less dense than Jupiter. Uranus and Neptune are the ice giants and are much smaller, each only about four times Earth''s diameter. The mental shortcut: Jupiter is the king of the gas giants by size and mass.', true, 'trusted'),
  ('GS-9', 'GS', 'gs.physical-science', 2, 'In an acid-base reaction, the pH of a neutral solution is:', '["0","7","10","14"]'::jsonb, 1, 'The pH scale runs from 0 to 14, and 7 sits dead center as the neutral point where hydrogen-ion and hydroxide-ion concentrations are equal. Pure water is the standard example. A pH of 0 marks the strongest common acids like concentrated hydrochloric acid. A pH of 14 marks the strongest bases like concentrated sodium hydroxide. A pH of 10 is mildly basic (think milk of magnesia), not neutral. Each whole-number step represents a tenfold change in hydrogen-ion concentration, so the scale is logarithmic, not linear.', true, 'trusted'),
  ('AR-9', 'AR', 'ar.ratio-proportion', 2, 'If 5 pens cost $3.75, what is the cost of 8 pens at the same price?', '["$5.00","$5.60","$6.00","$6.25"]'::jsonb, 2, 'Price per pen = $3.75 ÷ 5 = $0.75. Cost of 8 pens = 8 × $0.75 = $6.00.', true, 'trusted'),
  ('AR-10', 'AR', 'ar.arithmetic-fundamentals', 2, 'A rectangular field is 120 yards long and 80 yards wide. What is its area in square yards?', '["4,800","8,400","9,600","10,400"]'::jsonb, 2, 'Area = length × width = 120 × 80 = 9,600 square yards. Choice 4,800 halves the answer, perhaps computing perimeter logic (2 × (120 + 80) = 400) and then estimating area from that. Choice 8,400 drops a hundreds digit during the multiplication, treating it as 12 × 7 instead of 12 × 8. Choice 10,400 adds an extra 800 from a stray carry during the multiplication.', true, 'trusted'),
  ('AR-11', 'AR', 'ar.rate-distance-time', 3, 'A train leaves a station at 9:00 AM traveling at 60 mph. A second train leaves the same station at 10:00 AM traveling in the same direction at 90 mph. At what time does the second train catch up to the first?', '["11:00 AM","12:00 PM","12:30 PM","1:00 PM"]'::jsonb, 1, 'Train 1''s head start at 10:00 AM is 60 miles, closing rate = 90 − 60 = 30 mph, so catch-up = 60 ÷ 30 = 2 hours after 10:00 AM, which is 12:00 PM. Choice 11:00 AM uses 90 mph as the closing rate, forgetting that Train 1 keeps moving forward. Choice 12:30 PM adds a 30-minute buffer for unstated startup. Choice 1:00 PM divides 60 by 20 instead of 30, miscalculating the speed gap between the trains.', true, 'trusted'),
  ('AR-12', 'AR', 'ar.ratio-proportion', 2, 'A map has a scale of 1 inch = 50 miles. Two cities are 3.5 inches apart on the map. What is the actual distance between them?', '["150 miles","175 miles","200 miles","225 miles"]'::jsonb, 1, 'Actual distance = inches × scale = 3.5 × 50 = 175 miles. Choice 150 miles rounds 3.5 down to 3 inches before multiplying. Choice 200 miles rounds 3.5 up to 4 inches. Choice 225 miles adds an extra half-scale unit (4.5 × 50), reading the half-inch as a full step on top of the 4-inch round-up.', true, 'trusted'),
  ('WK-9', 'WK', 'wk.synonyms', 2, 'DILIGENT most nearly means:', '["Lazy","Reluctant","Hardworking","Honest"]'::jsonb, 2, 'Diligent means showing steady, careful effort in work or duty, as in ''the diligent technician double-checked every wire before powering on.'' Lazy is the direct antonym, naming the absence of effort. Reluctant describes unwillingness to act, the inverse of the eager application of effort that diligent names. Honest names truthfulness, a different virtue not focused on labor. Hardworking is the dominant synonym, capturing both the effort and the persistence at the heart of diligence.', true, 'trusted'),
  ('WK-10', 'WK', 'wk.synonyms', 2, 'VOLATILE most nearly means:', '["Stable","Unstable","Heavy","Silent"]'::jsonb, 1, 'Volatile means liable to change rapidly and unpredictably, especially for the worse, as in ''the volatile chemical reacted the moment air hit it.'' Stable is the direct antonym, naming consistency and predictability. Heavy is a property-confusion trap: volatility describes a tendency to vaporize or shift state, not weight, so the two words name unrelated traits. Silent is also unrelated; volatility is about change, not sound. Unstable is the dominant synonym, capturing both the unpredictability and the tendency toward sudden shifts.', true, 'trusted'),
  ('WK-11', 'WK', 'wk.synonyms', 2, 'EXPEDITE most nearly means:', '["Delay","Organize","Accelerate","Evaluate"]'::jsonb, 2, 'To expedite means to speed up a process or make it happen sooner, as in ''the dispatcher expedited the parts shipment so the crew could finish by Friday.'' Delay is the direct antonym, naming slowdown rather than acceleration. Organize is a partial-overlap trap: organizing can help speed things up, but the act of arranging is not the act of hastening. Evaluate is a register trap, naming assessment rather than acceleration. Accelerate is the dominant synonym, sharing the core meaning of moving faster.', true, 'trusted'),
  ('WK-12', 'WK', 'wk.synonyms', 2, 'METICULOUS most nearly means:', '["Careless","Precise","Modest","Flexible"]'::jsonb, 1, 'Meticulous means showing extreme attention to detail, as in ''her meticulous packing list accounted for every screw and zip tie.'' Careless is the direct antonym, naming inattention. Modest describes humility about oneself, a different trait entirely. Flexible is a register trap, since meticulous people often follow exacting standards that resist bending. Precise is the dominant synonym, sharing the core meaning of exactness and careful accuracy, though meticulous adds the connotation of painstaking thoroughness across many details.', true, 'trusted'),
  ('PC-7', 'PC', 'pc.inference', 3, 'Read the following passage and answer the question.

"Antibiotics are effective against bacterial infections but have no effect on viral illnesses such as the common cold or influenza. Overuse of antibiotics has led to the emergence of drug-resistant bacteria, which pose a significant public health threat."

What conclusion can be drawn from this passage?', '["Antibiotics should be prescribed for all infections to prevent complications.","Viral and bacterial infections require the same treatment.","Using antibiotics unnecessarily contributes to antibiotic resistance.","The common cold can be cured with the right antibiotic."]'::jsonb, 2, 'The passage states that "overuse of antibiotics has led to the emergence of drug-resistant bacteria." Choice C restates that link in plain terms: unnecessary use feeds resistance. Choice A contradicts the passage, since the text warns about overuse. Choice B contradicts the first sentence, which says antibiotics have no effect on viral illnesses. Choice D also contradicts that line, because the cold is named as a viral illness antibiotics cannot treat. Only C draws a conclusion the passage actually supports.', true, 'trusted'),
  ('PC-8', 'PC', 'pc.detail-recall', 2, 'Read the following passage and answer the question.

"Night vision devices amplify existing light, such as moonlight or starlight, to allow soldiers to see in low-light environments. Unlike infrared thermal devices, which detect heat signatures, night vision devices cannot function in complete darkness."

What is one limitation of night vision devices mentioned in the passage?', '["They are too heavy for field use.","They detect heat signatures rather than light.","They cannot function in complete darkness.","They can only be used by specially trained soldiers."]'::jsonb, 2, 'The passage states the limitation directly: "night vision devices cannot function in complete darkness." That follows logically from the explanation that the devices "amplify existing light." Choice A invents a weight problem the text never raises. Choice B paraphrases a passage detail but flips it, since heat detection is what thermal devices do, not night vision. Choice D adds a training requirement the passage does not discuss. C is the only choice that names a limitation the text actually states.', true, 'trusted'),
  ('PC-9', 'PC', 'pc.main-idea', 2, 'Read the following passage and answer the question.

"The Army''s supply chain relies on a system known as LOGCAP (Logistics Civil Augmentation Program), which contracts civilian companies to provide support services in combat zones. This allows military units to focus on combat operations rather than logistics management."

What is the main purpose of LOGCAP according to the passage?', '["To replace all military logistics units with civilian workers","To allow military units to concentrate on combat by outsourcing support services","To reduce the overall size of the military budget","To train civilian contractors in military combat tactics"]'::jsonb, 1, 'The second sentence states the purpose explicitly: LOGCAP "allows military units to focus on combat operations rather than logistics management." Choice B paraphrases that line directly. Choice A overstates by adding "all," since the passage never claims total replacement. Choice C invents a budget motive the text does not discuss. Choice D reverses the relationship by suggesting civilians learn combat tactics, when the passage describes civilians taking on support work so soldiers can fight. B is the only choice that matches the stated purpose.', true, 'trusted'),
  ('MK-9', 'MK', 'mk.exponents-polynomials', 2, 'Simplify: (3x²)(4x³)', '["7x⁵","12x⁵","12x⁶","7x⁶"]'::jsonb, 1, 'Multiply coefficients: 3 × 4 = 12. Add exponents: x² × x³ = x⁵. Result: 12x⁵.', true, 'trusted'),
  ('MK-10', 'MK', 'mk.geometry', 2, 'What is the circumference of a circle with a diameter of 10 inches? (Use π ≈ 3.14)', '["15.7 inches","31.4 inches","78.5 inches","314 inches"]'::jsonb, 1, 'Circumference uses C = πd, where d is the diameter. C = 3.14 × 10 = 31.4 inches. The choice 15.7 inches uses the radius (5) instead of the diameter, computing πr. The choice 78.5 inches applies the area formula πr² with r = 5, mixing area and circumference. The choice 314 inches uses d² instead of d, computing π × 100.', true, 'trusted'),
  ('MK-11', 'MK', 'mk.fractions-decimals', 2, 'If the ratio of boys to girls in a class is 3:5 and there are 24 boys, how many girls are in the class?', '["32","36","40","48"]'::jsonb, 2, 'Find the value of one ratio unit. 3 units = 24 boys, so 1 unit = 8. Girls = 5 units = 5 × 8 = 40. The choice 32 adds 8 to the boy count instead of scaling the girl ratio. The choice 36 mixes up the ratio direction (3/5 × something) and lands near 40. The choice 48 treats the ratio 3:5 as parts of 8, then multiplies the boy count by the total ratio (24 × 8/4) or doubles the boys.', true, 'trusted'),
  ('MK-12', 'MK', 'mk.number-properties', 1, 'Evaluate: |−18| + |5|', '["−13","13","23","−23"]'::jsonb, 2, 'Absolute value removes the sign: |−18| = 18, |5| = 5. Sum = 18 + 5 = 23.', true, 'trusted'),
  ('EI-7', 'EI', 'ei.circuit-types', 3, 'Two resistors of 6 ohms each are connected in parallel. What is the total resistance of the combination?', '["12 ohms","6 ohms","3 ohms","1 ohm"]'::jsonb, 2, 'Parallel resistance uses 1/Rt = 1/R1 + 1/R2 = 1/6 + 1/6 = 2/6, so Rt = 3 Ω. Shortcut for equal parallel resistors: divide one by the count, 6 / 2 = 3 Ω. Choice A (12 Ω) adds them as if in series. Choice B (6 Ω) leaves resistance unchanged, missing that parallel paths reduce total resistance. Choice D (1 Ω) misapplies the formula by computing 1/(1/6 + 1/6) incorrectly or treating the reciprocal sum as the answer instead of inverting it.', true, 'trusted'),
  ('EI-8', 'EI', 'ei.conductors-insulators', 1, 'Which material is the BEST electrical conductor?', '["Rubber","Glass","Copper","Wood"]'::jsonb, 2, 'Copper has a sea of loosely bound free electrons, giving it very low resistivity (about 1.7 × 10⁻⁸ Ω·m), which is why nearly all household wiring uses it. Choice A (rubber) is the classic insulator used for wire jackets, with resistivity many orders of magnitude higher. Choice B (glass) is an insulator used on power-line standoffs. Choice D (wood) is an insulator when dry. Mistaking any insulator for a conductor reverses the basic distinction between materials that pass current freely and materials that block it.', true, 'trusted'),
  ('EI-9', 'EI', 'ei.components-devices', 3, 'A transformer has 100 turns on its primary coil and 400 turns on its secondary coil. If the primary voltage is 120 volts, what is the secondary voltage?', '["30 volts","120 volts","480 volts","600 volts"]'::jsonb, 2, 'Transformer turns ratio: Vs / Vp = Ns / Np. Plug in: Vs = 120 V × (400 / 100) = 120 × 4 = 480 V. More secondary turns means a step-up transformer. Choice A (30 V) inverts the ratio (100/400) and steps down instead of up. Choice B (120 V) ignores the ratio entirely. Choice D (600 V) multiplies primary voltage by 5 instead of 4, possibly by adding turns wrong or using (Np + Ns)/Np. The ratio is secondary over primary, not their sum.', true, 'trusted'),
  ('AS-7', 'AS', 'as.vehicle-systems', 3, 'What is the purpose of a vehicle''s timing belt or timing chain?', '["Transfer power from the transmission to the wheels","Synchronize the rotation of the crankshaft and camshaft","Connect the steering column to the front wheels","Regulate fuel pressure in the injection system"]'::jsonb, 1, 'The timing belt or chain ties the crankshaft to the camshaft so the valves open and close in step with piston position, which is what makes the four-stroke cycle work. Transferring transmission output to the wheels is the driveshaft and axles, not anything inside the engine. Connecting the steering wheel to the front wheels is the steering linkage. Fuel pressure is controlled by the fuel pump and pressure regulator in the fuel system. All three wrong answers swap timing components for parts in completely separate vehicle systems.', true, 'trusted'),
  ('AS-8', 'AS', 'as.hand-tools', 3, 'Which hand tool would you use to measure the outside diameter of a cylindrical metal rod precisely?', '["Tape measure","Inside caliper","Outside micrometer","Combination square"]'::jsonb, 2, 'An outside micrometer is built specifically to measure outside diameters, with a calibrated thimble that reads to a thousandth of an inch as the spindle closes on the workpiece. A tape measure resolves to about a sixteenth of an inch, which is nowhere near precision work on a metal rod. An inside caliper measures the inside of a bore or hole, the opposite kind of measurement. A combination square is a layout tool for checking right angles and marking lines, not a diameter gauge. Match the tool family to whether you are measuring outside, inside, or laying out.', true, 'trusted'),
  ('AS-9', 'AS', 'as.shop-safety', 3, 'When welding, the primary purpose of a ground clamp attached to the workpiece is to:', '["Prevent the metal from warping","Complete the electrical circuit for the welding arc","Cool the metal after welding","Indicate the direction of welding travel"]'::jsonb, 1, 'Welding works by passing electrical current through an arc between the electrode and the workpiece, melting metal so it fuses. The ground clamp closes that circuit by giving the current a path back to the welder. Without it, no arc strikes. Warping comes from heat input and joint design, not from the clamp. Cooling happens by conduction into the parent metal and ambient air after the arc stops. Travel direction is something the welder controls by hand. The clamp is purely an electrical connection.', true, 'trusted'),
  ('MC-7', 'MC', 'mc.forces-friction', 2, 'If a hydraulic jack applies 10 pounds of force over a piston with an area of 2 square inches, what is the pressure transmitted through the hydraulic fluid?', '["2 psi","5 psi","12 psi","20 psi"]'::jsonb, 1, 'Pressure equals force divided by area: P = F / A = 10 lb / 2 in^2 = 5 psi. Pascal''s principle states this pressure is transmitted equally to every part of the enclosed fluid. Choice A (2 psi) uses the area as the answer directly, ignoring the force. Choice C (12 psi) adds the force and area (10 + 2), which mixes incompatible units. Choice D (20 psi) multiplies force by area (10 x 2), inverting the formula. The pressure-versus-force distinction matters: pressure is what the fluid carries; force is what each piston exerts, and the two are connected by piston area.', true, 'trusted'),
  ('MC-8', 'MC', 'mc.motion-projectile', 2, 'A ball rolls off a horizontal table and follows a curved path to the ground. This curved path is an example of which type of motion?', '["Circular motion","Simple harmonic motion","Projectile motion","Linear motion"]'::jsonb, 2, 'Projectile motion describes any object launched with a horizontal velocity that is then acted on only by gravity. The horizontal speed stays constant while vertical speed grows under g, producing a parabolic path. Choice A (circular motion) requires a centripetal force pulling toward a center point, not a constant downward gravitational pull. Choice B (simple harmonic motion) describes oscillation about an equilibrium, like a pendulum or spring, not a one-way arc. Choice D (linear motion) requires a straight-line path, but the ball curves downward as it leaves the table, ruling out a straight trajectory.', true, 'trusted'),
  ('MC-9', 'MC', 'mc.inclined-plane-hydraulics', 3, 'In an inclined plane, increasing the length of the ramp while keeping the height constant will:', '["Increase the effort force needed to move the load","Decrease the mechanical advantage","Increase the mechanical advantage by reducing effort force","Have no effect on mechanical advantage"]'::jsonb, 2, 'Mechanical advantage of an inclined plane equals ramp length divided by ramp height: MA = L / h. Increasing L while keeping h fixed makes the ratio larger, so MA goes up and the required effort force goes down. Choice A (increase effort) reverses the trade-off; a longer ramp lowers effort, not raises it. Choice B (decrease MA) inverts the formula. Choice D (no effect) ignores that MA depends explicitly on the L/h ratio. Work in equals work out: a longer ramp spreads the same lifting work over more distance, so the force at each point drops.', true, 'trusted'),
  ('AO-7', 'AO', 'ao.3d-visualization', 1, 'A standard six-sided die is held so that the 1 faces up. Which number is on the face directly opposite the 1?', '["2","4","6","5"]'::jsonb, 2, 'On a standard die, opposite faces always sum to 7. The pairs are 1 and 6, 2 and 5, 3 and 4. With 1 facing up, the face directly opposite is 6. Choosing ''2'' or ''5'' confuses opposite faces with adjacent faces, since 2 and 5 sit on the sides of a 1-up die rather than the bottom. Choosing ''4'' applies the wrong arithmetic, perhaps subtracting 1 from 5 or guessing without using the sum-to-7 rule.', true, 'trusted'),
  ('AO-9', 'AO', 'ao.spatial-counting', 2, 'A 12-inch ruler is broken into two pieces. One piece is twice as long as the other. What are the lengths of the two pieces?', '["3 inches and 9 inches","4 inches and 8 inches","5 inches and 7 inches","6 inches and 6 inches"]'::jsonb, 1, 'Let the shorter piece have length x. The longer piece is twice as long, so 2x. Together they form the full ruler: x + 2x = 3x = 12, giving x = 4. The pieces measure 4 inches and 8 inches. ''3 and 9'' satisfies the sum but the ratio is 3 to 1, not 2 to 1. ''5 and 7'' has the right sum but a ratio of 7 to 5. ''6 and 6'' makes two equal pieces, which would mean a 1 to 1 ratio rather than 2 to 1. Only 4 and 8 satisfy both the sum and the doubling relationship.', true, 'trusted'),
  ('WK-CTX-1', 'WK', 'wk.context-clues', 3, 'In the sentence ''The senator''s VERBOSE reply frustrated reporters who needed a simple yes or no,'' the word VERBOSE most nearly means:', '["enthusiastic","evasive","using more words than necessary","difficult to hear"]'::jsonb, 2, 'The phrase ''needed a simple yes or no'' pins the meaning: the reply failed because it used too many words for the simple answer required. Verbose specifically labels speech that uses more words than necessary. ''Evasive'' is plausible vocabulary-wise (a long answer can dodge), but the sentence frames frustration around length, not deception. ''Enthusiastic'' fits a long reply only if the speaker were excited, which the senator setting does not suggest. ''Difficult to hear'' addresses volume, which the sentence never raises.', true, 'trusted'),
  ('WK-CTX-2', 'WK', 'wk.context-clues', 3, 'In the sentence ''After three sleepless days on patrol, the soldiers were so TORPID they could barely lift their rifles,'' the word TORPID most nearly means:', '["alert","sluggish","angry","well-trained"]'::jsonb, 1, 'Three sleepless days and barely being able to lift their rifles pin the meaning to extreme physical and mental drain. Torpid specifically labels that drained, slowed state. ''Alert'' is the direct opposite of what the clues describe. ''Angry'' is plausible vocabulary-wise (tired soldiers may snap), but the sentence describes weakness, not temper. ''Well-trained'' fits the soldier frame but contradicts the clue: trained soldiers struggling to move signals exhaustion, not capability. Only Sluggish matches the evidence.', true, 'trusted'),
  ('WK-CTX-4', 'WK', 'wk.context-clues', 4, 'In the sentence ''The commander''s TACITURN nature meant that junior soldiers rarely received direct feedback, leaving them to interpret his single nods as either praise or disapproval,'' the word TACITURN most nearly means:', '["stern and demanding","reluctant to speak","unpredictable in mood","fair but strict"]'::jsonb, 1, 'Taciturn means habitually saying very little. The sentence''s clue is that soldiers got no verbal feedback at all, only nods — indicating a person who rarely speaks, not one who is merely stern or moody.', true, 'trusted'),
  ('WK-CTX-5', 'WK', 'wk.context-clues', 3, 'In the sentence ''The hiking trail was so ARDUOUS that even the most experienced climbers needed rest breaks every half mile,'' the word ARDUOUS most nearly means:', '["scenic","demanding","well-marked","narrow"]'::jsonb, 1, 'Experienced climbers needing rest breaks every half mile pins the meaning to extreme physical difficulty. Arduous specifically labels work or paths that demand great effort. ''Scenic'' is plausible for a hiking trail in general but the sentence focuses on hardship, not beauty. ''Well-marked'' addresses signage and visibility, which the sentence never mentions. ''Narrow'' could explain difficulty for some hikers but would not stop experienced climbers in particular. Only Demanding matches the evidence of effort overcoming even seasoned hikers.', true, 'trusted'),
  ('WK-CTX-6', 'WK', 'wk.context-clues', 4, 'In the sentence ''Her SARDONIC smile told the interviewer she found the question absurd, though she answered politely,'' the word SARDONIC most nearly means:', '["warm and welcoming","mocking or grimly humorous","nervous and tense","bright and enthusiastic"]'::jsonb, 1, 'Finding the question absurd while staying outwardly polite pins the meaning: the smile mocked the question without saying so openly. Sardonic specifically labels grimly humorous mockery. ''Warm and welcoming'' contradicts the disdain implied by finding the question absurd. ''Nervous and tense'' is plausible for an interview frame but the clue is contempt, not anxiety. ''Bright and enthusiastic'' clashes with the silent judgment behind the smile. Only Mocking or grimly humorous fits the combination of polite surface and dismissive interior.', true, 'trusted'),
  ('WK-CTX-8', 'WK', 'wk.context-clues', 3, 'In the sentence ''After three consecutive failed inspections and a barracks fire, the unit remained RESILIENT and returned to full readiness within a month,'' the word RESILIENT most nearly means:', '["resourceful","quick to recover from setbacks","highly trained","well-funded"]'::jsonb, 1, 'The sentence stacks adversities (failed inspections plus a fire) and then notes a return to full readiness. That pattern of being knocked down and bouncing back is exactly what resilient names: the capacity to recover from setbacks. ''Resourceful'' is the trickiest distractor because resourceful units also rebound, but resourcefulness specifically means creative problem-solving with limited means, not the rebound itself. ''Highly trained'' would describe a baseline competence, not a response to repeated adversity. ''Well-funded'' is unsupported by the sentence. Only ''quick to recover from setbacks'' names the resilience itself rather than a contributor to it.', true, 'trusted'),
  ('WK-CTX-9', 'WK', 'wk.context-clues', 4, 'In the sentence ''The general''s IMPERIOUS tone left no doubt that his orders were not suggestions — they were commands,'' the word IMPERIOUS most nearly means:', '["calm and measured","domineering and commanding","persuasive and logical","vague and uncertain"]'::jsonb, 1, 'Orders that ''were not suggestions, they were commands'' pins the meaning to a tone that expects unquestioning obedience. Imperious specifically labels that domineering authority. ''Calm and measured'' contradicts the forceful contrast in the sentence. ''Persuasive and logical'' implies the listener is being convinced through reasoning, but the sentence emphasizes that no choice is offered. ''Vague and uncertain'' is the opposite of the clarity the sentence describes. Only Domineering and commanding matches the no-choice frame the general''s tone establishes.', true, 'trusted'),
  ('WK-CTX-10', 'WK', 'wk.context-clues', 3, 'In the sentence ''The scientist''s HYPOTHESIS, though TENUOUS at first, grew stronger as more experimental data came in,'' the word TENUOUS most nearly means:', '["widely accepted","poorly worded","weak or lacking support","based on observation"]'::jsonb, 2, 'The phrase ''grew stronger as more experimental data came in'' pins the meaning: the hypothesis began with little support. Tenuous specifically labels arguments or threads that are thin and weakly supported. ''Widely accepted'' is the opposite of what the sentence describes. ''Poorly worded'' addresses phrasing rather than evidence, which the sentence never criticizes. ''Based on observation'' is plausible for any hypothesis but does not capture the weakness that the data later remedied. Only Weak or lacking support matches the trajectory from thin to strong.', true, 'trusted'),
  ('WK-CTX-11', 'WK', 'wk.context-clues', 4, 'In the sentence ''The judge''s IMPARTIAL ruling satisfied both sides because neither could claim favoritism,'' the word IMPARTIAL most nearly means:', '["biased toward the defendant","based on strict law","treating all sides equally without favoritism","delivered quickly"]'::jsonb, 2, 'The phrase ''neither could claim favoritism'' pins the meaning: the ruling did not lean toward either side. Impartial specifically labels that even-handed fairness. ''Biased toward the defendant'' is the opposite. ''Based on strict law'' is the trickiest distractor since strict law often is impartial, but strictness names rigor, not balance, and the sentence rewards balance specifically. ''Delivered quickly'' addresses speed, which the sentence never raises. Only Treating all sides equally without favoritism matches the both-sides-satisfied clue.', true, 'trusted'),
  ('WK-CTX-12', 'WK', 'wk.context-clues', 5, 'In the sentence ''His PERFUNCTORY review of the safety checklist — glancing at it for seconds before signing — nearly cost the crew their lives,'' the word PERFUNCTORY most nearly means:', '["thorough and systematic","done as a formality without real care","delayed and overdue","conducted by a supervisor"]'::jsonb, 1, 'Glancing at the checklist for seconds before signing, with near-catastrophic results, pins the meaning to a review done as bare formality. Perfunctory specifically labels actions done mechanically without genuine effort. ''Thorough and systematic'' is the direct opposite. ''Delayed and overdue'' addresses timing, but the sentence faults quality, not lateness. ''Conducted by a supervisor'' addresses who, not how, and the sentence never identifies the reviewer''s rank. Only Done as a formality without real care matches the seconds-of-glancing evidence.', true, 'trusted'),
  ('WK-PFX-1', 'WK', 'wk.prefixes-suffixes', 3, 'The word ANTECEDENT contains the prefix ANTE-. Based on that prefix, ANTECEDENT most nearly means:', '["something that comes after","something that came before","something that contradicts","something that repeats"]'::jsonb, 1, 'ANTECEDENT breaks down as ANTE- (before) plus CED- (go, from cedere) plus -ENT (noun-forming suffix), literally ''that which goes before.'' An antecedent is the prior thing that a later thing refers back to. ''Something that comes after'' confuses ANTE- (before) with POST- (after). ''Something that contradicts'' confuses ANTE- with ANTI- (against), the single most common error since the two prefixes differ by only one letter. ''Something that repeats'' would require RE- (again), a different prefix entirely.', true, 'trusted'),
  ('WK-PFX-2', 'WK', 'wk.prefixes-suffixes', 3, 'The word BENEVOLENT contains the root VOL (wish, will) and the prefix BENE-. BENEVOLENT most nearly means:', '["well-wishing or kind","all-powerful","voluntary","truthful"]'::jsonb, 0, 'BENEVOLENT breaks down as BENE- (well, good) plus VOL- (wish, will) plus -ENT (adjective-forming suffix), literally ''well-wishing.'' ''All-powerful'' would require OMNI- (all) plus POT- (power), as in omnipotent, a different morphology. ''Voluntary'' shares the VOL- root but lacks BENE-, so it names willingness without the good-wishing component. ''Truthful'' would require VER- (true, as in veracity), a different root that learners sometimes confuse with VOL-. Only Well-wishing or kind tracks both BENE- and VOL- correctly.', true, 'trusted'),
  ('WK-PFX-3', 'WK', 'wk.prefixes-suffixes', 3, 'The suffix -LOGY means the study of. CHRONOLOGY is therefore best defined as:', '["the science of timekeeping devices","the arrangement of events in time order","a record of weather patterns","the study of ancient languages"]'::jsonb, 1, 'CHRONOLOGY breaks down as CHRONO- (time) plus -LOGY (study or systematic ordering of). A chronology arranges events in time sequence. ''The science of timekeeping devices'' confuses -LOGY (study) with horology, which is the actual word for clock science. ''A record of weather patterns'' would require METEORO- (atmosphere), as in meteorology, not CHRONO-. ''The study of ancient languages'' would require PHILO- or LINGUO-, not CHRONO-. Only Arrangement of events in time order tracks both CHRONO- and -LOGY correctly.', true, 'trusted'),
  ('WK-PFX-4', 'WK', 'wk.prefixes-suffixes', 4, 'The word CIRCUMSPECT contains the prefix CIRCUM- (around) and the root SPECT (look). CIRCUMSPECT most nearly means:', '["easily distracted","wary and considering all possibilities","surrounded by obstacles","quick to decide"]'::jsonb, 1, 'CIRCUMSPECT breaks down as CIRCUM- (around) plus SPECT (look, from spectare), literally ''looking around'' before acting. The morphology points to careful surveying of all sides before deciding. ''Easily distracted'' misreads looking around as scattered attention, when the word actually means deliberate scanning. ''Surrounded by obstacles'' treats CIRCUM- as a physical description of the subject rather than an action they perform. ''Quick to decide'' is the opposite of what the morphology suggests. Only Wary and considering all possibilities tracks both pieces.', true, 'trusted'),
  ('WK-PFX-5', 'WK', 'wk.prefixes-suffixes', 3, 'The prefix TRANS- means across or through. A TRANSOCEANIC voyage is therefore a voyage:', '["below the ocean surface","along the coastline","across an ocean","within a single ocean region"]'::jsonb, 2, 'TRANSOCEANIC breaks down as TRANS- (across, through) plus OCEAN plus -IC (adjective-forming), literally ''across the ocean.'' Compare transcontinental, transatlantic, transport (carry across). ''Below the ocean surface'' would require SUB- (under), as in submarine, a different prefix. ''Along the coastline'' would require something like PARA- or PERI- (alongside, around), not TRANS-. ''Within a single ocean region'' would require INTRA- (within), the prefix that contrasts most directly with TRANS-. Only Across an ocean matches TRANS-.', true, 'trusted'),
  ('WK-PFX-6', 'WK', 'wk.prefixes-suffixes', 4, 'The word EQUIVOCAL contains the prefix EQUI- (equal) and the root VOC (voice/call). EQUIVOCAL most nearly means:', '["equally loud","open to two interpretations","fair and balanced","clearly stated"]'::jsonb, 1, 'Equivocal literally means ''equal voices'' — a statement that calls equally in two directions, making it deliberately ambiguous or unclear. Clearly stated is the antonym. Fair and balanced is a trap that uses EQUI- in isolation.', true, 'trusted'),
  ('WK-PFX-7', 'WK', 'wk.prefixes-suffixes', 4, 'The suffix -OLOGY means the study of, while -OLOGIST means one who studies. A SEISMOLOGIST studies:', '["the structure of the atmosphere","earthquake activity","ocean currents","ancient fossils"]'::jsonb, 1, 'SEISMOLOGIST breaks down as SEISMO- (shaking, earthquake, from Greek seismos) plus -OLOGIST (one who studies). ''Structure of the atmosphere'' would require METEORO-, the prefix for meteorology, not SEISMO-. ''Ocean currents'' would require OCEANO-, as in oceanography, plus the -GRAPHY suffix for description rather than -OLOGY. ''Ancient fossils'' would require PALEO- (ancient) plus ONTO- (being), as in paleontology, a completely different morpheme. Only Earthquake activity matches SEISMO- specifically.', true, 'trusted'),
  ('WK-PFX-8', 'WK', 'wk.prefixes-suffixes', 5, 'The word MAGNANIMOUS contains the roots MAGN- (great) and ANIM- (spirit/soul). MAGNANIMOUS most nearly means:', '["physically large and imposing","generous in forgiving insults or injuries","highly educated","emotionally volatile"]'::jsonb, 1, 'MAGNANIMOUS breaks down as MAGN- (great) plus ANIM- (spirit, soul) plus -OUS (adjective-forming), literally ''great-spirited.'' The ANIM- piece shifts the meaning from physical greatness toward greatness of character, especially generosity toward rivals. ''Physically large and imposing'' reads only the MAGN- piece (as in magnitude) and ignores ANIM-. ''Highly educated'' would require ERUD- or SAPI- roots, not MAGN-/ANIM-. ''Emotionally volatile'' confuses ANIM- with animated agitation rather than soul or character. Only Generous in forgiving insults or injuries tracks both pieces.', true, 'trusted'),
  ('WK-ROOT-1', 'WK', 'wk.root-words', 3, 'The word AUDIBLE shares its root with AUDITORIUM and AUDIENCE. The root AUD- means:', '["to speak","to hear","to see","to gather"]'::jsonb, 1, 'AUD- comes from Latin audire, meaning to hear. Cognates include audible (able to be heard), auditorium (a place built for hearing), audience (a group of listeners), audition (a hearing trial), and audio (sound recording). ''To speak'' would use DICT- (dictate, predict) or LOQU- (eloquent, loquacious), different roots entirely. ''To see'' would use VIS- (vision, visible) or SPEC- (spectator), commonly confused since both involve perception. ''To gather'' would use GREG- (congregate) or AGGREG-, not AUD-.', true, 'trusted'),
  ('WK-ROOT-2', 'WK', 'wk.root-words', 3, 'The root CHRON appears in CHRONIC, CHRONOMETER, and ANACHRONISM. CHRON means:', '["color","time","order","distance"]'::jsonb, 1, 'CHRON comes from Greek chronos, meaning time. Cognates include chronic (continuing over a long time), chronometer (a precise time-measuring device), anachronism (something placed in the wrong time period), chronicle (a time-ordered record), and synchronize (occur at the same time). ''Color'' would use CHROM- (chromatic, chromosome), a similar-sounding root that test-takers confuse with CHRON- because both start with CHR-. ''Order'' would use ORDIN- (ordinal, ordinary). ''Distance'' would use METR- or MILE-, not CHRON-.', true, 'trusted'),
  ('WK-ROOT-3', 'WK', 'wk.root-words', 3, 'The root TERRA appears in TERRITORY, TERRAIN, and MEDITERRANEAN. TERRA most nearly means:', '["water","sky","earth or land","boundary"]'::jsonb, 2, 'TERRA comes from Latin meaning earth or land. Cognates include terrain (the lay of the land), territory (a defined area of land), Mediterranean (middle of the land), terrestrial (relating to earth), and terrace (a flat platform of land). ''Water'' would use AQUA- (aquatic, aqueduct) or HYDRO- (hydrate, hydraulic), different roots. ''Sky'' would use AERO- or CEL- (celestial), not TERRA-. ''Boundary'' would use FIN- (finite, define) or LIMIT-, also separate roots. Only Earth or land matches TERRA across all the cognates.', true, 'trusted'),
  ('WK-ROOT-4', 'WK', 'wk.root-words', 4, 'The root SCRIB/SCRIPT appears in PRESCRIBE, DESCRIBE, INSCRIPTION, and MANUSCRIPT. This root most nearly means:', '["to speak","to write","to order","to carve"]'::jsonb, 1, 'SCRIB/SCRIPT comes from the Latin scribere, to write. Manuscript means handwritten; inscription is writing carved into a surface; prescribe originally meant to write before (instructions). ''To carve'' is a trap because inscriptions are carved, but the root itself means write.', true, 'trusted'),
  ('WK-ROOT-5', 'WK', 'wk.root-words', 4, 'The root RUPT appears in INTERRUPT, DISRUPT, ERUPT, and RUPTURE. RUPT most nearly means:', '["to flow","to break or burst","to begin","to connect"]'::jsonb, 1, 'RUPT comes from the Latin rumpere, to break. Interrupt means to break into; disrupt means to break apart; erupt means to burst out; rupture is a break or tear. ''To flow'' is a trap because eruptions involve flow, but the root captures the breaking action.', true, 'trusted'),
  ('WK-ROOT-6', 'WK', 'wk.root-words', 5, 'The root LOQUI/LOCUT appears in ELOQUENT, COLLOQUIAL, LOQUACIOUS, and SOLILOQUY. This root most nearly means:', '["to listen","to write formally","to speak","to persuade"]'::jsonb, 2, 'LOQUI/LOCUT comes from the Latin loqui, to speak. Eloquent means speaking with fluency and force; loquacious means very talkative; colloquial refers to everyday spoken language; a soliloquy is speaking alone. ''To persuade'' is tempting for eloquent, but persuasion is an effect, not the root''s meaning.', true, 'trusted'),
  ('PC-ATP-1', 'PC', 'pc.author-tone-purpose', 3, 'Read the passage below and answer the question.

"Every year, thousands of young people sign contracts they do not fully understand, binding themselves to financial obligations that can follow them for a decade. Financial literacy is not a luxury — it is a survival skill. Schools that skip personal finance education are not saving curriculum space; they are failing their students."

The author''s primary purpose is to:', '["explain how financial contracts work","argue that financial education should be required in schools","describe the difficulties young people face after graduation","compare different methods of teaching personal finance"]'::jsonb, 1, 'The passage builds toward a verdict: "Schools that skip personal finance education are not saving curriculum space; they are failing their students." The word "failing" plus "survival skill" signals advocacy, not neutral explanation. Choice B captures that argumentative purpose. Choice A picks the contracts example and treats it as the subject, when contracts are only the opening illustration. Choice C names a related topic but misses the persuasive thrust, since the author is not describing graduate hardship in general. Choice D invents a comparison of teaching methods that never appears.', true, 'trusted'),
  ('PC-ATP-2', 'PC', 'pc.author-tone-purpose', 3, 'Read the passage below and answer the question.

"The old lighthouse stood at the edge of the cliff, its white paint peeling, its lamp long dark. Fishermen who once depended on its beam now navigated by GPS coordinates that glowed on small screens below the wheelhouse. Progress, it seemed, had made the lighthouse beautiful again — no longer a tool, just a memory."

The author''s tone toward the lighthouse can best be described as:', '["angry at the march of technology","nostalgic and somewhat wistful","proud of modern navigation advances","indifferent to the lighthouse''s fate"]'::jsonb, 1, '''Beautiful again — no longer a tool, just a memory'' expresses a wistful, nostalgic view of something that has outlived its usefulness. The author is not angry — progress is accepted — but there is a gentle sense of loss, not pride or indifference.', true, 'trusted'),
  ('PC-ATP-3', 'PC', 'pc.author-tone-purpose', 4, 'Read the passage below and answer the question.

"The study followed 400 adults over 20 years and found that those who slept fewer than six hours per night had a 35 percent higher incidence of cardiovascular events than those who slept seven to eight hours. Researchers controlled for diet, exercise, and body mass index. The correlation was consistent across age groups and geographic regions."

The author''s tone is best described as:', '["alarmed and warning readers to change habits","objective and informative","persuasive, urging policy reform","skeptical of the study''s methodology"]'::jsonb, 1, 'The passage reports data and controlled variables without emotional language or calls to action. ''Controlled for diet, exercise, and BMI'' signals scientific rigor, not alarm or advocacy. Skeptical would involve questioning the methods, which the author does not do.', true, 'trusted'),
  ('PC-ATP-4', 'PC', 'pc.author-tone-purpose', 3, 'Read the passage below and answer the question.

"If you have ever watched a skilled carpenter fit two pieces of wood together without a visible gap, you have witnessed craftsmanship at its best. It is not magic — it is patience, the right tools, and a refusal to accept ''good enough.'' Anyone who calls woodworking a dying art has never stood in a shop full of sawdust and purpose."

The author''s attitude toward woodworking is best described as:', '["defensive and insecure about the craft''s future","enthusiastic and admiring","neutral and informational","critical of beginners who rush their work"]'::jsonb, 1, 'Phrases like "craftsmanship at its best," "patience, the right tools," and "a shop full of sawdust and purpose" register as praise. Choice B names that admiring tone. Choice A picks a near-but-distinct attitude, since the author confidently dismisses critics rather than sounding insecure about the craft''s future. Choice C ignores the value-loaded language entirely. Choice D misreads "refusal to accept good enough" as criticism of beginners, but that phrase praises the carpenter''s standards rather than scolding learners. Only B fits the celebratory tone the passage actually carries.', true, 'trusted'),
  ('PC-ATP-5', 'PC', 'pc.author-tone-purpose', 4, 'Read the passage below and answer the question.

"The proposal to expand the highway through the wetland was approved in 72 hours — a process that typically takes months of environmental review. Local conservation groups were not notified until after the vote. Three federal agencies later noted that proper procedure had not been followed, yet construction began on schedule."

The author''s implied attitude toward the approval process is:', '["supportive of faster infrastructure decisions","critical of the rushed and irregular process","neutral, simply reporting a timeline","uncertain about whether the wetland matters"]'::jsonb, 1, 'The author selects details that all point in one direction: "approved in 72 hours" against "months of environmental review," conservation groups "not notified until after the vote," and "three federal agencies later noted that proper procedure had not been followed, yet construction began on schedule." That pattern of contrast amounts to implied criticism. Choice A reverses the attitude. Choice C ignores the loaded selection of details, treating implied judgment as plain reporting. Choice D invents uncertainty about the wetland, when the author''s focus is procedural shortcuts rather than ecological worth.', true, 'trusted'),
  ('PC-ATP-6', 'PC', 'pc.author-tone-purpose', 4, 'Read the passage below and answer the question.

"Wolves were reintroduced to Yellowstone in 1995. Within a decade, the elk population shifted its grazing patterns away from riverbanks, allowing willows and aspens to regrow. Beavers returned; their dams slowed erosion; streambeds narrowed and deepened. A single predator had changed the rivers."

The author''s primary purpose is to:', '["argue that wolf populations should be expanded throughout the country","illustrate how the reintroduction of one species can reshape an entire ecosystem","criticize the original removal of wolves from Yellowstone","describe the daily behavior of wolves in the wild"]'::jsonb, 1, 'The passage traces a chain of ecological effects from one decision, building to ''a single predator had changed the rivers.'' This is an illustrative, cause-and-effect purpose. The author does not call for expanded wolf populations or criticize past decisions.', true, 'trusted'),
  ('PC-ATP-7', 'PC', 'pc.author-tone-purpose', 5, 'Read the passage below and answer the question.

"Efficiency, we are often told, is the highest virtue of a modern organization. But efficiency is a tool, not a goal. A surgeon who operates faster does not thereby become a better surgeon; a teacher who covers content faster is not necessarily teaching. When organizations optimize processes without asking what those processes are for, they risk becoming very good at doing the wrong thing."

The author''s attitude toward efficiency is best described as:', '["strongly opposed to using efficiency in any professional context","cautiously skeptical — useful in the right place, but easily misapplied","fully supportive if efficiency is paired with speed","indifferent; the author is presenting both sides without a position"]'::jsonb, 1, 'The author calls efficiency ''a tool, not a goal'' and uses examples to show how misapplied efficiency backfires — but never argues against efficiency itself. This is cautious skepticism, not wholesale opposition. The author clearly has a position, ruling out indifference.', true, 'trusted'),
  ('PC-ATP-8', 'PC', 'pc.author-tone-purpose', 5, 'Read the passage below and answer the question.

"The recruits arrived in October — cocky, loud, certain they were ready for anything. By December, most had stopped talking about what they thought training would be like. They had learned something that cannot be taught in a classroom: that confidence earned is different from confidence assumed."

The author''s tone toward the recruits at the end of the passage is best described as:', '["contemptuous of their early arrogance","approving of the growth they experienced","pessimistic about their long-term prospects","amused by their naivety throughout"]'::jsonb, 1, '''Confidence earned is different from confidence assumed'' is the author''s conclusion — framing the change as meaningful growth, not humiliation. Contemptuous would suggest the author mocks them; the passage instead presents the transformation with respect.', true, 'trusted'),
  ('AS-MNT-1', 'AS', 'as.maintenance-repair', 3, 'Engine oil should be changed at regular intervals primarily to:', '["increase fuel octane rating","remove contaminants and restore lubricating properties","cool the transmission fluid","maintain proper tire pressure"]'::jsonb, 1, 'Engine oil picks up combustion soot, metal wear particles, and acidic byproducts as it circulates, and its additive package wears out over time. Draining and refilling at the recommended interval removes that contamination and restores fresh detergents and viscosity improvers so bearings and rings stay protected. Fuel octane is a property of the gasoline itself, set at the refinery, and no oil change can change it. Cooling transmission fluid is the job of the transmission cooler or radiator side tank. Tire pressure is set by air volume in the tire, completely unrelated to engine oil.', true, 'trusted'),
  ('AS-MNT-2', 'AS', 'as.maintenance-repair', 3, 'A vehicle''s brake pedal sinks slowly to the floor when held with steady pressure. This most likely indicates:', '["worn brake pads","a failing master cylinder or brake fluid leak","air in the fuel line","a loose wheel bearing"]'::jsonb, 1, 'A pedal that sinks under steady pressure (called brake fade or pedal drop) is a classic sign of a failing master cylinder or a leak allowing fluid to bypass the seals. Worn pads change stopping distance but do not cause the pedal to drop under held pressure.', true, 'trusted'),
  ('AS-MNT-3', 'AS', 'as.maintenance-repair', 3, 'Tire rotation is recommended every 5,000–7,000 miles primarily because:', '["it resets the tire pressure monitoring system","front and rear tires wear at different rates due to different loads and steering forces","it prevents the tires from developing flat spots when parked","rotating tires improves fuel octane combustion"]'::jsonb, 1, 'On most cars, especially front-wheel-drive, the front tires carry more weight from the engine and transaxle and also handle every steering input, so they wear noticeably faster than the rears. Moving tires to new positions on a schedule evens out that wear and stretches the useful life of the full set. The TPMS reset is a separate maintenance step done with a scan tool or by drive cycle, not by rotating. Flat-spotting comes from prolonged parking with hot tires, not from rotation patterns. Octane combustion has nothing to do with tires.', true, 'trusted'),
  ('AS-MNT-4', 'AS', 'as.maintenance-repair', 4, 'When checking tire pressure, a technician should check it when the tires are:', '["hot, immediately after a long drive, for the most accurate reading","cold, before driving or after sitting for at least three hours","warm, after a short drive of about five miles","at any temperature, because modern gauges automatically adjust"]'::jsonb, 1, 'Tire pressure is specified for cold tires because driving heats air inside the tire, raising pressure by 4–8 psi. Checking hot tires gives a falsely high reading; the industry standard is to check cold tires. Modern gauges measure pressure but do not compensate for temperature.', true, 'trusted'),
  ('AS-MNT-5', 'AS', 'as.maintenance-repair', 3, 'A vehicle pulls consistently to the right when driving on a straight, level road. The most likely cause is:', '["a clogged fuel filter","uneven tire pressure or a wheel alignment problem","a worn timing belt","low windshield washer fluid"]'::jsonb, 1, 'Pulling to one side is the classic symptom of uneven tire pressure or wheel misalignment. A low right-side tire or toe misalignment causes the vehicle to drift toward the low-pressure or angled side. Fuel and timing issues cause performance problems, not directional pull.', true, 'trusted'),
  ('AS-MNT-6', 'AS', 'as.maintenance-repair', 4, 'A grinding noise that occurs only when the brakes are applied most likely indicates:', '["a failing alternator","brake pads worn down to the metal backing plate","loose lug nuts on the wheel","low power steering fluid"]'::jsonb, 1, 'Brake pads have friction material bonded to a steel backing plate. When the friction material wears down past its service limit, the bare steel rubs against the cast-iron rotor and produces a coarse grinding noise every time you brake. An alternator failure shows up as a dead battery or warning light, not as a sound tied to the brake pedal. Loose lug nuts make a clunk or vibration that is present whether or not you are braking. Low power steering fluid causes whining when you turn the wheel, again unrelated to the brakes. The brake-only timing is the key clue.', true, 'trusted'),
  ('AS-MNT-7', 'AS', 'as.maintenance-repair', 4, 'The purpose of a vehicle''s PCV (Positive Crankcase Ventilation) valve is to:', '["regulate fuel injection timing","route blow-by gases from the crankcase back into the intake manifold for combustion","control coolant flow to the heater core","measure exhaust oxygen content for the fuel management system"]'::jsonb, 1, 'The PCV valve draws unburned gases (blow-by) that slip past piston rings back into the intake manifold where they are reburned. A stuck-closed PCV valve can build crankcase pressure and force oil past seals. The oxygen sensor (not PCV) measures exhaust oxygen.', true, 'trusted'),
  ('AS-MNT-8', 'AS', 'as.maintenance-repair', 5, 'An engine runs rough at idle but smoothly at higher RPM. Disconnecting one spark plug wire at a time, you find that one cylinder makes no change to idle quality when its wire is removed. This means:', '["that cylinder is firing too often at idle","that cylinder is not contributing to engine power — it is misfiring or dead","the ignition coil for that cylinder is delivering extra voltage","all cylinders are sharing load equally"]'::jsonb, 1, 'Removing a plug wire from a healthy cylinder will cause idle to noticeably worsen. If removing a wire causes no change, that cylinder was already not contributing — it was misfiring. This test isolates the dead cylinder.', true, 'trusted'),
  ('MC-IPH-1', 'MC', 'mc.inclined-plane-hydraulics', 3, 'A 300-pound crate is slid up a frictionless ramp that is 15 feet long and rises 5 feet vertically. How many pounds of force are required to push it up the ramp?', '["60 pounds","100 pounds","150 pounds","300 pounds"]'::jsonb, 1, 'Mechanical advantage of an inclined plane equals length divided by height: MA = 15 / 5 = 3. Effort = Load / MA = 300 / 3 = 100 pounds. Choice A (60 pounds) corresponds to an MA of 5, which would require a 25-foot ramp at this height. Choice C (150 pounds) is half the load, treating the ramp like a single movable pulley. Choice D (300 pounds) ignores the ramp entirely and just lists the load weight, which is what would be required to lift the crate straight up with no machine helping.', true, 'trusted'),
  ('MC-IPH-2', 'MC', 'mc.inclined-plane-hydraulics', 3, 'In a hydraulic system, a small piston with an area of 2 square inches is pushed down with 50 pounds of force. What force does the large piston with an area of 10 square inches exert?', '["10 pounds","100 pounds","250 pounds","500 pounds"]'::jsonb, 2, 'Pascal''s principle gives F1/A1 = F2/A2, so F2 = F1 x (A2/A1) = 50 x (10/2) = 50 x 5 = 250 pounds. Choice A (10 pounds) divides force by area ratio instead of multiplying, treating hydraulics as if the large piston reduced force. Choice B (100 pounds) doubles the input, applying only the bare 2:1 ratio between pistons rather than the full 5:1 area ratio. Choice D (500 pounds) doubles the correct answer by mishandling the area ratio (using 10 x 1 instead of 10 / 2). The area ratio, not piston diameter or simple multiples, sets force multiplication.', true, 'trusted'),
  ('MC-IPH-3', 'MC', 'mc.inclined-plane-hydraulics', 4, 'A block-and-tackle pulley system uses 4 rope segments supporting the load. If you pull the free end with 75 pounds of force, how heavy a load can you lift (ignoring friction)?', '["75 pounds","150 pounds","225 pounds","300 pounds"]'::jsonb, 3, 'A block-and-tackle''s mechanical advantage equals the number of rope segments directly supporting the load. With 4 supporting strands, MA = 4, so the maximum load = effort x MA = 75 x 4 = 300 pounds. Choice A (75 pounds) ignores the pulley advantage entirely, treating the system like a single fixed pulley. Choice B (150 pounds) counts only two supporting strands, like a single movable pulley. Choice C (225 pounds) uses an MA of 3, possibly miscounting rope segments. Each supporting strand splits the load weight evenly, so doubling strands doubles the lift capacity for the same pull.', true, 'trusted'),
  ('MC-IPH-4', 'MC', 'mc.inclined-plane-hydraulics', 4, 'A hydraulic lift has an input piston area of 4 square inches and an output piston area of 20 square inches. If you need to lift 1,000 pounds, how much input force is required?', '["50 pounds","200 pounds","400 pounds","5,000 pounds"]'::jsonb, 1, 'Hydraulic MA = output area / input area = 20 / 4 = 5. Input force = Load / MA = 1,000 / 5 = 200 pounds. Choice A (50 pounds) corresponds to MA = 20, which would require comparing the output area to a 1-square-inch input. Choice C (400 pounds) cuts the load by 2.5 instead of 5, perhaps using diameter ratio if the pistons were taken as round, but areas are given directly. Choice D (5,000 pounds) multiplies the load by 5 instead of dividing, inverting Pascal''s principle. The input piston always moves with less force than the output when areas are larger downstream.', true, 'trusted'),
  ('MC-IPH-5', 'MC', 'mc.inclined-plane-hydraulics', 4, 'A wedge is driven under one edge of a 500-pound boulder. The wedge is 8 inches long and 2 inches thick at its widest point. What is the mechanical advantage of this wedge?', '["2","4","6","250"]'::jsonb, 1, 'Mechanical advantage of a wedge = length / thickness = 8 / 2 = 4. A longer, thinner wedge provides greater advantage; the 500-pound load is the object being moved, not a factor in calculating MA.', true, 'trusted'),
  ('MC-IPH-6', 'MC', 'mc.inclined-plane-hydraulics', 5, 'A 400-pound object must be raised 6 feet. You can use either a single fixed pulley, a ramp 18 feet long, or a hydraulic jack with a 5:1 area ratio. Ignoring friction, which requires the least input force?', '["single fixed pulley","the 18-foot ramp","the hydraulic jack","all three require identical force"]'::jsonb, 2, 'Compare mechanical advantages, ignoring friction. Fixed pulley: MA = 1, effort = 400 / 1 = 400 lb. 18-foot ramp lifting 6 feet: MA = 18 / 6 = 3, effort = 400 / 3 = 133.3 lb. Hydraulic 5:1: MA = 5, effort = 400 / 5 = 80 lb. The hydraulic jack wins with the highest MA and the smallest required input force. Choice A (fixed pulley) only redirects force and gives no mechanical advantage. Choice B (ramp) helps but at MA = 3 still requires more than 130 pounds. Choice D (all identical) is wrong because each machine has a different MA.', true, 'trusted'),
  ('MC-MOT-1', 'MC', 'mc.motion-projectile', 3, 'A 5-kg ball moving at 6 m/s collides with a stationary 5-kg ball and comes to a complete stop. What is the velocity of the second ball after the collision?', '["0 m/s","3 m/s","6 m/s","12 m/s"]'::jsonb, 2, 'Conservation of momentum: total momentum before equals total momentum after. Before: p = (5 kg)(6 m/s) + (5 kg)(0) = 30 kg m/s. After: first ball is at rest, so all 30 kg m/s must be carried by the second ball: 5 x v = 30, so v = 6 m/s. Choice A (0 m/s) violates conservation; momentum cannot vanish. Choice B (3 m/s) halves the answer, perhaps splitting the momentum across both balls. Choice D (12 m/s) doubles the answer, possibly adding velocities instead of conserving momentum. Equal masses in a head-on elastic-style stop produce a clean velocity transfer.', true, 'trusted'),
  ('MC-MOT-2', 'MC', 'mc.motion-projectile', 3, 'An object is dropped from a height and falls freely under gravity (9.8 m/s²). After 3 seconds, its velocity is approximately:', '["9.8 m/s","19.6 m/s","29.4 m/s","44.1 m/s"]'::jsonb, 2, 'Under free fall starting from rest, velocity equals g times time: v = g x t = 9.8 m/s^2 x 3 s = 29.4 m/s. Choice A (9.8 m/s) is the velocity after only 1 second, ignoring the 3-second duration. Choice B (19.6 m/s) is the velocity after 2 seconds, off by one second. Choice D (44.1 m/s) uses the distance formula d = 0.5 x g x t^2 (which gives 44.1 m) and mislabels it as velocity. Velocity and distance under constant acceleration are different quantities: velocity grows linearly with time, while distance grows with the square of time.', true, 'trusted'),
  ('MC-MOT-3', 'MC', 'mc.motion-projectile', 4, 'A net force of 20 N is applied to a 4-kg object. What is the object''s acceleration?', '["0.2 m/s²","5 m/s²","16 m/s²","80 m/s²"]'::jsonb, 1, 'Newton''s Second Law: a = F / m = 20 N / 4 kg = 5 m/s^2. Choice A (0.2 m/s^2) inverts the formula and divides mass by force (4 / 20). Choice C (16 m/s^2) subtracts mass from force (20 - 4), mixing incompatible units. Choice D (80 m/s^2) multiplies force by mass (20 x 4) instead of dividing, which would give force units squared and is dimensionally invalid. Acceleration scales directly with force and inversely with mass, so heavier objects accelerate less under the same force.', true, 'trusted'),
  ('MC-MOT-4', 'MC', 'mc.motion-projectile', 4, 'A ball is launched horizontally from a cliff at 20 m/s. Ignoring air resistance, what happens to the ball''s horizontal speed as it falls?', '["it increases because gravity accelerates it forward","it decreases because gravity slows horizontal motion","it stays constant because horizontal and vertical motions are independent","it reaches zero at peak height"]'::jsonb, 2, 'In projectile motion the horizontal and vertical components are independent. Gravity acts only vertically, so without air resistance there is no force in the horizontal direction. With zero horizontal force, Newton''s First Law keeps the horizontal velocity constant at 20 m/s for the entire fall. Choice A (increases) would require a forward-pointing force, which gravity is not. Choice B (decreases) would require a backward-pointing force, also absent without air resistance. Choice D (zero at peak height) confuses this with a vertically launched projectile; a horizontally launched ball has no peak, only a parabolic fall.', true, 'trusted'),
  ('MC-MOT-5', 'MC', 'mc.motion-projectile', 4, 'Two identical hockey pucks rest on frictionless ice. Puck A is pushed with twice the force of Puck B for the same amount of time. Compared to Puck B, Puck A will have:', '["the same final velocity","twice the final velocity","four times the final velocity","half the final velocity"]'::jsonb, 1, 'Impulse equals force times time and equals the change in momentum: F x t = m x delta-v. Same time and same mass, but double the force on puck A means double the impulse and therefore double the change in velocity. Starting from rest, the final velocity of A is twice that of B. Choice A (same velocity) ignores the force difference. Choice C (four times) squares the force ratio, which would apply to kinetic energy (KE proportional to v^2), not momentum. Choice D (half) inverts the relationship, treating more force as if it slowed the puck.', true, 'trusted'),
  ('MC-MOT-6', 'MC', 'mc.motion-projectile', 5, 'A 10-kg object traveling at 4 m/s east collides and sticks to a 6-kg object traveling at 4 m/s west. What is the velocity of the combined mass after the collision?', '["4 m/s east","1 m/s east","0 m/s (they stop)","2.5 m/s west"]'::jsonb, 1, 'Momentum is a vector. Taking east as positive: p_total = (10)(+4) + (6)(-4) = 40 - 24 = 16 kg m/s east. After sticking, combined mass = 10 + 6 = 16 kg. Common velocity = 16 / 16 = 1 m/s east. Choice A (4 m/s east) ignores the westbound object''s momentum entirely. Choice C (0 m/s) treats the speeds as equal-and-opposite without weighting by mass; only equal masses would fully cancel. Choice D (2.5 m/s west) assumes the lighter object wins the collision, but in an inelastic collision the direction follows the larger momentum, which is east.', true, 'trusted'),
  ('GS-PHY-1', 'GS', 'gs.physics-mechanics', 3, 'A book rests on a table without moving. According to Newton''s First Law, the book remains at rest because:', '["gravity is not acting on it","the table exerts an upward normal force that balances gravity","the book has no mass","friction from the table pushes the book upward"]'::jsonb, 1, 'Newton''s First Law states that an object at rest stays at rest when net force is zero. The table''s normal force (upward) exactly balances gravity (downward), producing zero net force. Friction acts horizontally and does not support the book''s weight.', true, 'trusted'),
  ('GS-PHY-2', 'GS', 'gs.physics-mechanics', 3, 'Which simple machine is a screw most closely related to?', '["lever","wheel and axle","inclined plane","pulley"]'::jsonb, 2, 'A screw is an inclined plane wrapped around a cylinder. The threads form a spiral ramp that lets a small rotational force advance the screw a small distance with each turn, trading turns for depth, exactly like walking up a long shallow ramp instead of a short steep one. A lever pivots about a fulcrum and uses arm length to multiply force. A wheel and axle multiplies force through different radii. A pulley redirects force through a rope. None of those involve a ramp wound into a cylinder the way a screw does.', true, 'trusted'),
  ('GS-PHY-3', 'GS', 'gs.physics-mechanics', 4, 'A person lifts a 60-Newton box 2 meters off the ground. How much work is done?', '["30 joules","62 joules","120 joules","240 joules"]'::jsonb, 2, 'Work = Force × Distance = 60 N × 2 m = 120 joules. Work is measured in joules (newton-meters). Dividing instead of multiplying gives 30 — a common sign-flip error. Adding (60 + 2 = 62) confuses the formula.', true, 'trusted'),
  ('GS-PHY-4', 'GS', 'gs.physics-mechanics', 4, 'A compressed spring stores energy as:', '["kinetic energy","thermal energy","potential energy","chemical energy"]'::jsonb, 2, 'A compressed or stretched spring holds elastic potential energy, stored in the deformed structure and ready to do work when released. Kinetic energy is energy of motion, which the spring only has while the coils are actively moving, not while held still in compression. Thermal energy would mean the spring heated up, which is not the dominant effect of squeezing it. Chemical energy lives in molecular bonds, like in gasoline or a battery, and is unrelated to mechanical deformation. Position and shape, not motion or heat, are what store the energy here.', true, 'trusted'),
  ('GS-PHY-5', 'GS', 'gs.physics-mechanics', 4, 'Two balls of different mass are dropped from the same height at the same time in a vacuum. Which hits the ground first?', '["the heavier ball, because gravity pulls it harder","the lighter ball, because it has less air resistance","they hit at the same time","it depends on the shape of each ball"]'::jsonb, 2, 'In a vacuum there is no air resistance. Gravity accelerates all objects equally regardless of mass (9.8 m/s²). This is what Galileo demonstrated — the common misconception is that heavier objects fall faster because gravity ''pulls harder,'' but acceleration is mass-independent.', true, 'trusted'),
  ('GS-PHY-6', 'GS', 'gs.physics-mechanics', 5, 'A 500-W electric motor lifts a 200-N load vertically. How high can it lift the load in 4 seconds (ignoring friction)?', '["2.5 meters","5 meters","10 meters","40 meters"]'::jsonb, 2, 'Power equals work divided by time, so total work is 500 W times 4 s, or 2,000 joules. Work also equals force times distance, so distance equals 2,000 J divided by 200 N, which is 10 meters. The 40-meter answer multiplies power by time directly without dividing by force, a unit-confusion error. The 2.5-meter answer divides force by power, inverting the relationship. The 5-meter answer divides time by force. Keeping the units paired (J = N·m, W = J/s) prevents the wrong combination.', true, 'trusted'),
  ('EI-CON-2', 'EI', 'ei.conductors-insulators', 3, 'A semiconductor differs from a conductor because a semiconductor:', '["conducts electricity under all conditions","never allows current to flow","conducts electricity only under certain conditions (such as added heat or doping)","has the same resistance as an insulator"]'::jsonb, 2, 'Semiconductors like silicon and germanium sit between conductors and insulators. Pure silicon barely conducts at room temperature, but doping it with phosphorus (n-type) or boron (p-type), heating it, or shining light on it can flip it into a conductive state. Choice A (conducts always) describes a conductor like copper. Choice B (never conducts) describes a true insulator like glass. Choice D (same resistance as insulator) ignores the controllable middle ground that makes transistors and integrated circuits possible in the first place.', true, 'trusted'),
  ('EI-CON-3', 'EI', 'ei.conductors-insulators', 4, 'Which of the following best explains why aluminum wire requires a larger gauge than copper wire to carry the same current safely?', '["aluminum is magnetic, which resists current flow","aluminum has higher resistivity than copper, so a larger cross-section is needed to reduce resistance","aluminum melts at a lower temperature and must be thicker for safety","aluminum has lower resistivity, making it harder for electrons to move"]'::jsonb, 1, 'Resistance follows R = ρL/A. Aluminum''s resistivity (about 2.8 × 10⁻⁸ Ω·m) is roughly 1.6 times copper''s (1.7 × 10⁻⁸ Ω·m). To match copper''s resistance at the same length, aluminum needs a proportionally larger cross-sectional area, meaning a larger gauge. Choice A (magnetic) is wrong; aluminum is non-magnetic. Choice C (melting point) confuses ampacity ratings with the underlying resistivity argument. Choice D inverts the truth by claiming aluminum has lower resistivity, when it actually has higher resistivity than copper.', true, 'trusted'),
  ('EI-CON-4', 'EI', 'ei.conductors-insulators', 4, 'Wet wood does not normally conduct electricity well, but wet wood with dissolved salts conducts much better. This demonstrates that:', '["wood becomes a semiconductor when cut","dissolved ions in water create charge carriers that enable conduction","heat from the salt lowers electrical resistance","salt acts as an insulator that traps electrons"]'::jsonb, 1, 'Pure water is a poor conductor, but dissolved salts (ionic compounds) break into positive and negative ions that can carry charge through the liquid. This is why saltwater and moist soil are better conductors than pure water alone.', true, 'trusted'),
  ('EI-CON-5', 'EI', 'ei.conductors-insulators', 5, 'A technician handles a live wire while standing on a dry rubber mat. Why does the rubber mat protect the technician?', '["rubber absorbs excess electrical current and releases it as heat","rubber is an insulator that blocks the flow of current from the technician to ground","rubber becomes positively charged and repels electrons","rubber stores electrical charge, reducing voltage at the technician''s feet"]'::jsonb, 1, 'Current needs a complete path from source to ground. Rubber has extremely high resistivity, so a dry rubber mat breaks the path between the technician''s body and ground, and no meaningful current flows through the technician. Choice A confuses rubber with a resistor that absorbs and dissipates energy as heat. Choice C invents a charge-repulsion mechanism rubber does not have at normal scales. Choice D describes a capacitor storing charge, which is not how an insulating mat protects against shock; it simply blocks the return path.', true, 'trusted'),
  ('EI-OHM-1', 'EI', 'ei.ohms-law-power', 3, 'A light bulb operates on 120 volts and draws 2 amperes. What is the power consumption of the bulb?', '["60 watts","122 watts","240 watts","480 watts"]'::jsonb, 2, 'Power = Voltage × Current = P = IV = 120 × 2 = 240 watts. Dividing (120/2 = 60) is the most common error — students confuse the power formula with Ohm''s Law for resistance.', true, 'trusted'),
  ('EI-OHM-2', 'EI', 'ei.ohms-law-power', 3, 'Three resistors of 4 ohms, 6 ohms, and 2 ohms are connected in series. What is the total resistance of the circuit?', '["1 ohm","6 ohms","12 ohms","48 ohms"]'::jsonb, 2, 'In a series circuit, total resistance = R₁ + R₂ + R₃ = 4 + 6 + 2 = 12 ohms. The parallel formula (1/R) is often mistakenly applied here; in series, resistances simply add together.', true, 'trusted'),
  ('EI-OHM-3', 'EI', 'ei.ohms-law-power', 4, 'A 12-volt battery powers a circuit with two resistors in series: 3 ohms and 1 ohm. What is the power dissipated by the 3-ohm resistor?', '["9 watts","12 watts","27 watts","36 watts"]'::jsonb, 2, 'Total resistance = 3 + 1 = 4 ohms. Current = V/R = 12/4 = 3 amperes. Power in the 3-ohm resistor: P = I²R = 3² × 3 = 9 × 3 = 27 watts. Using total voltage instead of calculating current first gives 48 W — a two-step problem requiring correct sequencing.', true, 'trusted'),
  ('EI-OHM-4', 'EI', 'ei.ohms-law-power', 4, 'Two resistors are connected in parallel: one is 6 ohms and one is 3 ohms. What is the combined resistance?', '["9 ohms","4.5 ohms","2 ohms","1 ohm"]'::jsonb, 2, 'Parallel resistance formula: 1/R_total = 1/6 + 1/3 = 1/6 + 2/6 = 3/6 = 1/2. So R_total = 2 ohms. A common error is adding resistances as in series (6 + 3 = 9). In parallel, total resistance is always less than the smallest individual resistor.', true, 'trusted'),
  ('EI-OHM-5', 'EI', 'ei.ohms-law-power', 5, 'A 9-volt battery powers a parallel circuit. Branch 1 has a 9-ohm resistor; Branch 2 has an 18-ohm resistor. What is the total current drawn from the battery?', '["0.5 amperes","1 ampere","1.5 amperes","3 amperes"]'::jsonb, 2, 'In parallel circuits, voltage across each branch equals source voltage. Branch 1 current: I₁ = 9/9 = 1 A. Branch 2 current: I₂ = 9/18 = 0.5 A. Total current = I₁ + I₂ = 1.5 A. Students who use combined parallel resistance alone often get the right answer but skip confirming via branch currents — here either method works.', true, 'trusted'),
  ('AR-WRD-1', 'AR', 'ar.word-problems', 4, 'A supply truck can carry 4,800 pounds. It is loaded with boxes weighing 60 pounds each and crates weighing 120 pounds each. If there are 20 crates, how many boxes can also be loaded without exceeding the limit?', '["20 boxes","40 boxes","48 boxes","56 boxes"]'::jsonb, 1, 'Crates use: 20 × 120 = 2,400 lbs. Remaining capacity: 4,800 − 2,400 = 2,400 lbs. Number of boxes: 2,400 / 60 = 40 boxes. Dividing remaining capacity by 120 (crate weight) gives 20 — the error of using the wrong unit weight.', true, 'trusted'),
  ('AR-WRD-2', 'AR', 'ar.word-problems', 4, 'A fuel tank is 3/4 full and holds 24 gallons at that level. How many total gallons does the tank hold when completely full?', '["18 gallons","30 gallons","32 gallons","36 gallons"]'::jsonb, 2, 'If 3/4 of the tank = 24 gallons, then 1/4 = 8 gallons, and the full tank = 4 × 8 = 32 gallons. Multiplying 24 × (3/4) = 18 gallons is the reverse error — treating the fraction as a multiplier instead of recognizing it represents the current fill level.', true, 'trusted'),
  ('AR-PCT-1', 'AR', 'ar.percent', 4, 'A piece of equipment originally cost $800. After a 15% discount it was purchased, then later sold for 10% more than the purchase price. What was the final selling price?', '["$748.00","$756.00","$770.00","$792.00"]'::jsonb, 0, 'Apply percentages sequentially: $800 × (1 − 0.15) = $680, then $680 × (1 + 0.10) = $748. Common error: netting the percentages to −5% gives $760, which is wrong because each percent applies to a different base.', true, 'trusted'),
  ('AR-RAT-1', 'AR', 'ar.ratio-proportion', 4, 'A military convoy travels 120 miles in 2.5 hours. At the same rate, how far will it travel in 4 hours?', '["160 miles","192 miles","200 miles","240 miles"]'::jsonb, 1, 'Speed = 120 ÷ 2.5 = 48 mph, so distance in 4 hours = 48 × 4 = 192 miles. Choice 160 miles uses 40 mph, rounding 48 down a bit too aggressively. Choice 200 miles rounds 48 up to 50 mph before multiplying, a clean but inaccurate shortcut. Choice 240 miles doubles 120 because 4 is roughly double 2.5, skipping the rate calculation entirely and treating the time ratio as 2:1.', true, 'trusted'),
  ('AR-ALG-1', 'AR', 'ar.arithmetic-fundamentals', 5, 'A storage room has 3 shelves. Each shelf holds twice as many items as the shelf below it. The bottom shelf holds 15 items. How many items are in the storage room in total?', '["45 items","90 items","105 items","120 items"]'::jsonb, 2, 'Build the sequence: bottom = 15, middle = 30, top = 60, so total = 15 + 30 + 60 = 105. Choice 45 items adds 15 three times, ignoring the doubling entirely. Choice 90 items doubles 15 once and triples the result (15 × 2 × 3), applying the doubling rule flat across all shelves instead of compounding it. Choice 120 items doubles to 60 only and then doubles again to 120, picking the top shelf alone after one extra doubling step.', true, 'trusted'),
  ('MK-ALG-1', 'MK', 'mk.algebra-linear', 4, 'If 5(x − 3) = 2x + 6, what is the value of x?', '["x = 3","x = 5","x = 7","x = 9"]'::jsonb, 2, 'Distribute: 5x − 15 = 2x + 6. Subtract 2x: 3x − 15 = 6. Add 15: 3x = 21. x = 7. A common error is failing to distribute the 5 to −3, giving 5x − 3 = 2x + 6 and solving to x = 3.', true, 'trusted'),
  ('MK-GEO-1', 'MK', 'mk.geometry', 4, 'A cylindrical water tank has a radius of 3 feet and a height of 10 feet. What is its volume? (Use π ≈ 3.14)', '["94.2 cubic feet","188.4 cubic feet","282.6 cubic feet","942 cubic feet"]'::jsonb, 2, 'Volume of a cylinder = π × r² × h = 3.14 × 9 × 10 = 282.6 cubic feet. Using diameter (6) instead of radius (3) gives 3.14 × 36 × 10 = 1,130.4 — squaring the diameter is the most common error. Using r = 3 without squaring gives 3.14 × 3 × 10 = 94.2.', true, 'trusted'),
  ('MK-FRC-1', 'MK', 'mk.fractions-decimals', 5, 'A fuel mixture is 2/5 diesel and the rest is gasoline. If the tank holds 60 liters, how many more liters of gasoline than diesel does it contain?', '["12 liters more gasoline","24 liters more gasoline","12 liters more diesel","36 liters more gasoline"]'::jsonb, 0, 'Diesel = (2/5) × 60 = 24 liters. Gasoline = 60 − 24 = 36 liters. Difference = 36 − 24 = 12 liters more gasoline. Choosing 24 liters confuses the diesel volume with the difference; choosing 36 liters is the gasoline volume, not the difference between the two.', true, 'trusted'),
  ('WK-CTX-HARD-1', 'WK', 'wk.context-clues', 5, 'In the sentence ''The politician''s OBSEQUIOUS deference to every donor in the room struck journalists as calculated rather than genuine,'' the word OBSEQUIOUS most nearly means:', '["bold and outspoken","excessively eager to please or serve","professionally courteous","openly hostile"]'::jsonb, 1, 'The phrase ''struck journalists as calculated rather than genuine'' pins the meaning: the deference went beyond what real courtesy looks like. Obsequious specifically labels fawning servility, often used negatively. ''Bold and outspoken'' is the direct opposite of deference. ''Openly hostile'' also contradicts the sentence. ''Professionally courteous'' is the trickiest distractor since deference can be courteous, but the sentence explicitly distinguishes the politician''s behavior from genuine courtesy by calling it calculated. Only Excessively eager to please or serve matches the negative excess the clue establishes.', true, 'trusted'),
  ('WK-SYN-HARD-1', 'WK', 'wk.synonyms', 4, 'EPHEMERAL most nearly means:', '["ancient","lasting only a short time","extraordinarily rare","deeply emotional"]'::jsonb, 1, 'Ephemeral means lasting only a brief moment, from Greek ephemeros ''lasting a day,'' as in ''the ephemeral mayfly lives less than 24 hours.'' Ancient is the direct antonym, naming long duration rather than brevity. Extraordinarily rare is a partial-overlap trap: ephemeral things are often hard to catch, but rarity is about scarcity, not duration. Deeply emotional is a register trap, drawing on the poetic feel of the word rather than its meaning. Only Lasting only a short time captures the core of brief duration.', true, 'trusted'),
  ('WK-SYN-HARD-2', 'WK', 'wk.synonyms', 5, 'VERACIOUS most nearly means:', '["extremely hungry","truthful","speedy","aggressive"]'::jsonb, 1, 'Veracious means habitually truthful, as in ''a veracious witness whose testimony has never been contradicted.'' The VER- root means truth (verify, verdict, veracity). Extremely hungry is the classic sound-alike trap with voracious, which uses VOR- (to devour, as in carnivore, devour). Speedy is unrelated; truthfulness has no speed component. Aggressive is a register trap drawing on the harsh sound, but veracious is a neutral quality of honesty, not force. Only Truthful matches VER-, while voracious lives one letter away.', true, 'trusted'),
  ('PC-INF-HARD-1', 'PC', 'pc.inference', 4, 'Read the passage below and answer the question.

"The lab''s results were submitted three times before the review board accepted them. Each submission included additional documentation requested by the board, yet the board raised new objections with each round. When the research was finally published, it overturned a theory the board''s chair had authored fifteen years earlier. The chair did not recuse himself from the review."

What can most reasonably be inferred from this passage?', '["The research contained significant methodological flaws that required correction.","The board''s repeated objections may have been influenced by a conflict of interest.","Government agencies routinely require three rounds of submission for new research.","The board chair ultimately supported the research once it was explained clearly."]'::jsonb, 1, 'The detail that the board kept finding new objections — and that the final research contradicted the chair''s own published theory — strongly implies a conflict of interest. Choice A is contradicted by the research''s eventual publication. Choices C and D are not supported by any passage detail.', true, 'trusted'),
  ('PC-MAIN-HARD-1', 'PC', 'pc.main-idea', 4, 'Read the passage below and answer the question.

"Maps are not neutral documents. Every map involves choices: what to include, what to omit, which areas to enlarge, and which projection to use. The Mercator projection, still common in classrooms, inflates the size of land near the poles — making Greenland appear as large as Africa, when Africa is actually fourteen times larger. A map teaches not just geography but a way of seeing the world."

What is the main idea of this passage?', '["The Mercator projection is the most accurate map projection available.","Maps reflect decisions and assumptions that shape how people perceive the world.","Africa is fourteen times larger than Greenland.","Classroom maps should be replaced with digital navigation tools."]'::jsonb, 1, 'The passage opens and closes with the argument that maps embed choices and teach a ''way of seeing.'' The Greenland/Africa fact is supporting evidence, not the main point. Choice D is never mentioned; Choice A contradicts the passage''s argument.', true, 'trusted'),
  ('MK-ALG-HARD-1', 'MK', 'mk.algebra-linear', 5, 'Depot A charges a $40 setup fee plus $12 per unit ordered. Depot B charges no setup fee but $16 per unit. At exactly how many units do the two depots cost the same?', '["5 units","8 units","10 units","12 units"]'::jsonb, 2, 'Set costs equal: 40 + 12n = 16n. Subtract 12n from both sides: 40 = 4n. Divide: n = 10 units. At 10 units: Depot A = 40 + 120 = $160; Depot B = 16 × 10 = $160. Confirm equal. A common error is setting up the equation as 40 + 16n = 12n, which gives a negative n because the student reverses which depot has the base fee.', true, 'trusted'),
  ('MK-GEO-HARD-1', 'MK', 'mk.geometry', 4, 'A right triangle has legs of 9 and 12. What is the length of the hypotenuse?', '["13","15","17","21"]'::jsonb, 1, 'Pythagorean theorem: c² = 9² + 12² = 81 + 144 = 225. c = √225 = 15. This is a classic 3-4-5 triple scaled by 3 (9-12-15). Adding the legs (9 + 12 = 21) or averaging them are common wrong approaches.', true, 'trusted'),
  ('AR-PCT-HARD-1', 'AR', 'ar.percent', 5, 'A soldier scores 72 on a first test and 88 on a second test. What is the percent increase from the first score to the second score, rounded to the nearest whole percent?', '["16%","18%","22%","25%"]'::jsonb, 2, 'Percent increase = (new − old) / old × 100 = (88 − 72) / 72 × 100 = 16/72 × 100 ≈ 22.2%, rounded to 22%. Dividing by the new score (16/88 ≈ 18%) is the most common error — percent change always uses the original value as the base.', true, 'trusted'),
  ('WK-CTX-D2-1', 'WK', 'wk.context-clues', 2, 'In the sentence ''The trail looked safe but proved TREACHEROUS, with hidden drop-offs and unstable footing,'' the word TREACHEROUS most nearly means:', '["deceptively dangerous","exhausting","remote","unfamiliar"]'::jsonb, 0, 'Treacherous means deceptively dangerous — something that appears safe but conceals serious hazards. The new stem reinforces this with ''hidden drop-offs and unstable footing.'' Exhausting, remote, and unfamiliar describe possible trail qualities but do not capture the deceptive, unpredictable danger that treacherous conveys.', true, 'trusted'),
  ('WK-PFX-D2-1', 'WK', 'wk.prefixes-suffixes', 2, 'The prefix MIS- means wrongly or badly. MISJUDGE therefore means:', '["to judge again","to judge fairly","to judge wrongly","to refuse to judge"]'::jsonb, 2, 'MISJUDGE breaks down as MIS- (wrongly, badly) plus JUDGE. Compare mislead (lead wrongly), misfire (fire wrongly), misuse (use wrongly), misread (read wrongly). ''To judge again'' would require RE- (again), as in rejudge or reconsider, a different prefix. ''To judge fairly'' is the opposite of the morpheme MIS-, which always signals error. ''To refuse to judge'' would require a negating or rejecting prefix like UN-, NON-, or DIS-, not MIS-, which means the judgment happened but came out wrong. Only To judge wrongly tracks MIS-.', true, 'trusted'),
  ('AS-MNT-D2-1', 'AS', 'as.maintenance-repair', 2, 'Why is it important to check the coolant level in a vehicle''s radiator regularly?', '["Low coolant improves fuel economy","Low coolant can cause the engine to overheat","Coolant affects the transmission shift points","Coolant level determines oil viscosity"]'::jsonb, 1, 'Coolant is the working fluid that absorbs heat at the cylinder head and block and carries it out to the radiator. If the level falls too low, less fluid is available to soak up the heat, temperatures climb, and you can warp a head, blow a head gasket, or crack the block. Low coolant does not improve fuel economy, and an overheating engine usually hurts economy by running rich. Transmission shift points come from the transmission control module, not the cooling system. Oil viscosity is determined by the oil grade itself.', true, 'trusted'),
  ('GS-PHY-D2-1', 'GS', 'gs.physics-mechanics', 2, 'Which of the following is an example of potential energy?', '["a spinning fan blade","a rock sitting on a high cliff","a car moving at 60 mph","sound traveling through air"]'::jsonb, 1, 'Potential energy is stored energy from position or configuration. A rock on a cliff has gravitational potential energy: pull mass times g times height, and the rock can convert all of it to kinetic energy if it falls. A spinning fan blade is in motion, so its energy is kinetic. A car moving at 60 mph is also kinetic, and a fast-moving car carries a lot of it because KE scales with velocity squared. Sound traveling through air is a wave carrying kinetic energy through molecular vibration, not stored stationary energy.', true, 'trusted'),
  ('MC-MOT-D2-1', 'MC', 'mc.motion-projectile', 2, 'Newton''s First Law states that an object in motion stays in motion unless acted on by an outside force. Which of the following best demonstrates this law?', '["a ball speeding up as it rolls downhill","a hockey puck sliding across frictionless ice at constant speed","a rocket accelerating after launch","a pendulum slowing down due to air resistance"]'::jsonb, 1, 'Newton''s First Law states that an object continues in uniform motion unless a net external force acts on it. The frictionless-ice puck has no horizontal force acting on it, so its constant speed is a direct demonstration of inertia. Choice A (ball rolling downhill speeding up) shows acceleration caused by gravity along the incline, which is the Second Law in action. Choice C (rocket accelerating) involves a thrust force, again Second Law. Choice D (pendulum slowing) involves air resistance and gravity, both unbalanced forces, so motion changes; this illustrates a violation of the First Law''s idealized condition, not its demonstration.', true, 'trusted'),
  ('EI-OHM-D2-1', 'EI', 'ei.ohms-law-power', 2, 'A circuit has a resistance of 8 ohms and a current of 3 amperes flowing through it. What is the voltage across the circuit?', '["2.7 volts","11 volts","24 volts","64 volts"]'::jsonb, 2, 'Ohm''s Law: V = I × R = 3 × 8 = 24 volts. Dividing instead of multiplying (8 / 3 ≈ 2.7) is the most common error. Adding (3 + 8 = 11) confuses the formula entirely.', true, 'trusted'),
  ('MK-GEO-D2-1', 'MK', 'mk.geometry', 2, 'What is the perimeter of a rectangle that is 8 feet long and 5 feet wide?', '["13 feet","26 feet","40 feet","80 feet"]'::jsonb, 1, 'Perimeter = 2 × (length + width) = 2 × (8 + 5) = 2 × 13 = 26 feet. A common error is adding all four sides without doubling (8 + 5 = 13) or multiplying length by width to get area (40 square feet) instead of perimeter.', true, 'trusted'),
  ('AR-AF-1', 'AR', 'ar.arithmetic-fundamentals', 3, 'A crate holds 24 bottles. A store receives 15 crates. After selling 120 bottles, how many bottles remain?', '["120","180","240","300"]'::jsonb, 2, 'Total bottles received = 24 × 15 = 360, then subtract sold: 360 − 120 = 240 remain. Choice 120 picks the number sold instead of the number left, a direct misread of the question. Choice 180 subtracts the sold count from a wrong multiplication (24 × 12.5 = 300, then 300 − 120). Choice 300 uses 20 × 15 = 300 by dropping the 4 in 24, then forgets to subtract anything afterward.', true, 'trusted'),
  ('AR-AF-2', 'AR', 'ar.arithmetic-fundamentals', 3, 'A soldier buys 4 notebooks at $3 each and 6 pens at $1.25 each. What is the total cost?', '["$16.50","$17.50","$18.75","$19.50"]'::jsonb, 3, 'Total = (4 × $3) + (6 × $1.25) = $12 + $7.50 = $19.50. Choice $16.50 uses 6 × $0.75 for the pens, dropping the whole-dollar part of $1.25. Choice $17.50 rounds pens to $1 each ($6) and adds $11.50 in notebooks, slipping a dollar. Choice $18.75 multiplies 5 × $1.25 = $6.25 for pens, miscounting six pens as five before adding to the $12 notebook total plus $0.50.', true, 'trusted'),
  ('AR-AF-3', 'AR', 'ar.arithmetic-fundamentals', 4, 'A truck can carry 850 pounds. A soldier loads 10 boxes at 75 pounds each. How many pounds of capacity remain?', '["75","100","125","150"]'::jsonb, 1, 'Load = 10 × 75 = 750 lb, so remaining capacity = 850 − 750 = 100 lb. Choice 75 reports the weight of a single box instead of the leftover capacity, a misread of the question. Choice 125 subtracts 725 instead of 750 (dropped a 5 in the box-multiplication). Choice 150 doubles one box weight to arrive at a tempting round number that has no basis in the setup.', true, 'trusted'),
  ('AR-AF-4', 'AR', 'ar.arithmetic-fundamentals', 3, 'A barracks has 6 rooms, each holding 4 soldiers. If 14 soldiers are currently assigned, how many empty beds remain?', '["6","8","10","14"]'::jsonb, 2, 'Total beds = 6 × 4 = 24, then empty beds = 24 − 14 = 10. Choice 6 picks the room count by mistake instead of completing the bed count. Choice 8 uses (4 × 4) − 14 = 2, then adds 6 rooms or similar mix-up between rooms and beds. Choice 14 reports the number of soldiers currently assigned instead of the empty beds, the most direct misread of the question.', true, 'trusted'),
  ('AR-AF-5', 'AR', 'ar.arithmetic-fundamentals', 4, 'A soldier earns $2,880 per month. After paying $720 in rent and $340 in other bills, she saves the rest. How much does she save over 4 months?', '["$1,820","$6,400","$7,280","$11,520"]'::jsonb, 2, 'Monthly savings = $2,880 − $720 − $340 = $1,820, and 4 months × $1,820 = $7,280. Choice $1,820 reports one month of savings, forgetting the four-month window. Choice $6,400 uses ($2,880 − $720) × 4, skipping the second bill of $340. Choice $11,520 multiplies the full $2,880 paycheck by 4 months and ignores both deductions, treating the question as gross pay only.', true, 'trusted'),
  ('AR-RP-1', 'AR', 'ar.ratio-proportion', 3, 'A recipe uses 3 cups of flour for every 2 cups of sugar. How many cups of sugar are needed if you use 12 cups of flour?', '["6","8","9","18"]'::jsonb, 1, 'Sugar = (2/3) × 12 = 8 cups, applying the sugar-to-flour ratio directly. Choice 6 halves the flour count, treating the ratio as a clean 2:1. Choice 9 uses 3/4 of 12, confusing the ratio parts with the total ratio sum. Choice 18 flips the ratio and computes 3/2 × 12 = 18, giving more sugar than flour, which contradicts a 3:2 flour-heavy ratio.', true, 'trusted'),
  ('AR-RP-2', 'AR', 'ar.ratio-proportion', 3, 'The exchange rate is 1 U.S. dollar = 0.85 euros. A soldier converts $240 to euros. How many euros does she receive?', '["180","196","204","282"]'::jsonb, 2, 'Euros = dollars × rate = 240 × 0.85 = 204 euros. Choice 180 uses 0.75 instead of 0.85, misreading the conversion factor. Choice 196 multiplies by about 0.82, rounding the rate down before the multiplication. Choice 282 divides 240 ÷ 0.85, converting in the reverse direction as if 240 euros were being converted to dollars, the classic currency-direction trap.', true, 'trusted'),
  ('AR-RP-4', 'AR', 'ar.ratio-proportion', 5, 'A squad of 12 soldiers can build a wall in 8 hours. How long will it take a squad of 16 soldiers to build the same wall at the same work rate?', '["4 hours","5 hours","6 hours","7 hours"]'::jsonb, 2, 'Total work = 12 × 8 = 96 soldier-hours, so with 16 soldiers the time = 96 ÷ 16 = 6 hours. This is inverse proportion: more workers means less time. Choice 4 hours halves the time because the crew grew, but 16 is not double 12. Choice 5 hours scales linearly (8 − 3), treating extra soldiers as a flat hour subtraction. Choice 7 hours barely reduces the time, as if 4 extra soldiers only shave off 1 hour.', true, 'trusted'),
  ('AR-RP-5', 'AR', 'ar.ratio-proportion', 4, 'A kitchen uses oil and vinegar in a 5:3 ratio to make dressing. A cook needs 64 ounces of dressing total. How many ounces of vinegar are needed?', '["16","20","24","40"]'::jsonb, 2, 'Total parts = 5 + 3 = 8, so vinegar = (3/8) × 64 = 24 ounces. Choice 16 uses (2/8) × 64, miscounting parts or off-by-one on the vinegar share. Choice 20 uses (5/16) × 64, mixing the parts-of-eight with a parts-of-sixteen denominator. Choice 40 takes (5/8) × 64, giving the oil portion instead of the vinegar portion, the classic which-side-of-the-ratio trap.', true, 'trusted'),
  ('AR-RP-6', 'AR', 'ar.ratio-proportion', 3, 'A kitchen uses salt and pepper in a ratio of 4:1 by weight. If a cook uses 20 grams of salt, how many grams of pepper are needed?', '["4","5","8","16"]'::jsonb, 1, 'Pepper = salt ÷ 4 = 20 ÷ 4 = 5 grams, applying the 4:1 ratio directly. Choice 4 picks the larger ratio number itself rather than scaling it against the 20 grams. Choice 8 doubles the correct answer, treating the ratio as 4:2 by mistake. Choice 16 subtracts 4 from 20, mixing subtraction with the ratio relationship instead of dividing.', true, 'trusted'),
  ('AR-RP-7', 'AR', 'ar.ratio-proportion', 4, 'A supply truck carries canned goods and dry goods in a 3:5 ratio by weight. The total shipment weighs 640 pounds. How many pounds of canned goods are delivered?', '["160","200","240","400"]'::jsonb, 2, 'Total parts = 3 + 5 = 8. Each part = 640 ÷ 8 = 80 lb. Canned goods = 3 × 80 = 240 lb. The trap is using 3/5 of 640 = 384.', true, 'trusted'),
  ('AR-PC-1', 'AR', 'ar.percent', 3, 'A jacket originally costs $80. It is on sale for 25% off. What is the sale price?', '["$20","$55","$60","$65"]'::jsonb, 2, 'Sale price = $80 × (1 − 0.25) = $80 × 0.75 = $60. Choice $20 reports the discount amount ($80 × 0.25) instead of the sale price, a misread of what is asked. Choice $55 subtracts $25 (treating 25% as a flat dollar amount). Choice $65 subtracts $15, using a roughly 19% discount or rounding $20 down to $15 in the discount step.', true, 'trusted'),
  ('AR-PC-2', 'AR', 'ar.percent', 3, 'A soldier''s physical fitness score increased from 60 to 75. What is the percent increase?', '["15%","20%","25%","30%"]'::jsonb, 2, 'Percent change = (new − old) / old × 100 = (75 − 60) / 60 × 100 = 15/60 × 100 = 25%. Choice 15% reports the raw point gain as if a percentage, treating each point as one percent. Choice 20% divides 15 by the new value 75 instead of the original 60, the most common percent-change error. Choice 30% doubles the raw gain, treating each point as 2%.', true, 'trusted'),
  ('AR-PC-3', 'AR', 'ar.percent', 4, 'A meal costs $36. A 15% tip and a separate 10% service fee are both applied to the original $36 bill. What is the total amount paid?', '["$40.68","$43.20","$45.00","$45.36"]'::jsonb, 2, 'Tip = 15% × $36 = $5.40. Service fee = 10% × $36 = $3.60. Total = $36 + $5.40 + $3.60 = $45.00. The trap is compounding the service fee onto the tipped price.', true, 'trusted'),
  ('AR-PC-4', 'AR', 'ar.percent', 3, 'A soldier invests $1,000 at 6% simple annual interest. How much interest is earned after 3 years?', '["$60","$180","$191","$600"]'::jsonb, 1, 'Simple interest = P × r × t = $1,000 × 0.06 × 3 = $180. Choice $60 computes one year''s interest only and forgets to multiply by the 3-year period. Choice $191 applies compound interest (1,000 × 1.06³ − 1,000 ≈ 191), but the problem specifies simple interest. Choice $600 uses 60% instead of 6%, shifting the decimal one place during the rate setup.', true, 'trusted'),
  ('AR-PC-5', 'AR', 'ar.percent', 4, 'A store marks up a $50 item by 20%, then offers a 10% discount on the marked-up price. What is the final selling price?', '["$50.00","$54.00","$55.00","$58.00"]'::jsonb, 1, 'Final = $50 × 1.20 × 0.90 = $60 × 0.90 = $54. Choice $50.00 assumes +20% and −10% cancel back to the original price, but the percentages apply to different bases. Choice $55.00 nets the rates additively (+20% − 10% = +10%) and applies that single rate to $50. Choice $58.00 applies the 10% discount to the original $50 first and then adds the 20% markup, mixing the order of operations.', true, 'trusted'),
  ('AR-PC-6', 'AR', 'ar.percent', 3, 'A town''s population grew from 4,000 to 4,600 in one year. What was the percent increase?', '["12.5%","13%","15%","16%"]'::jsonb, 2, 'Percent increase = (new − old) / old × 100 = 600 / 4,000 × 100 = 15%. Choice 12.5% divides 600 by 4,800, slightly inflating the base population beyond the original. Choice 13% divides 600 by 4,600, using the new total as the base, the most common percent-change reversal trap. Choice 16% divides 600 by 3,750 or rounds 15% up to a friendlier whole number, overshooting the true ratio by a single percentage point.', true, 'trusted'),
  ('AR-RD-1', 'AR', 'ar.rate-distance-time', 3, 'A soldier runs at 6 miles per hour. How far does she run in 45 minutes?', '["3.5 miles","4 miles","4.5 miles","5 miles"]'::jsonb, 2, 'Convert 45 minutes to 0.75 hour, then distance = 6 × 0.75 = 4.5 miles. Choice 3.5 miles uses 35 minutes instead of 45, misreading the time. Choice 4 miles rounds 0.75 down to 2/3 and computes 6 × 2/3, undershooting the time fraction. Choice 5 miles rounds 0.75 up to about 0.83 hour, overshooting the conversion from minutes to hours.', true, 'trusted'),
  ('AR-RD-2', 'AR', 'ar.rate-distance-time', 4, 'Two convoys leave the same base traveling in opposite directions. One travels at 45 mph and the other at 55 mph. How far apart are they after 2 hours?', '["90 miles","110 miles","180 miles","200 miles"]'::jsonb, 3, 'Combined separation rate = 45 + 55 = 100 mph, so after 2 hours they are 100 × 2 = 200 miles apart. Choice 90 miles uses only the slower convoy (45 × 2), ignoring the second convoy''s motion. Choice 110 miles uses only the faster convoy (55 × 2). Choice 180 miles uses an average speed of 50 mph for one convoy and doubles, settling on 90 × 2 instead of summing both speeds.', true, 'trusted'),
  ('AR-RD-3', 'AR', 'ar.rate-distance-time', 4, 'Pump A fills a tank at 40 gallons per minute. Pump B drains it at 15 gallons per minute. Starting empty, how many minutes until a 1,000-gallon tank is full with both pumps running?', '["25 minutes","33 minutes","40 minutes","67 minutes"]'::jsonb, 2, 'Net fill rate = 40 − 15 = 25 gal/min, so time = 1,000 ÷ 25 = 40 minutes. Choice 25 minutes divides 1,000 by 40, using only the fill rate and ignoring the drain. Choice 33 minutes uses about 30 gal/min net, rounding the fill rate up loosely. Choice 67 minutes divides 1,000 by 15, using only the drain rate as if the fill pump were off, the inverse-direction trap.', true, 'trusted'),
  ('AR-RD-4', 'AR', 'ar.rate-distance-time', 3, 'A vehicle travels 180 miles in 3 hours. At the same speed, how long will it take to travel 270 miles?', '["3.5 hours","4 hours","4.5 hours","5 hours"]'::jsonb, 2, 'Speed = 180 ÷ 3 = 60 mph, so time for 270 miles = 270 ÷ 60 = 4.5 hours. Choice 3.5 hours adds a half-hour to the original 3 hours, ignoring the proper rate-based scaling for the extra 90 miles. Choice 4 hours uses a speed of 67.5 mph (270/4), rounding the speed up. Choice 5 hours uses 54 mph (270/5), rounding the speed down a hair below the actual 60 mph.', true, 'trusted'),
  ('AR-RD-5', 'AR', 'ar.rate-distance-time', 5, 'Soldier A can complete a course in 4 hours alone. Soldier B can complete the same course in 6 hours alone. Working together, how long do they take?', '["2 hours","2 hours 24 minutes","3 hours","3 hours 20 minutes"]'::jsonb, 1, 'Combined rate = 1/4 + 1/6 = 5/12 per hour, so time = 12/5 = 2.4 hours = 2 hours 24 minutes. Choice 2 hours assumes the team finishes in half of A''s time, ignoring B''s slower pace. Choice 3 hours splits the difference between 4 and 6 by halving the sum, the classic average-the-times trap. Choice 3 hours 20 minutes adds the times wrong (10/3 hours), still averaging instead of combining rates.', true, 'trusted'),
  ('AR-RD-6', 'AR', 'ar.rate-distance-time', 3, 'A helicopter flies 420 miles at 140 mph. How long does the flight take?', '["2 hours","2.5 hours","3 hours","3.5 hours"]'::jsonb, 2, 'Time = distance ÷ speed = 420 ÷ 140 = 3 hours, a clean division once the formula is set up. Choice 2 hours divides 420 by about 210, mistakenly doubling the speed before dividing. Choice 2.5 hours divides 420 by 168, an arbitrary midpoint between 140 and 210. Choice 3.5 hours divides 420 by 120, rounding the speed down from 140 by a full 20 mph and inflating the time.', true, 'trusted'),
  ('AR-WP-1', 'AR', 'ar.word-problems', 4, 'A soldier spends 1/3 of his monthly pay on rent and 1/4 on food, and saves the rest. His monthly pay is $2,400. How much does he save each month?', '["$400","$600","$800","$1,000"]'::jsonb, 3, 'Spent fraction = 1/3 + 1/4 = 7/12, so saved fraction = 5/12, and 5/12 × $2,400 = $1,000. Choice $400 takes about 1/6 of pay, likely from adding 1/3 + 1/4 incorrectly as 1/7 then taking the complement. Choice $600 reports the food spending alone instead of the savings. Choice $800 reports the rent spending alone, again confusing a spent category with the leftover savings amount.', true, 'trusted'),
  ('AR-WP-2', 'AR', 'ar.word-problems', 5, 'Three soldiers share a $420 supply order. One soldier pays twice as much as each of the other two. How much does the soldier paying more contribute?', '["$105","$140","$168","$210"]'::jsonb, 3, 'Let each smaller share = x and the larger share = 2x; total = x + x + 2x = 4x = $420, so x = $105 and the larger share = 2x = $210. Choice $105 reports the smaller share rather than the larger one. Choice $140 splits $420 evenly across three soldiers, ignoring the doubled share. Choice $168 uses 2/5 of $420 instead of 2/4, splitting the order into five parts rather than four.', true, 'trusted'),
  ('AR-WP-3', 'AR', 'ar.word-problems', 3, 'A base has 480 personnel. If 35% are on leave, how many are currently on base?', '["148","168","288","312"]'::jsonb, 3, 'On base = 480 × (1 − 0.35) = 480 × 0.65 = 312. Choice 148 uses about 30% remaining (a rounding-down of the complement). Choice 168 reports the number on leave (480 × 0.35) instead of those remaining, the most common misread. Choice 288 uses 60% on base instead of 65%, rounding the leave percent up to 40% before taking the complement.', true, 'trusted'),
  ('AR-WP-4', 'AR', 'ar.word-problems', 4, 'A mess hall serves breakfast for 2 hours at 80 soldiers per hour and lunch for 3 hours at 120 soldiers per hour. What is the total number of soldiers served?', '["400","500","520","600"]'::jsonb, 2, 'Total = (80 × 2) + (120 × 3) = 160 + 360 = 520. Choice 400 multiplies 80 × 5 hours, applying the breakfast rate to the entire 5-hour window. Choice 500 uses 100 × 5, averaging the two rates instead of weighting each by its own hours. Choice 600 uses 120 × 5, applying the lunch rate to all hours and inflating the breakfast portion.', true, 'trusted'),
  ('AR-WP-5', 'AR', 'ar.word-problems', 4, 'A soldier drives 3 legs of a trip: 60 miles at 30 mph, then 120 miles at 60 mph, then 90 miles at 45 mph. What is the total driving time?', '["5 hours","5.5 hours","6 hours","6.5 hours"]'::jsonb, 2, 'Each leg takes distance ÷ speed: 60/30 = 2 hr, 120/60 = 2 hr, 90/45 = 2 hr, total = 6 hours. Choice 5 hours adds two legs at 2 hours and rounds the third leg down to 1 hour. Choice 5.5 hours uses 90/60 = 1.5 hours for the third leg, applying the wrong speed. Choice 6.5 hours adds a half-hour buffer that the problem never mentions.', true, 'trusted'),
  ('AR-WP-6', 'AR', 'ar.word-problems', 3, 'A soldier''s monthly pay is $3,000. She receives a 5% pay raise. What is her new monthly pay?', '["$3,050","$3,100","$3,150","$3,200"]'::jsonb, 2, 'New pay = $3,000 × 1.05 = $3,150, or compute the raise as $3,000 × 0.05 = $150 and add. Choice $3,050 adds only $50, treating 5% as a flat $50 increase. Choice $3,100 uses about a 3.3% raise (adding $100). Choice $3,200 uses a 6.7% raise, rounding the dollar increase up to a friendlier $200 instead of the actual $150.', true, 'trusted'),
  ('MK-AL-1', 'MK', 'mk.algebra-linear', 3, 'Solve for x: 3x + 7 = 22', '["x = 3","x = 5","x = 7","x = 9"]'::jsonb, 1, 'Undo addition first, then multiplication. Subtract 7 from both sides: 3x = 15. Divide by 3: x = 5. The choice x = 3 comes from dividing 22 by 3 (skipping the −7 step) and rounding. The choice x = 7 comes from leaving the 7 on the wrong side, computing (22 + 7)÷3 = 29÷3 ≈ 9.67 and selecting the nearest small integer, or by sign-flipping the 7. The choice x = 9 adds 7 instead of subtracting, getting 3x = 29 → about 9.67 rounded to 9.', true, 'trusted'),
  ('MK-AL-2', 'MK', 'mk.algebra-linear', 3, 'Solve for x: 4x − 9 = 23', '["x = 3.5","x = 7","x = 8","x = 32"]'::jsonb, 2, 'Add 9 to both sides to clear the constant: 4x = 32. Divide by 4: x = 8. The choice x = 3.5 comes from subtracting 9 instead of adding, getting 4x = 14, then 14÷4. The choice x = 7 comes from adding 9 but then subtracting 4 instead of dividing: 32 − 4 close to 28, slipped to 28÷4. The choice x = 32 stops one step short, taking 4x = 32 as the final answer without dividing by 4.', true, 'trusted'),
  ('MK-AL-3', 'MK', 'mk.algebra-linear', 5, 'Solve the system: 2x + y = 11 and x − y = 1. What is the value of x?', '["x = 2","x = 3","x = 4","x = 5"]'::jsonb, 2, 'Add the equations to eliminate y: (2x + y) + (x − y) = 11 + 1, giving 3x = 12, so x = 4. Back-substitute into x − y = 1: y = 3. Verify: 2(4) + 3 = 11. The choice x = 2 comes from subtracting the equations instead of adding (the y terms have opposite signs, so addition is what cancels). The choice x = 3 returns the y value by mistake. The choice x = 5 comes from solving only the first equation with a guessed y.', true, 'trusted'),
  ('MK-AL-4', 'MK', 'mk.algebra-linear', 4, 'Which value of x satisfies the inequality 5x − 4 > 16?', '["x = 2","x = 3","x = 4","x = 5"]'::jsonb, 3, 'Solve the inequality first: add 4 to both sides to get 5x > 20, then divide by 5 to get x > 4. The solution set is every value strictly greater than 4, so x = 5 is the only choice that qualifies. ''x = 4'' is the trap of treating > as ≥; substituting gives 5(4) − 4 = 16, which equals 16 rather than strictly exceeding it. ''x = 3'' gives 5(3) − 4 = 11 and ''x = 2'' gives 5(2) − 4 = 6, both well below 16.', true, 'trusted'),
  ('MK-AL-5', 'MK', 'mk.algebra-linear', 3, 'If 2(x + 3) = 18, what is x?', '["x = 6","x = 7","x = 9","x = 12"]'::jsonb, 0, 'Two equivalent paths give the same answer. Distribute: 2x + 6 = 18, then 2x = 12, so x = 6. Or divide first: x + 3 = 9, then x = 6. The choice x = 7 comes from subtracting 3 from 18 first (15) and dividing by something near 2. The choice x = 9 comes from dividing 18 by 2 and stopping, ignoring the +3 inside the parentheses. The choice x = 12 stops at 2x = 12 without dividing by 2.', true, 'trusted'),
  ('MK-AL-6', 'MK', 'mk.algebra-linear', 4, 'A soldier earns $d per day. After 5 days he has earned $650. He spends $200. Which expression correctly gives his remaining money?', '["5d − 200","d/5 − 200","650 − 5d","5(d − 200)"]'::jsonb, 0, 'Earnings come first, then spending. Five days at $d per day earns 5d total. Subtracting the $200 spent leaves 5d − 200. The choice d/5 − 200 divides instead of multiplies, treating d as a total rather than a daily rate. The choice 650 − 5d double-counts the earnings by subtracting them from the stated total. The choice 5(d − 200) applies the spending inside the daily rate, which would mean spending $200 every day, not once.', true, 'trusted'),
  ('MK-FR-1', 'MK', 'mk.fractions-decimals', 3, 'What is 3/4 + 2/3?', '["5/7","5/12","1 5/12","1 7/12"]'::jsonb, 2, 'Find a common denominator. LCD of 4 and 3 is 12. Convert: 3/4 = 9/12 and 2/3 = 8/12. Add: 9/12 + 8/12 = 17/12 = 1 5/12. The choice 5/7 comes from adding numerators and denominators directly (3+2 over 4+3), which never works for fraction addition. The choice 5/12 has the right denominator but uses subtraction in the numerator. The choice 1 7/12 swaps the numerator and adds an extra 2/12 by mis-converting 2/3 as 10/12.', true, 'trusted'),
  ('MK-FR-2', 'MK', 'mk.fractions-decimals', 3, 'Which fraction is largest: 5/8, 2/3, 3/5, or 7/12?', '["5/8","2/3","3/5","7/12"]'::jsonb, 1, 'Convert to a common denominator of 120: 5/8 = 75/120, 2/3 = 80/120, 3/5 = 72/120, 7/12 = 70/120. The largest numerator wins, so 2/3 is largest. Decimal check: 0.625, 0.667, 0.600, 0.583. The choice 5/8 looks close to 2/3 but is a hair smaller. The choice 3/5 confuses students who think a smaller denominator always means a larger fraction. The choice 7/12 has the largest denominator and is the smallest of the four.', true, 'trusted'),
  ('MK-FR-3', 'MK', 'mk.fractions-decimals', 4, 'A soldier runs 2.75 miles on Monday and 1 3/4 miles on Tuesday. What is the combined distance?', '["4.00 miles","4.25 miles","4.50 miles","4.75 miles"]'::jsonb, 2, 'Put both in the same form. 1 3/4 = 1.75 miles. Add: 2.75 + 1.75 = 4.50 miles. The choice 4.00 miles comes from misreading 3/4 as 1/4, giving 1.25 + 2.75. The choice 4.25 miles comes from converting 3/4 to 0.5 (mixing it up with 1/2). The choice 4.75 miles comes from adding the whole-number parts to the larger decimal (2.75 + 2 instead of 2.75 + 1.75).', true, 'trusted'),
  ('MK-FR-4', 'MK', 'mk.fractions-decimals', 3, 'What is (3/5) × (10/9)?', '["1/3","2/3","6/5","5/3"]'::jsonb, 1, 'Multiply numerators and denominators: (3 × 10) / (5 × 9) = 30/45 = 2/3 in lowest terms. The trap ‘5/3’ is what students get when they invert the wrong fraction and multiply — flipping 10/9 to 9/10 then computing (3/5) × (9/10)? No: the inversion error is treating multiplication like division, giving 3/5 ÷ 10/9 = (3/5) × (9/10) = 27/50, or more simply, students who flip both fractions get (5/3) × (9/10) and then lose track. The key takeaway: multiply straight across, then simplify.', true, 'trusted'),
  ('MK-FR-5', 'MK', 'mk.fractions-decimals', 4, 'Express 0.625 as a fraction in lowest terms.', '["5/8","6/10","25/40","3/5"]'::jsonb, 0, 'Write the decimal as a fraction over a power of ten and reduce. 0.625 = 625/1000. Divide numerator and denominator by 125: 5/8. Verify: 5 ÷ 8 = 0.625. The choice 6/10 simplifies to 3/5 = 0.6, not 0.625. The choice 25/40 equals 5/8 in value but is not in lowest terms, so it fails the "lowest terms" requirement. The choice 3/5 equals 0.6, off by 0.025.', true, 'trusted'),
  ('MK-EP-1', 'MK', 'mk.exponents-polynomials', 3, 'Simplify: 2³ × 2⁴', '["2⁶","2⁷","4⁷","8⁷"]'::jsonb, 1, 'When multiplying powers with the same base, add the exponents: 2³ × 2⁴ = 2^(3+4) = 2⁷. The choice 2⁶ comes from off-by-one addition (treating 3 + 4 as 6) or counting one factor short. The choice 4⁷ comes from multiplying the bases together (2 × 2 = 4) while still adding the exponents, which double-counts the multiplication. The choice 8⁷ comes from computing 2³ = 8 as the new base while keeping the second exponent stack intact.', true, 'trusted'),
  ('MK-EP-2', 'MK', 'mk.exponents-polynomials', 3, 'What is (3²)³?', '["3⁵","3⁶","9³","27²"]'::jsonb, 1, 'Power of a power means multiply the exponents: (3²)³ = 3^(2×3) = 3⁶ = 729. The choice 3⁵ comes from adding the exponents (2 + 3) instead of multiplying, which is the rule for same-base multiplication, not nested powers. The choice 9³ computes 3² = 9 first as the new base, which equals 729 in value but is not the simplified exponent form the question asks for. The choice 27² = 729 in value but again is not the requested simplification.', true, 'trusted'),
  ('MK-EP-3', 'MK', 'mk.exponents-polynomials', 4, 'Expand and simplify: (x + 4)(x − 3)', '["x² − 12","x² + x − 12","x² − x − 12","x² + 7x − 12"]'::jsonb, 1, 'Use FOIL. First: x · x = x². Outer: x · (−3) = −3x. Inner: 4 · x = 4x. Last: 4 · (−3) = −12. Combine like terms: x² + 4x − 3x − 12 = x² + x − 12. The choice x² − 12 skips the cross terms entirely. The choice x² − x − 12 reverses the sign on the middle term by swapping which term gets the negative. The choice x² + 7x − 12 adds the cross terms instead of combining them with their correct signs (4 + 3 instead of 4 − 3).', true, 'trusted'),
  ('MK-EP-4', 'MK', 'mk.exponents-polynomials', 4, 'Factor: x² − 9', '["(x − 3)²","(x + 3)(x − 3)","(x − 9)(x + 1)","(x + 9)(x − 1)"]'::jsonb, 1, 'This is a difference of squares: x² − 9 = x² − 3² = (x + 3)(x − 3). The trap (x − 3)² expands to x² − 6x + 9, not x² − 9.', true, 'trusted'),
  ('MK-EP-5', 'MK', 'mk.exponents-polynomials', 4, 'Simplify: (4x³y²) ÷ (2xy)', '["2x²y","2x³y","4x²y","2x²y²"]'::jsonb, 0, 'Divide piece by piece. Coefficients: 4 ÷ 2 = 2. Powers of x: x³ ÷ x¹ = x² (subtract exponents). Powers of y: y² ÷ y¹ = y. Result: 2x²y. The choice 2x³y keeps the x³ unchanged, forgetting to subtract exponents. The choice 4x²y forgets to divide the coefficients. The choice 2x²y² keeps the y² unchanged, again skipping the exponent subtraction on y.', true, 'trusted'),
  ('MK-GE-1', 'MK', 'mk.geometry', 3, 'A rectangular field is 80 meters long and 35 meters wide. What is its perimeter?', '["115 m","230 m","270 m","2,800 m"]'::jsonb, 1, 'Perimeter of a rectangle equals 2(length + width). P = 2(80 + 35) = 2(115) = 230 m. The choice 115 m computes the sum of length and width but forgets to double it, capturing only two of the four sides. The choice 270 m comes from adding 80 + 35 + 80 + 75 with an arithmetic slip on the last width. The choice 2,800 m computes the area (80 × 35) instead of perimeter, mixing area and perimeter formulas.', true, 'trusted'),
  ('MK-GE-2', 'MK', 'mk.geometry', 3, 'A triangle has a base of 14 cm and a height of 9 cm. What is its area?', '["46 cm²","63 cm²","126 cm²","252 cm²"]'::jsonb, 1, 'Triangle area uses A = (1/2) × base × height. A = (1/2) × 14 × 9 = 63 cm². The choice 46 cm² comes from adding base and height twice (perimeter-style thinking) and adjusting. The choice 126 cm² omits the (1/2) factor, applying the rectangle formula to a triangle. The choice 252 cm² doubles the rectangle value instead of halving the triangle, the opposite mistake.', true, 'trusted'),
  ('MK-GE-3', 'MK', 'mk.geometry', 4, 'A cylinder has a radius of 5 cm and a height of 10 cm. What is its volume? (Use π ≈ 3.14)', '["157 cm³","314 cm³","785 cm³","1,570 cm³"]'::jsonb, 2, 'V = πr²h = 3.14 × 5² × 10 = 3.14 × 25 × 10 = 785 cm³. Using the diameter (10) as the radius gives 3.14 × 100 × 10 = 3,140 — a common error.', true, 'trusted'),
  ('MK-GE-4', 'MK', 'mk.geometry', 3, 'A circle has a diameter of 10 cm. What is its area? (Use π ≈ 3.14)', '["31.4 cm²","62.8 cm²","78.5 cm²","314 cm²"]'::jsonb, 2, 'Area uses πr², not πd. Radius = diameter ÷ 2 = 5 cm. Area = 3.14 × 5² = 3.14 × 25 = 78.5 cm². The choice 31.4 cm² computes circumference (πd) and mislabels it as area. The choice 62.8 cm² computes 2πr (also a circumference variant) and treats it as area. The choice 314 cm² plugs the diameter into r² instead of the radius, getting 3.14 × 100.', true, 'trusted'),
  ('MK-NP-1', 'MK', 'mk.number-properties', 3, 'Which of the following is a prime number?', '["51","57","61","91"]'::jsonb, 2, 'A prime number has exactly two factors: 1 and itself. Test each. 51 = 3 × 17 (digits sum to 6, divisible by 3). 57 = 3 × 19 (digits sum to 12, divisible by 3). 91 = 7 × 13 (a common trap because it looks prime). 61 has no divisor between 2 and 7 (its square root is about 7.8), so it is prime. The choice 51 fools students who skip the divisibility-by-3 check. The choice 57 has the same trap. The choice 91 is the classic ASVAB prime-trap because the factors 7 and 13 are not in the small-number reflex set.', true, 'trusted'),
  ('MK-NP-2', 'MK', 'mk.number-properties', 3, 'What is the greatest common factor (GCF) of 36 and 48?', '["6","9","12","18"]'::jsonb, 2, 'Use prime factorization. 36 = 2² × 3² and 48 = 2⁴ × 3. Take the lowest power of each shared prime: 2² × 3 = 12. The choice 6 takes only 2 × 3, missing one factor of 2. The choice 9 takes 3², ignoring the shared 2s entirely. The choice 18 includes 3² but only one prime is shared at that power (3 appears as 3² in 36 but only 3¹ in 48), so 18 over-counts and is a factor of 36 but not of 48.', true, 'trusted'),
  ('MK-NP-3', 'MK', 'mk.number-properties', 4, 'The product of two consecutive even integers is 48. What is the smaller integer?', '["4","6","8","10"]'::jsonb, 1, 'Consecutive even integers differ by 2. Let them be n and n + 2 with n(n + 2) = 48. Test even integers: 4 × 6 = 24 (too low), 6 × 8 = 48. The smaller is 6. The choice 4 comes from picking the first factor pair without checking that both must be even and consecutive (4 and 12 multiply to 48 but are not consecutive). The choice 8 returns the larger of the correct pair. The choice 10 comes from solving for the wrong product (10 × 12 = 120) or sliding too far up the even integers.', true, 'trusted'),
  ('MK-NP-4', 'MK', 'mk.number-properties', 4, 'A number N is divisible by both 6 and 10. What is the smallest positive value N can be?', '["16","30","60","120"]'::jsonb, 1, 'The least common multiple (LCM) of 6 and 10 is found using prime factors: 6 = 2 × 3, 10 = 2 × 5. LCM = 2 × 3 × 5 = 30. The trap is multiplying 6 × 10 = 60.', true, 'trusted'),
  ('WK-SN-2', 'WK', 'wk.synonyms', 2, 'TRANQUIL most nearly means:', '["Noisy","Peaceful","Rushed","Dangerous"]'::jsonb, 1, 'Tranquil means free from agitation and disturbance, as in ''the tranquil pond mirrored the trees without a ripple.'' Noisy is the direct antonym, naming auditory chaos. Rushed is a register antonym, pointing to hurried motion rather than calm stillness. Dangerous is a register trap that draws on the absence of threat in tranquil settings, but danger is about risk while tranquil is about absence of disturbance. Peaceful is the dominant synonym, sharing the core sense of stillness and freedom from agitation.', true, 'trusted'),
  ('WK-SN-5', 'WK', 'wk.synonyms', 3, 'LETHARGIC most nearly means:', '["Energetic","Sluggish","Aggressive","Focused"]'::jsonb, 1, 'Lethargic means lacking energy and slow to act, as in ''after the long flight he felt lethargic and could barely climb the stairs.'' Energetic is the direct antonym, naming vigor rather than torpor. Aggressive is a register antonym, naming active hostility, which requires energy lethargic lacks. Focused is a register trap, since a focused person can be calm but is engaged, not depleted. Sluggish is the dominant synonym, sharing the slowed-down, low-energy quality at the heart of lethargic.', true, 'trusted'),
  ('WK-SN-6', 'WK', 'wk.synonyms', 4, 'INSCRUTABLE most nearly means:', '["Mysterious","Obvious","Unreliable","Talkative"]'::jsonb, 0, 'Inscrutable means impossible to interpret or read, as in ''his inscrutable expression gave away nothing during negotiations.'' The root SCRUT- means examine (scrutinize, scrutiny); the IN- here negates it. Obvious is the direct antonym, naming easy readability. Unreliable is a register trap, since an inscrutable person may be trustworthy or not; readability has no necessary tie to dependability. Talkative is unrelated; inscrutable concerns interpretability of expression or motive, not volume of speech. Only Mysterious captures the unreadable quality.', true, 'trusted'),
  ('WK-SN-10', 'WK', 'wk.synonyms', 5, 'RECALCITRANT most nearly means:', '["Obedient","Defiant","Cautious","Calculating"]'::jsonb, 1, 'Recalcitrant means stubbornly resistant to authority or control, as in ''the recalcitrant prisoner refused every order.'' From Latin calcitrare, to kick back. Obedient is the direct antonym. Cautious overlaps with hesitation but cautious people slow down to think, while recalcitrant people actively resist. Calculating is a visual-similarity trap, drawing on the shared CAL- letters, but calculating means scheming and shrewd, an unrelated trait. A test-taker picking Calculating has matched letters rather than meaning. Only Defiant captures the active resistance.', true, 'trusted'),
  ('AO-3D-1', 'AO', 'ao.3d-visualization', 3, 'A solid cube rests flat on a table. The top face is painted red. The cube is rotated 90 degrees forward, tilting toward you and pivoting around its front-bottom edge. After this rotation, which face is now on top?', '["The original top face (red)","The original front face","The original back face","The original bottom face"]'::jsonb, 2, 'Imagine a die rolling toward you one quarter turn. The pivot is the front-bottom edge, so that edge stays put while the cube tips forward. The face that was on top swings forward to become the new front (so the red moves to the front, not the top). The original front swings down onto the table (new bottom). The original bottom swings forward and up to face away from the viewer (new back). The original back swings up into the sky position, so it is now on top. Choice A confuses the rotation with a 360 spin; choice B is the trap of stopping the trace one step early; choice D would require a full 180 flip, not 90.', true, 'trusted'),
  ('AO-3D-3', 'AO', 'ao.3d-visualization', 4, 'A cube''s faces are colored: top = white, bottom = black, front = red, back = green, left = blue, right = yellow. The cube is rotated 90° to the right (around the vertical axis — the right side swings to the front). What color is now on top?', '["White","Black","Yellow","Blue"]'::jsonb, 0, 'Rotation around the vertical axis only moves the four side faces; the top and bottom faces stay fixed because they sit on that axis. So white remains on top regardless of how far the cube is spun horizontally. ''Yellow'' is the trap of grabbing the right face (which was yellow before the spin), confusing horizontal rotation with a tilt that would actually bring a side face to the top. ''Blue'' makes the same mistake with the left face. ''Black'' would require flipping the cube upside down, which is a rotation around a horizontal axis, not vertical.', true, 'trusted'),
  ('AO-3D-4', 'AO', 'ao.3d-visualization', 3, 'Using the same colored cube (top = white, front = red, right = yellow, bottom = black, back = green, left = blue): after rotating 90° to the right around the vertical axis, what color is now facing you (front)?', '["Red","Green","Yellow","Blue"]'::jsonb, 2, 'A 90 degree rotation to the right around the vertical axis (right side swinging forward, per the convention in question AO-3D-3) brings the yellow right face around to the front. The red original front rotates to the left, the blue original left moves to the back, and the green original back rotates to the right. New front equals yellow. ''Red'' is the trap of forgetting that the cube moved at all, treating the original front as fixed. ''Blue'' confuses left and right rotation. ''Green'' jumps to the opposite face, which would require a 180 degree turn rather than 90.', true, 'trusted'),
  ('AO-3D-5', 'AO', 'ao.3d-visualization', 5, 'A cube is sliced by a flat plane that passes through exactly three vertices of the cube, one vertex on each of three different faces that share no common edge. What shape is the cross-section?', '["Square","Rectangle","Equilateral triangle","Right triangle"]'::jsonb, 2, 'Pick three vertices of a cube, one on each of three faces that share no common edge: each pair of those vertices is connected by a face diagonal of the cube. Face diagonals of a cube all have the same length (side times sqrt 2). Three equal-length edges meeting pairwise create an equilateral triangle. ''Square'' would require four vertices, not three. ''Rectangle'' also needs four vertices and two distinct edge lengths. ''Right triangle'' tempts test takers who assume any triangle inside a cube must have a right angle, but the three vertices chosen here lie symmetrically and produce 60 degree angles, not 90.', true, 'trusted'),
  ('AO-PF-1', 'AO', 'ao.paper-folding-nets', 3, 'A flat net consists of 1 center square with 4 squares attached, one to each side (forming a plus/cross shape — 5 squares total). When folded, what 3D shape does it create?', '["A cube","A square pyramid","An open-top box (box without a lid)","A triangular prism"]'::jsonb, 2, 'The plus-shaped net has one central square plus four flaps attached to each side. Folding the four flaps up along the central square produces a base with four walls but no top: only 5 of the 6 sides needed for a closed cube are present. The result is an open-top box. ''A cube'' is the natural trap, but a cube needs 6 squares, not 5. ''A square pyramid'' would require triangular flaps converging to a point, not square ones folding up parallel. ''A triangular prism'' has 3 rectangular sides and 2 triangular ends, none of which appear in this all-square net.', true, 'trusted'),
  ('AO-PF-3', 'AO', 'ao.paper-folding-nets', 3, 'A flat net consists of a square in the center with 4 equilateral triangles attached to each of the square''s edges. When folded, what shape does it form?', '["A cube","A rectangular prism","A square pyramid","A triangular prism"]'::jsonb, 2, 'The square in the center becomes the base. Each equilateral triangle hinges upward along one edge of the square. Because all four triangles have the same side length and lean inward at equal angles, their free apex vertices converge to a single point above the center of the base. That is the definition of a square pyramid. ''A cube'' is impossible because the net has triangles, not all squares. ''A rectangular prism'' likewise needs 6 rectangular faces. ''A triangular prism'' has only 2 triangular faces (the ends) plus 3 rectangular sides, while this net has 4 triangles and a square.', true, 'trusted'),
  ('AO-PF-4', 'AO', 'ao.paper-folding-nets', 4, 'A cube net: face A is in the center; face B is directly above A; face C is directly below A; face D is to the left of A; face E is to the right of A; face F is directly below C. When folded into a cube, which face is directly opposite face B?', '["Face A","Face C","Face F","Face D"]'::jsonb, 1, 'With face A as the base of the cube, B folds up to be the back wall and C folds up to be the front wall — making B and C opposite faces. D and E become the left and right sides (also opposite). F, attached to C’s far edge, folds over to become the top — making F opposite A. Therefore the face opposite B is C.', true, 'trusted'),
  ('AO-PF-5', 'AO', 'ao.paper-folding-nets', 5, 'A square sheet of paper is folded in half by bringing the bottom edge up to meet the top edge (a horizontal fold). The resulting rectangle is then folded in half by bringing the right edge over to meet the left edge (a vertical fold). The paper is then fully unfolded. How many rectangular sections does the paper have?', '["2","4","6","8"]'::jsonb, 1, 'Each fold along a different axis multiplies, not adds. The first horizontal fold creates 1 crease across the middle, splitting the square into 2 horizontal strips. The second vertical fold adds 1 crease running the other direction, slicing each strip in two. The result is a 2 by 2 grid: 4 rectangular sections separated by one horizontal and one vertical crease. ''2'' counts only the first fold. ''6'' incorrectly adds 2 plus the perceived 4. ''8'' doubles every step as if both folds shared the same axis, but perpendicular folds multiply differently than parallel ones.', true, 'trusted'),
  ('AO-SC-1', 'AO', 'ao.spatial-counting', 3, 'A structure is built by stacking cubes. The bottom layer is a 3×3 grid (9 cubes). The second layer is a 2×2 grid centered on the first (4 cubes). The third layer has 1 cube centered on the second. How many cubes are in the structure?', '["9","12","14","16"]'::jsonb, 2, 'Add the cubes layer by layer. Bottom layer: 3 by 3 = 9. Middle layer: 2 by 2 = 4. Top: 1. Total = 9 + 4 + 1 = 14. ''9'' counts only the bottom layer, ignoring the stacked layers. ''12'' is a guess that splits the difference between 9 and the next plausible number. ''16'' overcounts, possibly by assuming the second layer is 3 by 3 again or by squaring 4 instead of using 2 by 2. The layered sum approach (9 + 4 + 1) gives 14 directly.', true, 'trusted'),
  ('AO-SC-3', 'AO', 'ao.spatial-counting', 3, 'You see a staircase of cubes: 3 cubes on the bottom row, 2 cubes on the middle row, and 1 cube on the top. All rows are aligned to the left edge. How many cubes are in the structure?', '["5","6","7","9"]'::jsonb, 1, 'Add the cubes row by row: bottom 3, middle 2, top 1, for a total of 3 + 2 + 1 = 6. ''5'' undercounts, possibly missing the top cube. ''7'' overcounts by adding an extra. ''9'' applies the wrong rule entirely (3 by 3 grid logic instead of a staircase). The staircase formula n(n+1)/2 with n = 3 gives 3 times 4 divided by 2 = 6, confirming the direct count.', true, 'trusted'),
  ('AO-SC-4', 'AO', 'ao.spatial-counting', 4, 'A 2×3 single-layer base (6 cubes) sits on a table. A second layer of 2×2 cubes is stacked on top starting from one corner. How many cubes are in the complete structure?', '["8","9","10","12"]'::jsonb, 2, 'Count by layer. Bottom layer is 2 by 3 = 6 cubes. Second layer is 2 by 2 = 4 cubes stacked on top. Total = 6 + 4 = 10. ''8'' undercounts the second layer (treating it as 2 cubes instead of 4). ''9'' splits the difference between 6 and 10 without a clear method. ''12'' overcounts by assuming the second layer matches the base (2 by 3 = 6) rather than the smaller stated 2 by 2. The layered addition gives 10.', true, 'trusted'),
  ('AO-SC-5', 'AO', 'ao.spatial-counting', 5, 'A 4×4×4 large cube is built from unit cubes. How many unit cubes are completely hidden inside (touching no outer face)?', '["0","4","8","16"]'::jsonb, 2, 'Hidden interior cubes do not touch any outer face. For a 4 by 4 by 4 cube, peel off the outer shell one unit thick on every side: the remaining hidden core is (4 minus 2) cubed = 2 cubed = 8 cubes. ''16'' confuses surface count with interior. ''4'' undercounts the interior dimension. ''0'' is the answer only for a cube smaller than 3 units on a side, where there is no interior. The (n minus 2) cubed formula works for any n by n by n cube where n is at least 3.', true, 'trusted'),
  ('AR-AF-B3-1', 'AR', 'ar.arithmetic-fundamentals', 2, 'A classroom has 6 rows of desks with 5 desks in each row. How many desks are in the classroom?', '["11","25","30","36"]'::jsonb, 2, 'Total desks = 6 × 5 = 30. Adding 6 + 5 = 11 instead of multiplying is the most common error.', true, 'trusted'),
  ('AR-AF-B3-2', 'AR', 'ar.arithmetic-fundamentals', 3, 'A warehouse receives 3 shipments of 144 items each. Workers then remove 85 items for immediate distribution. How many items remain in the warehouse?', '["347","357","372","432"]'::jsonb, 0, 'Total received = 3 × 144 = 432, then 432 − 85 = 347 remain. Choice 357 subtracts 75 instead of 85, dropping a digit during the subtraction step. Choice 372 subtracts 60 instead of 85, misreading the removal count as a smaller round number. Choice 432 reports the gross intake and forgets the removal step entirely, the most common misread of the problem.', true, 'trusted'),
  ('AR-AF-B3-3', 'AR', 'ar.arithmetic-fundamentals', 3, 'A painter earns $18 per hour and works 7 hours on Monday, 5 hours on Tuesday, and 6 hours on Wednesday. What are her total earnings for the three days?', '["$216","$252","$288","$324"]'::jsonb, 3, 'Total hours = 7 + 5 + 6 = 18, then earnings = 18 × $18 = $324. Choice $216 multiplies 18 × $12, using a $12 wage instead of $18. Choice $252 multiplies 14 × $18, dropping a workday (likely Tuesday). Choice $288 multiplies 18 × $16, using a wrong hourly wage that is close to but lower than $18. Each trap keeps the hours right and bends the wage, or keeps the wage and bends the hours.', true, 'trusted'),
  ('AR-AF-B3-4', 'AR', 'ar.arithmetic-fundamentals', 4, 'A fuel tank holds 320 gallons when full. A convoy uses 3/8 of the fuel. How many gallons remain?', '["120 gallons","160 gallons","200 gallons","240 gallons"]'::jsonb, 2, 'Remaining fraction = 1 − 3/8 = 5/8, so remaining gallons = 5/8 × 320 = 200. Choice 120 gallons reports the amount used (3/8 × 320), the exact opposite of what is asked. Choice 160 gallons takes half the tank, treating 3/8 as if it were 1/2. Choice 240 gallons uses 3/4 remaining, possibly misreading 3/8 as the leftover share rather than the used share.', true, 'trusted'),
  ('AR-AF-B3-5', 'AR', 'ar.arithmetic-fundamentals', 4, 'A soldier earns $2,640 per month. She contributes 5% to a savings plan and pays $420 in rent. What is her take-home pay after both deductions?', '["$2,088","$2,100","$2,112","$2,220"]'::jsonb, 0, 'Savings = 5% × $2,640 = $132; take-home = $2,640 − $132 − $420 = $2,088, subtracting both deductions in order. Choice $2,100 rounds the savings to $120 and rounds rent loosely, settling on a tempting round number. Choice $2,112 deducts a 4% savings rate ($105.60) instead of 5%, undercounting the contribution by a single percentage point. Choice $2,220 subtracts only rent and ignores the 5% savings contribution, the classic missing-deduction trap on multi-step paycheck problems.', true, 'trusted'),
  ('AR-AF-B3-6', 'AR', 'ar.arithmetic-fundamentals', 3, 'A store sells notebooks for $2.50 each and pens for $0.75 each. A student buys 8 notebooks and 10 pens. What is the total cost?', '["$25.00","$26.50","$27.50","$28.00"]'::jsonb, 2, 'Total = (8 × $2.50) + (10 × $0.75) = $20.00 + $7.50 = $27.50, summing the two product lines. Choice $25.00 rounds pens down to $0.50 each, dropping a quarter per pen across the ten pens. Choice $26.50 uses 8 pens instead of 10, miscounting the pen quantity and pulling the total down. Choice $28.00 rounds the pen line up to $8 instead of $7.50, adding a stray $0.50 in the totals step.', true, 'trusted'),
  ('AR-AF-B3-7', 'AR', 'ar.arithmetic-fundamentals', 4, 'A bus seats 48 passengers. On three consecutive trips, it carries 35, 41, and 48 passengers. What is the total number of empty seats across all three trips?', '["18","20","22","24"]'::jsonb, 1, 'Empty seats per trip = 48 − 35, 48 − 41, 48 − 48 = 13, 7, 0; total = 13 + 7 + 0 = 20. Choice 18 drops 2 seats during the sum (perhaps 13 + 5 instead of 13 + 7). Choice 22 adds 2 phantom empty seats to the third trip, treating 48 passengers as 46. Choice 24 uses (48 − 35) + (48 − 37), misreading the middle trip count as 37 instead of 41.', true, 'trusted'),
  ('AR-AF-B3-8', 'AR', 'ar.arithmetic-fundamentals', 5, 'A supply depot has 2,400 ration packs. Each platoon of 30 soldiers needs 4 packs per soldier per day. If 4 platoons draw supplies for 2 days, how many ration packs remain?', '["480","960","1,440","1,920"]'::jsonb, 2, 'Packs drawn per platoon per day = 30 × 4 = 120. Total drawn = 4 platoons × 120 × 2 days = 960 packs. Remaining = 2,400 − 960 = 1,440. The trap is computing per-day total only (960) and selecting that as the answer without subtracting from stock.', true, 'trusted'),
  ('AR-AF-B3-9', 'AR', 'ar.arithmetic-fundamentals', 5, 'A mess hall serves breakfast daily. Each soldier eats 4 eggs at breakfast. For a unit of 120 soldiers over 5 days, how many total eggs are used at breakfast?', '["480","1,200","2,000","2,400"]'::jsonb, 3, 'Eggs = eggs per soldier × soldiers × days = 4 × 120 × 5 = 2,400. Choice 480 computes 4 × 120 and stops, forgetting the 5-day window entirely. Choice 1,200 multiplies 120 × 5 × 2, halving the eggs-per-soldier from 4 to 2. Choice 2,000 uses 100 soldiers × 4 × 5, rounding the unit size down from 120 to 100 to make the arithmetic easier.', true, 'trusted'),
  ('AR-AF-B3-10', 'AR', 'ar.arithmetic-fundamentals', 5, 'A warehouse stores canned goods on pallets. Each pallet holds 48 cases; each case holds 24 cans. Three pallets arrive fully loaded. Then 864 cans are removed. How many cans remain?', '["2,592","2,736","2,880","3,024"]'::jsonb, 0, 'Total cans = 3 × 48 × 24 = 3,456. After removal: 3,456 − 864 = 2,592. The trap is computing 3 × 48 = 144 and subtracting 864 as if it were cases rather than individual cans.', true, 'trusted'),
  ('AR-AF-B3-11', 'AR', 'ar.arithmetic-fundamentals', 4, 'A canteen sells water bottles for $1.25 each. A soldier buys 16 bottles and pays with a $20 bill and a $5 bill. How much change does he receive?', '["$1.00","$3.00","$5.00","$7.00"]'::jsonb, 2, 'Cost = 16 × $1.25 = $20.00; total paid = $20 + $5 = $25; change = $25 − $20 = $5.00. Choice $1.00 forgets the $5 bill, treating the soldier as paying $21 (a $20 bottle stack plus $1 extra). Choice $3.00 uses 17 bottles in the multiplication, overpaying the count by one. Choice $7.00 multiplies 16 × $1.125 = $18, dropping pennies from the unit price.', true, 'trusted'),
  ('AR-AF-B3-12', 'AR', 'ar.arithmetic-fundamentals', 3, 'A recruit runs 3 miles on Monday, 4 miles on Wednesday, and 5 miles on Friday. How many miles does she run in total?', '["10","11","12","13"]'::jsonb, 2, 'Total = 3 + 4 + 5 = 12 miles, a straight sum of the three workouts. Choice 10 drops a mile somewhere in the sum (perhaps treating Wednesday as 3 miles). Choice 11 swaps Wednesday''s 4 for a 3, totaling 3 + 3 + 5. Choice 13 adds an extra mile, perhaps double-counting one workout or misreading Friday as 6 miles.', true, 'trusted'),
  ('AR-AF-B3-13', 'AR', 'ar.arithmetic-fundamentals', 2, 'A school trip costs $15 per student. There are 32 students registered, but 4 drop out. How much is collected from the students who actually attend?', '["$360","$390","$420","$480"]'::jsonb, 2, 'Students attending = 32 − 4 = 28. Revenue = 28 × $15 = $420. The trap is computing 32 × $15 = $480 before accounting for the dropouts.', true, 'trusted'),
  ('AR-AF-B3-14', 'AR', 'ar.arithmetic-fundamentals', 4, 'A truck can carry 1,200 pounds. It is loaded with 10 boxes at 80 pounds each and 5 boxes at 48 pounds each. How many pounds of remaining capacity does the truck have?', '["160 pounds","180 pounds","200 pounds","240 pounds"]'::jsonb, 0, 'Heavy boxes: 10 × 80 = 800 lb. Light boxes: 5 × 48 = 240 lb. Total loaded = 1,040 lb. Remaining = 1,200 − 1,040 = 160 lb. The trap is adding only 10 boxes: 10 × 80 = 800; 1,200 − 800 = 400, ignoring the lighter boxes.', true, 'trusted'),
  ('AR-RP-B3-1', 'AR', 'ar.ratio-proportion', 3, 'A map uses a scale of 1 inch = 20 miles. Two towns are 4 inches apart on the map. What is the actual distance between them?', '["5 miles","24 miles","80 miles","100 miles"]'::jsonb, 2, 'Actual distance = inches × scale = 4 × 20 = 80 miles. Choice 5 miles divides 20 ÷ 4, inverting the scale to ask how many miles per inch of map instead of total. Choice 24 miles adds 20 + 4, mixing the scale and the map inches as if they were the same unit. Choice 100 miles multiplies 5 × 20, treating the map distance as 5 inches rather than 4.', true, 'trusted'),
  ('AR-RP-B3-2', 'AR', 'ar.ratio-proportion', 3, 'Concrete is mixed using cement, sand, and gravel in a ratio of 1:2:3. To produce 360 pounds of concrete, how many pounds of sand are needed?', '["60","90","120","180"]'::jsonb, 2, 'Total parts = 1 + 2 + 3 = 6. Sand portion = 2/6 of 360 = 120 pounds. The trap is using 2/3 of 360 = 240, which treats the ratio as sand:other rather than sand:total.', true, 'trusted'),
  ('AR-RP-B3-3', 'AR', 'ar.ratio-proportion', 3, 'A car uses 3 gallons of fuel for every 75 miles driven. At the same rate, how many gallons are needed for a 325-mile trip?', '["9","11","13","15"]'::jsonb, 2, 'Mileage = 75 ÷ 3 = 25 mpg, so gallons = 325 ÷ 25 = 13. Choice 9 uses about 36 mpg, miscomputing the rate (perhaps 75 ÷ 2 rounded). Choice 11 divides 325 by 30 mpg, rounding the mileage up by 5. Choice 15 divides 300 by 20, using both numbers as round figures rather than the exact 25 mpg from the setup.', true, 'trusted'),
  ('AR-RP-B3-4', 'AR', 'ar.ratio-proportion', 4, 'A trail mix uses nuts and dried fruit in a ratio of 5:3 by weight. A hiker makes 4 pounds of trail mix. How many ounces of dried fruit does she need? (1 pound = 16 ounces)', '["24 oz","30 oz","32 oz","40 oz"]'::jsonb, 0, 'Total parts = 8. Dried fruit = (3/8) × 4 lb = 1.5 lb = 1.5 × 16 = 24 oz. The trap is using 3/5 of 4 lb = 2.4 lb = 38.4 oz, which treats the ratio as fruit:nuts rather than fruit:total.', true, 'trusted'),
  ('AR-RP-B3-5', 'AR', 'ar.ratio-proportion', 4, 'A machine produces 420 parts in 7 hours. At the same rate, how many parts does it produce in 10 hours?', '["540","560","580","600"]'::jsonb, 3, 'Rate = 420 ÷ 7 = 60 parts/hour, so output in 10 hours = 60 × 10 = 600 parts at the same rate. Choice 540 uses about 54 parts/hour, dropping 6 parts per hour from the true rate. Choice 560 uses 56 parts/hour, an undershoot from miscomputing the division. Choice 580 uses 58 parts/hour, again under the true rate, possibly from a long-division slip on 420 ÷ 7.', true, 'trusted'),
  ('AR-RP-B3-6', 'AR', 'ar.ratio-proportion', 4, 'A scale model of a ship is built at a ratio of 1:250. The model is 48 centimeters long. What is the actual length of the ship in meters?', '["90 m","100 m","120 m","150 m"]'::jsonb, 2, 'Actual length = 48 × 250 = 12,000 cm = 120 m after dividing by 100 to convert cm to m. Choice 90 m uses about a 1:187.5 ratio by mistake, scaling shorter than the stated 1:250. Choice 100 m rounds 12,000 cm down to 10,000 cm before converting to meters, the classic round-to-something-easy trap. Choice 150 m uses a 1:312 ratio, scaling longer than 1:250 by inflating the multiplier above the stated value.', true, 'trusted'),
  ('AR-RP-B3-7', 'AR', 'ar.ratio-proportion', 3, 'A recipe for 12 cookies requires 2 cups of flour. How many cups of flour are needed for 42 cookies?', '["5","6","7","8"]'::jsonb, 2, 'Scale factor = 42 ÷ 12 = 3.5, so flour = 2 × 3.5 = 7 cups. Choice 5 uses a scale factor of 2.5, treating 42 as 30 cookies. Choice 6 triples the flour, ignoring the half-batch in the scale factor. Choice 8 uses a scale of 4, rounding 42/12 up to a clean 4 instead of using 3.5 exactly.', true, 'trusted'),
  ('AR-RP-B3-8', 'AR', 'ar.ratio-proportion', 4, 'Two workers share a project payment in proportion to the hours each works. Worker A works 18 hours and Worker B works 12 hours. The total payment is $750. How much does Worker A receive?', '["$300","$375","$420","$450"]'::jsonb, 3, 'Total hours = 18 + 12 = 30. Worker A''s share = (18/30) × $750 = 0.60 × $750 = $450. The trap is selecting Worker B''s share (12/30 × $750 = $300) or splitting equally ($375).', true, 'trusted'),
  ('AR-RP-B3-9', 'AR', 'ar.ratio-proportion', 5, 'Eight workers can load a truck in 3 hours. Two workers leave after the first hour. How many additional hours will the remaining 6 workers need to finish the job?', '["2 hours","2 hours 20 minutes","2 hours 40 minutes","3 hours"]'::jsonb, 2, 'Total job = 8 × 3 = 24 worker-hours; after 1 hour, 8 worker-hours are completed, leaving 16. With 6 workers, 16 ÷ 6 = 2 hours 40 minutes. Choice 2 hours scales linearly (24/6 minus the hour already done) without correctly tracking remaining worker-hours. Choice 2 hours 20 minutes uses 16/7 by miscount of remaining workers. Choice 3 hours ignores the first hour''s work and divides 18 wh by 6 workers.', true, 'trusted'),
  ('AR-RP-B3-10', 'AR', 'ar.ratio-proportion', 3, 'A paint color is mixed using blue and white paint in a ratio of 2:5 (blue:white). A painter needs 28 ounces of the mixture total. How many ounces of blue paint are needed?', '["4","6","8","10"]'::jsonb, 2, 'Total parts = 2 + 5 = 7, so blue = (2/7) × 28 = 8 ounces. Choice 4 takes (2/14) of 28, doubling the total parts to 14 by miscount. Choice 6 uses 28/5 rounded, treating the total ratio sum as 5 (the white share) instead of 7. Choice 10 uses (2/5) × 28 ≈ 11 then rounds down, reading the ratio as blue/white rather than blue/total, the classic parts-confusion trap.', true, 'trusted'),
  ('AR-RP-B3-11', 'AR', 'ar.ratio-proportion', 5, 'Two pipes together fill a tank in 4 hours. Pipe A alone fills the tank in 6 hours. How long does Pipe B take to fill the tank alone?', '["8 hours","10 hours","12 hours","14 hours"]'::jsonb, 2, 'Combined rate = 1/4. Pipe A rate = 1/6. Pipe B rate = 1/4 − 1/6 = 3/12 − 2/12 = 1/12. Pipe B alone takes 12 hours. The trap is subtracting times directly: 4 − 6 = −2, which is meaningless.', true, 'trusted'),
  ('AR-RP-B3-12', 'AR', 'ar.ratio-proportion', 5, 'In a survey, the ratio of respondents who prefer Brand A : Brand B : Brand C is 4:3:2. A total of 270 people were surveyed. How many more people prefer Brand A than Brand C?', '["30","45","60","90"]'::jsonb, 2, 'Total parts = 9. Each part = 270 ÷ 9 = 30. Brand A = 4 × 30 = 120. Brand C = 2 × 30 = 60. Difference = 60. The trap is computing the difference in parts (4 − 2 = 2) and answering 2, or selecting 30 (one part).', true, 'trusted'),
  ('AR-RP-B3-13', 'AR', 'ar.ratio-proportion', 4, 'On a blueprint, 1/4 inch represents 6 feet. A room on the blueprint is 3.5 inches wide. What is the actual width of the room in feet?', '["72 feet","78 feet","84 feet","96 feet"]'::jsonb, 2, 'Scale: 1/4 inch = 6 feet, so 1 inch = 24 feet. Actual width = 3.5 × 24 = 84 feet. The trap is multiplying 3.5 × 6 = 21, failing to account for the fact that each inch contains four quarter-inches.', true, 'trusted'),
  ('AR-RP-B3-14', 'AR', 'ar.ratio-proportion', 5, 'A caterer makes punch using juice and sparkling water in a ratio of 3:7 (juice:water). She needs 50 liters total. How many liters of juice are needed?', '["12 liters","15 liters","18 liters","21 liters"]'::jsonb, 1, 'Total parts = 3 + 7 = 10, so juice = (3/10) × 50 = 15 liters. Choice 12 liters uses (3/12) × 50, miscounting total parts as 12. Choice 18 liters uses about 36% of 50 by averaging the two ratio numbers poorly. Choice 21 liters takes (3/7) × 50 ≈ 21.4, treating the ratio as juice/water rather than juice/total, the most common ratio-parts trap.', true, 'trusted'),
  ('AR-PC-B3-1', 'AR', 'ar.percent', 3, 'A test has 40 questions. A student answers 30 correctly. What percent did the student answer correctly?', '["65%","70%","75%","80%"]'::jsonb, 2, 'Percent correct = correct ÷ total × 100 = 30 ÷ 40 × 100 = 75%. Choice 65% uses 26 correct out of 40, undercounting the correct answers by four. Choice 70% uses 28/40, off by two on the correct count. Choice 80% uses 32/40, two questions too generous on the correct count and rounding the percentage up to a clean 80.', true, 'trusted'),
  ('AR-PC-B3-2', 'AR', 'ar.percent', 2, 'What is 30% of 150?', '["35","40","45","50"]'::jsonb, 2, '30% × 150 = 0.30 × 150 = 45, a clean decimal multiplication. Choice 35 takes about 23% of 150, rounding 30% down to roughly a quarter. Choice 40 uses about 27% of 150, undershooting the rate. Choice 50 takes 1/3 of 150, treating 30% as if it were exactly one-third, the classic almost-the-same-fraction trap on percent problems.', true, 'trusted'),
  ('AR-PC-B3-3', 'AR', 'ar.percent', 3, 'A phone originally priced at $360 is discounted by 15%. What is the sale price?', '["$288","$300","$306","$312"]'::jsonb, 2, 'Sale price = $360 × (1 − 0.15) = $360 × 0.85 = $306, applying the discount factor directly. Choice $288 uses a 20% discount instead of 15%, rounding the discount rate up. Choice $300 rounds the discount to $60 (about 16.7% off) for a cleaner final price. Choice $312 uses about a 13% discount, rounding 15% down for a friendlier markdown but cutting less off the original.', true, 'trusted'),
  ('AR-PC-B3-4', 'AR', 'ar.percent', 3, 'A soldier''s weight dropped from 200 pounds to 185 pounds during training. What is the percent decrease?', '["6.5%","7.0%","7.5%","8.1%"]'::jsonb, 2, 'Percent decrease = (200 − 185) / 200 × 100 = 15/200 × 100 = 7.5%. Choice 6.5% uses a 13-pound drop instead of 15. Choice 7.0% divides 15 by 215, an averaged base that doesn''t match either weight. Choice 8.1% divides 15 by 185, using the new weight as the base instead of the original, the most common percent-change reversal.', true, 'trusted'),
  ('AR-PC-B3-5', 'AR', 'ar.percent', 3, 'A charity collected $3,200 last year. This year it collected $4,000. By what percent did collections increase?', '["20%","25%","28%","33%"]'::jsonb, 1, 'Percent increase = (new − old) / old × 100 = 800 / 3,200 × 100 = 25%. Choice 20% divides 800 by 4,000, using the new total as the base, the classic percent-change reversal. Choice 28% averages the two bases to about 3,600 and divides 800 by that. Choice 33% treats the ratio of new to old as 4:3 and reads the 1/3 as a percent gain on the larger total.', true, 'trusted'),
  ('AR-PC-B3-6', 'AR', 'ar.percent', 3, 'In a class of 60 students, 45% received a grade of A or B. How many students received an A or B?', '["24","27","30","33"]'::jsonb, 1, '45% × 60 = 0.45 × 60 = 27 students received an A or B. Choice 24 uses 40% of 60, rounding 45% down to a friendlier rate. Choice 30 rounds 45% up to 50%, picking exactly half the class. Choice 33 uses 55%, the complement of the rounded-down 45%, mixing rounding direction with the complement of the asked percentage.', true, 'trusted'),
  ('AR-PC-B3-7', 'AR', 'ar.percent', 4, 'A bank account has a balance of $2,500. It earns 4% simple annual interest. What is the balance after 2.5 years?', '["$2,600","$2,750","$2,800","$2,850"]'::jsonb, 1, 'Simple interest = P × r × t = $2,500 × 0.04 × 2.5 = $250, so balance = $2,500 + $250 = $2,750. Choice $2,600 uses only 1 year of interest ($100), forgetting the 2.5-year window. Choice $2,800 uses 3 years of interest by rounding 2.5 up to 3 years. Choice $2,850 uses 3.5 years of interest, adding an extra year on top of the rounded value and inflating the gain.', true, 'trusted'),
  ('AR-PC-B3-8', 'AR', 'ar.percent', 4, 'A restaurant bill comes to $48. A 20% tip and an 8% tax are both applied to the original $48 bill. What is the total amount paid?', '["$56.64","$60.48","$61.44","$62.08"]'::jsonb, 2, 'Tip = 20% × $48 = $9.60. Tax = 8% × $48 = $3.84. Total = $48 + $9.60 + $3.84 = $61.44. The trap is applying tax to the post-tip amount ($57.60 × 0.08 = $4.61), which gives a different total.', true, 'trusted'),
  ('AR-PC-B3-9', 'AR', 'ar.percent', 4, 'A mutual fund gained 20% in Year 1, then lost 20% in Year 2 from the Year 1 ending value. Starting with $1,000, what is the value after Year 2?', '["$960","$970","$980","$1,000"]'::jsonb, 0, 'After Year 1: $1,000 × 1.20 = $1,200. After Year 2: $1,200 × 0.80 = $960. The trap is assuming +20% and −20% cancel out, returning $1,000; they do not because the 20% loss applies to the higher Year 1 balance.', true, 'trusted'),
  ('AR-PC-B3-10', 'AR', 'ar.percent', 5, 'A laptop is marked up 40% from its wholesale cost, then placed on sale for 25% off the marked-up price. The sale price is $252. What was the original wholesale cost?', '["$210","$240","$250","$270"]'::jsonb, 1, 'Let wholesale cost = W. Marked-up price = 1.40W. Sale price = 1.40W × 0.75 = 1.05W = $252. W = $252 ÷ 1.05 = $240. The trap is netting the percentages: +40% − 25% = +15%, giving W = $252 ÷ 1.15 ≈ $219.', true, 'trusted'),
  ('AR-PC-B3-11', 'AR', 'ar.percent', 5, 'A store reduces a price by 30%, then reduces it again by 20% from the already-reduced price. What single percent reduction would produce the same final price?', '["44%","46%","48%","50%"]'::jsonb, 0, 'Combined multiplier = 0.70 × 0.80 = 0.56. Total reduction = 1 − 0.56 = 0.44 = 44%. The trap is adding 30% + 20% = 50%, which ignores that the second reduction applies to an already-reduced base.', true, 'trusted'),
  ('AR-PC-B3-12', 'AR', 'ar.percent', 5, 'A clothing store applies a 35% markup to all wholesale costs, then offers 20% off the marked-up price at clearance. A jacket''s clearance price is $86.40. What was the wholesale cost?', '["$72","$80","$88","$96"]'::jsonb, 1, 'Let W = wholesale. Marked-up = 1.35W. Clearance = 1.35W × 0.80 = 1.08W = $86.40. W = $86.40 ÷ 1.08 = $80. The trap is netting percents (35% − 20% = 15%) and dividing: $86.40 ÷ 1.15 ≈ $75.', true, 'trusted'),
  ('AR-PC-B3-13', 'AR', 'ar.percent', 5, 'A company''s revenue grew by 25% in Q1 and by 16% in Q2 relative to the Q1 ending revenue. If starting revenue was $80,000, what was the revenue at the end of Q2?', '["$103,200","$107,200","$112,800","$116,000"]'::jsonb, 3, 'After Q1: $80,000 × 1.25 = $100,000; after Q2: $100,000 × 1.16 = $116,000. Choice $103,200 applies 16% to the original $80,000 and stacks part of the Q1 gain incorrectly. Choice $107,200 applies the 16% growth to the original (giving $92,800) then adds 25% of $58,000, mixing bases. Choice $112,800 sums the rates additively (25% + 16% = 41%) and applies once: $80,000 × 1.41, the classic non-compounding trap.', true, 'trusted'),
  ('AR-PC-B3-14', 'AR', 'ar.percent', 4, 'A worker earns $160 per week. She receives a 25% raise. That same week she also earns a bonus equal to 12% of her new weekly wage. What is her total pay for that week?', '["$200","$212","$224","$236"]'::jsonb, 2, 'New weekly wage = $160 × 1.25 = $200. Bonus = 12% × $200 = $24. Total = $200 + $24 = $224. The trap is computing 12% of the original wage ($160 × 0.12 = $19.20) and adding to $200, giving $219.20.', true, 'trusted'),
  ('AR-RD-B3-1', 'AR', 'ar.rate-distance-time', 3, 'A car travels at 50 mph. How far does it travel in 3 hours?', '["100 miles","140 miles","150 miles","160 miles"]'::jsonb, 2, 'Distance = speed × time = 50 × 3 = 150 miles. Choice 100 miles uses 50 × 2, dropping an hour from the time. Choice 140 miles uses about 47 mph for 3 hours, rounding the speed down. Choice 160 miles uses about 53 mph for 3 hours, rounding the speed up by a few mph, or alternatively adds an extra 10-mile fudge to the correct answer.', true, 'trusted'),
  ('AR-RD-B3-2', 'AR', 'ar.rate-distance-time', 3, 'A cyclist rides at 15 mph. How far does she travel in 2 hours and 20 minutes?', '["30 miles","33 miles","35 miles","37 miles"]'::jsonb, 2, 'Convert 2 hr 20 min to 7/3 hours, then distance = 15 × 7/3 = 35 miles. Choice 30 miles drops the 20 minutes and uses 15 × 2 only. Choice 33 miles uses 2.2 hours, converting 20 minutes to 0.2 of an hour rather than the correct 1/3. Choice 37 miles uses 2.5 hours, rounding 20 minutes up to a half hour.', true, 'trusted'),
  ('AR-RD-B3-3', 'AR', 'ar.rate-distance-time', 3, 'A train travels 360 miles in 4 hours. At the same speed, how long will it take the train to travel 495 miles?', '["4.5 hours","5 hours","5.5 hours","6 hours"]'::jsonb, 2, 'Speed = 360 ÷ 4 = 90 mph, so time = 495 ÷ 90 = 5.5 hours at the same speed. Choice 4.5 hours uses about 110 mph (495/4.5), inflating the speed by 20 mph. Choice 5 hours uses 99 mph, rounding 90 up to 99 for a cleaner divisor against 495. Choice 6 hours uses about 82.5 mph, rounding the speed down to make the division simpler at the cost of accuracy.', true, 'trusted'),
  ('AR-RD-B3-4', 'AR', 'ar.rate-distance-time', 3, 'A plane flies 1,200 miles in 2.5 hours. What is the plane''s average speed?', '["400 mph","440 mph","460 mph","480 mph"]'::jsonb, 3, 'Speed = distance ÷ time = 1,200 ÷ 2.5 = 480 mph, the average speed for the flight. Choice 400 mph uses 3 hours instead of 2.5, rounding the time up by a half hour. Choice 440 mph divides by about 2.73, splitting the difference between 2.5 and 3 hours. Choice 460 mph uses about 2.6 hours, rounding the time up slightly to a friendlier denominator and pulling the answer down.', true, 'trusted'),
  ('AR-RD-B3-5', 'AR', 'ar.rate-distance-time', 4, 'Two runners start at the same point and run in opposite directions. Runner A runs at 7 mph and Runner B at 9 mph. After how many hours are they 64 miles apart?', '["3 hours","4 hours","5 hours","6 hours"]'::jsonb, 1, 'Combined separation rate = 7 + 9 = 16 mph. Time = 64 ÷ 16 = 4 hours. The trap is using only one runner''s speed (64 ÷ 7 ≈ 9 or 64 ÷ 9 ≈ 7).', true, 'trusted'),
  ('AR-RD-B3-6', 'AR', 'ar.rate-distance-time', 4, 'A supply convoy travels 120 miles to a base, makes a 45-minute stop, then returns over the same route. The convoy travels at 40 mph in both directions. What is the total elapsed time including the stop?', '["5 hours 45 minutes","6 hours 15 minutes","6 hours 45 minutes","7 hours"]'::jsonb, 2, 'One-way time = 120 ÷ 40 = 3 hours; round trip = 6 hours; plus the 0.75-hour stop = 6 hours 45 minutes. Choice 5 hours 45 minutes only counts one leg at 3 hours and the second leg at 2 hours, dropping driving time. Choice 6 hours 15 minutes treats the stop as 15 minutes instead of 45. Choice 7 hours rounds the 45-minute stop up to a full hour.', true, 'trusted'),
  ('AR-RD-B3-7', 'AR', 'ar.rate-distance-time', 4, 'Worker A can fill a storage bin in 6 hours; Worker B can fill the same bin in 4 hours. How long will it take them working together?', '["2 hours","2 hours 24 minutes","2 hours 48 minutes","3 hours"]'::jsonb, 1, 'Combined rate = 1/6 + 1/4 = 5/12 bins/hour, so time = 12/5 = 2 hours 24 minutes. Choice 2 hours assumes the team finishes in half of A''s time, ignoring B''s rate. Choice 2 hours 48 minutes adds rates wrong, perhaps 1/(6+4) × 2. Choice 3 hours averages 4 and 6 by halving the sum, the classic average-the-times trap that beginners always fall into.', true, 'trusted'),
  ('AR-RD-B3-8', 'AR', 'ar.rate-distance-time', 5, 'A drain empties a 900-gallon pool at 30 gallons per minute. A hose adds water at 12 gallons per minute. Both run simultaneously starting with the pool full. How many minutes until the pool is empty?', '["30 minutes","40 minutes","45 minutes","50 minutes"]'::jsonb, 3, 'Net drain rate = 30 − 12 = 18 gal/min, so time = 900 ÷ 18 = 50 minutes. Choice 30 minutes divides 900 by 30, using only the drain rate and ignoring the inflow. Choice 40 minutes uses about 22.5 gal/min net by miscomputing the rate difference. Choice 45 minutes uses 20 gal/min, rounding the net rate up by 2 to get a cleaner divisor.', true, 'trusted'),
  ('AR-RD-B3-9', 'AR', 'ar.rate-distance-time', 4, 'A soldier jogs to a checkpoint at 6 mph and walks back the same route at 4 mph. The total round trip takes 2.5 hours. How far away is the checkpoint?', '["4 miles","5 miles","6 miles","8 miles"]'::jsonb, 2, 'Let distance = d. Time equation: d/6 + d/4 = 2.5. LCD = 12: 2d/12 + 3d/12 = 5d/12 = 2.5. d = 2.5 × 12/5 = 6 miles. The trap is dividing 2.5 by the average speed (5 mph) to get 5 miles.', true, 'trusted'),
  ('AR-RD-B3-10', 'AR', 'ar.rate-distance-time', 5, 'A and B start from the same town at the same time. A heads north at 50 mph; B heads east at 120 mph. After how many hours is the straight-line distance between them exactly 130 miles?', '["1 hour","1.5 hours","2 hours","2.5 hours"]'::jsonb, 0, 'Distance after t hours = √((50t)² + (120t)²) = 130t (a 5-12-13 right triangle scaled by 10), so set 130t = 130 and t = 1 hour. Choice 1.5 hours adds the speeds (170 mph) and divides 130 ÷ 170 wrong. Choice 2 hours uses one convoy alone, treating motion as linear addition. Choice 2.5 hours averages the speeds and divides 130 by the average, ignoring the Pythagorean setup that perpendicular motion requires.', true, 'trusted'),
  ('AR-RD-B3-11', 'AR', 'ar.rate-distance-time', 5, 'Three painters working together: Painter 1''s rate is 1/6 of a fence per hour; Painter 2''s rate is 1/8 per hour; Painter 3''s rate is 1/12 per hour. How long does it take all three to paint the entire fence?', '["2 hours 10 minutes","2 hours 40 minutes","3 hours","3 hours 20 minutes"]'::jsonb, 1, 'Combined rate = 1/6 + 1/8 + 1/12 = 4/24 + 3/24 + 2/24 = 9/24 = 3/8 fence/hour, so time = 8/3 = 2 hours 40 minutes. Choice 2 hours 10 minutes adds only 1/6 + 1/8, ignoring Painter 3 entirely. Choice 3 hours rounds 8/3 down to 3. Choice 3 hours 20 minutes averages the three times (6 + 8 + 12)/3 ≈ 8.67 then trims, the classic average-the-times error.', true, 'trusted'),
  ('AR-RD-B3-12', 'AR', 'ar.rate-distance-time', 4, 'Car A leaves City X at 8:00 AM toward City Y at 60 mph. Car B leaves City Y at 9:00 AM toward City X at 90 mph. The cities are 210 miles apart. At what time do the cars meet?', '["9:30 AM","10:00 AM","10:30 AM","11:00 AM"]'::jsonb, 1, 'At 9:00 AM, Car A has covered 60 miles, leaving a 150-mile gap; closing rate after 9 AM = 60 + 90 = 150 mph, so time to close = 150 ÷ 150 = 1 hour, meeting at 10:00 AM. Choice 9:30 AM uses a 75-mile gap, dropping Car A''s hour of head start. Choice 10:30 AM closes 150 miles at 100 mph average. Choice 11:00 AM ignores the head start and divides 210/150 = 1.4 hours after 9 AM.', true, 'trusted'),
  ('AR-RD-B3-13', 'AR', 'ar.rate-distance-time', 3, 'A cargo ship travels 540 nautical miles at 18 knots, then returns the same distance at 12 knots. What is the total travel time for the round trip?', '["65 hours","70 hours","72 hours","75 hours"]'::jsonb, 3, 'Outbound = 540 ÷ 18 = 30 hours; return = 540 ÷ 12 = 45 hours; total = 30 + 45 = 75 hours. Choice 65 hours uses an average speed of about 16.6 knots over the full 1,080 miles. Choice 70 hours uses 15 knots over 1,080 miles, averaging the two speeds (18 + 12)/2, the classic harmonic-mean trap. Choice 72 hours uses 30 hours + 42 hours, miscomputing 540/12 as 42 instead of 45.', true, 'trusted'),
  ('AR-RD-B3-14', 'AR', 'ar.rate-distance-time', 5, 'A boat''s engine speed is 14 mph in still water. Traveling downstream with a 4 mph current, it covers 108 miles. How long does the trip take?', '["5 hours","6 hours","6.5 hours","7 hours"]'::jsonb, 1, 'Effective downstream speed = 14 + 4 = 18 mph, so time = 108 ÷ 18 = 6 hours. Choice 5 hours uses about 21.6 mph, adding the current twice on top of the engine speed. Choice 6.5 hours divides 108 by about 16.6 mph, splitting the current contribution in half. Choice 7 hours uses 108 ÷ 14, ignoring the current''s downstream boost entirely.', true, 'trusted'),
  ('AR-WP-B3-1', 'AR', 'ar.word-problems', 3, 'A box of 48 granola bars is divided equally among 6 hikers. Each hiker then gives 2 bars to a seventh hiker who arrived late. How many bars does the seventh hiker receive?', '["8","10","12","14"]'::jsonb, 2, 'Each of the 6 hikers gets 48 ÷ 6 = 8 bars, then gives 2 to the seventh, so the seventh receives 6 × 2 = 12 bars. Choice 8 reports the share each original hiker received. Choice 10 uses 48 ÷ 6 + 2, adding the 2 bars once instead of multiplying by six contributors. Choice 14 splits 48 ÷ 7 ≈ 7 then doubles, ignoring the rule that only six hikers contribute.', true, 'trusted'),
  ('AR-WP-B3-2', 'AR', 'ar.word-problems', 4, 'A gardener plants tomatoes in 5 rows with 12 plants each and peppers in 4 rows with 9 plants each. How many plants are there in total?', '["84","88","92","96"]'::jsonb, 3, 'Tomatoes = 5 × 12 = 60; peppers = 4 × 9 = 36; total = 60 + 36 = 96. Choice 84 uses 4 × 12 + 4 × 9, dropping a row of tomatoes. Choice 88 uses 5 × 12 + 4 × 7, miscomputing the pepper-per-row count. Choice 92 uses 5 × 12 + 4 × 8, miscounting peppers per row as 8 instead of 9, the closest near-miss on the trap path.', true, 'trusted'),
  ('AR-WP-B3-3', 'AR', 'ar.word-problems', 4, 'A jogger burns 8 calories per minute while running and 3 calories per minute while walking. She runs for 25 minutes and walks for 20 minutes. How many total calories does she burn?', '["240","260","280","300"]'::jsonb, 1, 'Total = (8 × 25) + (3 × 20) = 200 + 60 = 260. Choice 240 uses (8 × 20) + (4 × 20), swapping run minutes for walk minutes and bumping the walking rate. Choice 280 uses 11 × 25, summing the rates as 11 cal/min and applying to run time only. Choice 300 uses (8 × 30) + (3 × 20), inflating the run time by 5 minutes.', true, 'trusted'),
  ('AR-WP-B3-4', 'AR', 'ar.word-problems', 3, 'A merchant buys 60 items at $4 each and sells all of them at $7 each. What is his total profit?', '["$120","$150","$180","$210"]'::jsonb, 2, 'Profit per item = $7 − $4 = $3, then total profit = 60 × $3 = $180. Choice $120 uses $2 profit per item, miscomputing the price spread. Choice $150 uses 50 items × $3, dropping ten items from the inventory. Choice $210 uses 60 × $3.50, splitting the difference between cost and price as if the markup were halfway between them.', true, 'trusted'),
  ('AR-WP-B3-5', 'AR', 'ar.word-problems', 5, 'Three siblings split an inheritance. The eldest receives twice as much as the middle sibling, and the middle sibling receives three times as much as the youngest. If the youngest receives $4,200, what is the total inheritance?', '["$29,400","$33,600","$37,800","$42,000"]'::jsonb, 3, 'Youngest = $4,200. Middle = 3 × $4,200 = $12,600. Eldest = 2 × $12,600 = $25,200. Total = $4,200 + $12,600 + $25,200 = $42,000. The trap is computing eldest as 2 × youngest ($8,400) instead of 2 × middle.', true, 'trusted'),
  ('AR-WP-B3-6', 'AR', 'ar.word-problems', 4, 'A water tank is 3/4 full. After adding 240 gallons, the tank is 9/10 full. What is the total capacity of the tank in gallons?', '["1,200","1,500","1,600","2,000"]'::jsonb, 2, 'The 240 gallons fills the gap 9/10 − 3/4 = 18/20 − 15/20 = 3/20 of capacity, so capacity = 240 ÷ (3/20) = 240 × 20/3 = 1,600 gallons. Choice 1,200 treats 240 as 1/5 of capacity, miscomputing the fraction added. Choice 1,500 treats 240 as 4/25, near the right setup but with wrong subtraction. Choice 2,000 treats 240 as 3/25 of capacity, over-shrinking the added fraction.', true, 'trusted'),
  ('AR-WP-B3-7', 'AR', 'ar.word-problems', 4, 'A plumber charges $65 for the first hour and $45 for each additional hour, plus a flat $20 materials fee. If a job takes 4 hours total, what is the total bill?', '["$200","$220","$240","$280"]'::jsonb, 1, 'Bill = first hour + 3 additional hours + materials = $65 + 3 × $45 + $20 = $65 + $135 + $20 = $220. Choice $200 forgets the $20 materials fee. Choice $240 uses 4 × $45 + $20 + $40, treating the first hour at the same $45 rate. Choice $280 uses 4 × $65 + $20, charging the first-hour rate of $65 for all four hours.', true, 'trusted'),
  ('AR-WP-B3-8', 'AR', 'ar.word-problems', 5, 'A factory produces two products. Product X requires 3 labor-hours and $12 in materials per unit; Product Y requires 5 labor-hours and $8 in materials per unit. Labor costs $8 per hour. In one week, 20 units of X and 10 units of Y are produced. What is the total production cost?', '["$1,100","$1,200","$1,300","$1,400"]'::jsonb, 1, 'X cost per unit: 3 × $8 + $12 = $36. Y cost per unit: 5 × $8 + $8 = $48. Total = 20 × $36 + 10 × $48 = $720 + $480 = $1,200. The trap is multiplying all units by only the labor rate and forgetting materials: (20×3 + 10×5) × $8 = 110 × $8 = $880.', true, 'trusted'),
  ('AR-WP-B3-10', 'AR', 'ar.word-problems', 4, 'A bookshelf has 8 shelves, each holding 6 books. Currently, 3/4 of the shelves are completely full and the remaining shelves are empty. How many more books can the shelf unit hold?', '["6","8","10","12"]'::jsonb, 3, 'Empty shelves = 8 × (1 − 3/4) = 2; remaining capacity = 2 × 6 = 12 books. Choice 6 reports the capacity of just one shelf, treating only 1 shelf as empty. Choice 8 likely counts 2 empty shelves but multiplies by 4 books per shelf, miscounting capacity. Choice 10 uses 2 empty shelves × 5 books per shelf, dropping a book per shelf from the count.', true, 'trusted'),
  ('AR-WP-B3-11', 'AR', 'ar.word-problems', 5, 'A catering company charges $11 per adult and $7 per child. At an event, the number of adults is 3 times the number of children. The total bill is $1,200. How many children attended?', '["20","25","30","40"]'::jsonb, 2, 'Let c = children, adults = 3c, so total = 11(3c) + 7c = 40c = $1,200, giving c = 30. Choice 20 sets up 60c = $1,200, miscomputing the coefficient by adding rates flat. Choice 25 uses 48c, mixing adult and child rates with a wrong multiplier. Choice 40 ignores the 3:1 adult-to-child ratio and just divides $1,200 by an average price near $30, missing the structural relationship.', true, 'trusted'),
  ('AR-WP-B3-12', 'AR', 'ar.word-problems', 4, 'A bus leaves a depot every 20 minutes. A train leaves the same depot every 30 minutes. Both departed together at 6:00 AM. At what time will they next depart together?', '["6:40 AM","6:50 AM","7:00 AM","7:10 AM"]'::jsonb, 2, 'Next joint departure = LCM(20, 30) = 60 minutes after 6:00 AM, so 7:00 AM. Choice 6:40 AM picks 2 × 20 = 40 minutes, the bus''s second departure, but the train isn''t there yet. Choice 6:50 AM adds 20 + 30 = 50 minutes, treating the cycles as additive rather than a least common multiple. Choice 7:10 AM overshoots the LCM by 10 minutes, picking 70 minutes after start.', true, 'trusted'),
  ('AR-WP-B3-13', 'AR', 'ar.word-problems', 4, 'A soldier''s monthly budget is $2,400. He spends 1/3 on housing, 1/4 on food, and 1/6 on transportation. How much remains for other expenses?', '["$500","$600","$700","$800"]'::jsonb, 1, 'Spent fraction = 1/3 + 1/4 + 1/6 = 4/12 + 3/12 + 2/12 = 9/12 = 3/4, so remaining = 1/4 × $2,400 = $600. Choice $500 sums fractions wrong (perhaps 1/3 + 1/4 + 1/6 = 11/12), leaving 1/12 × $2,400 ≈ $200 plus a slip. Choice $700 mixes spending categories and reports a near-miss leftover. Choice $800 reports the housing amount alone instead of the leftover.', true, 'trusted'),
  ('AR-WP-B3-14', 'AR', 'ar.word-problems', 3, 'A fundraiser sells two types of tickets: regular at $8 and VIP at $20. They sell 150 regular tickets and 50 VIP tickets. What is the total revenue?', '["$1,800","$2,000","$2,200","$2,400"]'::jsonb, 2, 'Total = (150 × $8) + (50 × $20) = $1,200 + $1,000 = $2,200. Choice $1,800 uses (150 × $8) + (30 × $20), miscounting VIP tickets as 30 instead of 50. Choice $2,000 uses 200 tickets × $10 average, blending the two ticket prices into one. Choice $2,400 uses (200 × $12) average pricing, inflating the per-ticket value by a couple of dollars.', true, 'trusted'),
  ('MK-AL-B3-1', 'MK', 'mk.algebra-linear', 2, 'Solve for x: x + 14 = 30', '["x = 12","x = 14","x = 16","x = 18"]'::jsonb, 2, 'Subtract 14 from both sides to isolate x: x = 30 − 14 = 16. The choice x = 12 comes from subtracting 18 (a misread of 14). The choice x = 14 comes from copying the constant on the left side instead of solving. The choice x = 18 comes from subtracting 14 from a misread 32 or adding instead of subtracting somewhere in the chain.', true, 'trusted'),
  ('MK-AL-B3-2', 'MK', 'mk.algebra-linear', 3, 'Solve for x: 6x − 11 = 31', '["x = 5","x = 6","x = 7","x = 8"]'::jsonb, 2, 'Add 11 to both sides to clear the constant: 6x = 42. Divide by 6: x = 7. The choice x = 5 comes from subtracting 11 instead of adding, getting 6x = 20 and rounding 20÷6. The choice x = 6 comes from a slip that gives 6x = 36 (subtracting 5 instead of adding 11). The choice x = 8 comes from dividing 48 by 6, using 31 + 17 or 42 + 6 by mistake.', true, 'trusted'),
  ('MK-AL-B3-3', 'MK', 'mk.algebra-linear', 3, 'If y = 3x − 4 and x = 5, what is y?', '["7","9","11","13"]'::jsonb, 2, 'Substitute x = 5 into the formula. y = 3(5) − 4 = 15 − 4 = 11. Order of operations matters: multiply before subtracting. The choice 7 comes from subtracting first, computing 3(5 − 4) = 3. The choice 9 comes from computing 3(5) − 4 − 2 with a stray slip, or 5 + 4 = 9 (using the wrong operation entirely). The choice 13 comes from adding 4 instead of subtracting it.', true, 'trusted'),
  ('MK-AL-B3-4', 'MK', 'mk.algebra-linear', 3, 'If 3(2x − 4) = 24, what is x?', '["x = 4","x = 5","x = 6","x = 7"]'::jsonb, 2, 'Divide both sides by 3: 2x − 4 = 8. Add 4: 2x = 12. x = 6. The trap is skipping the division step and solving 2x − 4 = 24, giving x = 14.', true, 'trusted'),
  ('MK-AL-B3-5', 'MK', 'mk.algebra-linear', 4, 'Solve for y: 4y + 9 = 2y − 5', '["y = −7","y = −5","y = 2","y = 7"]'::jsonb, 0, 'Subtract 2y from both sides: 2y + 9 = −5. Subtract 9: 2y = −14. y = −7. The trap is adding the constants rather than subtracting: 2y = −5 + 9 = 4, giving y = 2.', true, 'trusted'),
  ('MK-AL-B3-6', 'MK', 'mk.algebra-linear', 4, 'Which value of x satisfies both inequalities: 2x > 6 AND x + 3 < 10?', '["x = 2","x = 3","x = 4","x = 8"]'::jsonb, 2, 'Solve each inequality. From 2x > 6, divide by 2: x > 3. From x + 3 < 10, subtract 3: x < 7. Combined range: 3 < x < 7. Only x = 4 lies strictly inside. The choice x = 2 fails the first inequality (2 is not greater than 3). The choice x = 3 fails the strict greater-than: x must exceed 3, not equal it. The choice x = 8 fails the second inequality (8 is not less than 7).', true, 'trusted'),
  ('MK-AL-B3-7', 'MK', 'mk.algebra-linear', 4, 'A number is 5 more than twice another number. Their sum is 29. What is the larger number?', '["17","19","21","23"]'::jsonb, 2, 'Let the smaller number be n. The larger is 2n + 5. Their sum is n + (2n + 5) = 29, so 3n = 24 and n = 8. The larger number is 2(8) + 5 = 21. The choice 17 comes from computing 2n + 1 instead of 2n + 5. The choice 19 comes from using n = 7 (off-by-one in the division). The choice 23 comes from solving for the smaller and adding 15 instead of 5, or by using n + 5 instead of 2n + 5.', true, 'trusted'),
  ('MK-AL-B3-8', 'MK', 'mk.algebra-linear', 4, 'Solve for x: (x/3) + 5 = 11', '["x = 12","x = 15","x = 18","x = 21"]'::jsonb, 2, 'Subtract 5 from both sides: x/3 = 6. Multiply both sides by 3: x = 18. The choice x = 12 comes from dividing 11 by something or treating x/3 as 3x and computing 3x = 6. The choice x = 15 comes from subtracting 5 from 11 to get 6, then multiplying by 2.5 by mistake, or computing 11 + 4. The choice x = 21 comes from adding 5 instead of subtracting (x/3 = 16) and rounding 16 × something.', true, 'trusted'),
  ('MK-AL-B3-9', 'MK', 'mk.algebra-linear', 5, 'If 2(3x − 1) = 5x + 4, what is x?', '["x = 4","x = 5","x = 6","x = 7"]'::jsonb, 2, 'Expand: 6x − 2 = 5x + 4. Subtract 5x: x − 2 = 4. x = 6. The trap is distributing 2 only to 3x (ignoring −1): 6x − 1 = 5x + 4, giving x = 5.', true, 'trusted'),
  ('MK-AL-B3-10', 'MK', 'mk.algebra-linear', 4, 'The sum of three consecutive odd integers is 57. What is the largest of the three integers?', '["17","19","21","23"]'::jsonb, 2, 'Consecutive odd integers differ by 2. Let them be n, n + 2, n + 4. Sum: 3n + 6 = 57, so 3n = 51 and n = 17. The largest is n + 4 = 21. Check: 17 + 19 + 21 = 57. The choice 17 returns the smallest integer instead of the largest. The choice 19 returns the middle integer. The choice 23 comes from using n + 6 as the largest (treating four integers instead of three).', true, 'trusted'),
  ('MK-AL-B3-11', 'MK', 'mk.algebra-linear', 5, 'Solve the system: 3x − y = 11 and x + y = 9. What is x + y?', '["5","7","8","9"]'::jsonb, 3, 'The second equation states x + y = 9 directly, so the answer is 9 without further work. To verify, add the equations to eliminate y: 4x = 20, so x = 5; then y = 4. Sum: 5 + 4 = 9. The choice 5 returns x alone. The choice 7 comes from averaging x and y or another mid-step value. The choice 8 comes from using x − y = 1 (the result of subtracting the equations) and pairing it with the wrong x.', true, 'trusted'),
  ('MK-AL-B3-12', 'MK', 'mk.algebra-linear', 5, 'A company rents vans at $40/day plus $0.25 per mile. An employee uses a van for 3 days and is charged $195 total. How many miles did she drive?', '["220 miles","260 miles","300 miles","340 miles"]'::jsonb, 2, 'Base cost = 3 × $40 = $120. Mileage charge = $195 − $120 = $75. Miles = $75 ÷ $0.25 = 300 miles. The trap is dividing the total by the per-mile rate without subtracting the daily fee: $195 ÷ $0.25 = 780.', true, 'trusted'),
  ('MK-FR-B3-1', 'MK', 'mk.fractions-decimals', 2, 'What is 1/2 + 1/4 + 1/8?', '["6/8","7/8","3/4","5/8"]'::jsonb, 1, 'Use a common denominator of 8. Convert: 1/2 = 4/8, 1/4 = 2/8, 1/8 = 1/8. Sum: 4/8 + 2/8 + 1/8 = 7/8. The choice 6/8 misses the final 1/8 (stops after 1/2 + 1/4 only). The choice 3/4 equals 6/8 in lowest terms, the same one-eighth-short error. The choice 5/8 comes from converting 1/2 as 2/8 instead of 4/8.', true, 'trusted'),
  ('MK-FR-B3-2', 'MK', 'mk.fractions-decimals', 3, 'What is 5/6 − 3/8?', '["11/24","7/24","2/3","1/2"]'::jsonb, 0, 'Find the LCD of 6 and 8, which is 24. Convert: 5/6 = 20/24 and 3/8 = 9/24. Subtract: 20/24 − 9/24 = 11/24. The choice 7/24 comes from converting 5/6 as 18/24 instead of 20/24 by mistake. The choice 2/3 comes from subtracting numerators and denominators directly: (5−3)/(6−8) = 2/(−2), which would give −1, then taking the absolute value and rewriting. The choice 1/2 comes from estimating 5/6 ≈ 0.83 and 3/8 ≈ 0.38 and reading the difference as 0.5 instead of 0.46.', true, 'trusted'),
  ('MK-FR-B3-3', 'MK', 'mk.fractions-decimals', 3, 'What is 1 3/4 × 2 2/3?', '["3 1/2","4 2/3","4 5/12","3 11/12"]'::jsonb, 1, 'Convert mixed numbers to improper fractions before multiplying. 1 3/4 = 7/4 and 2 2/3 = 8/3. Multiply: 7/4 × 8/3 = 56/12 = 14/3 = 4 2/3. The choice 3 1/2 comes from multiplying whole-number parts (1 × 2 = 2) and fractional parts (3/4 × 2/3 = 1/2) separately, missing the cross terms. The choice 4 5/12 comes from a partial cross-term sum. The choice 3 11/12 mixes mixed-number multiplication with addition of the fractional parts.', true, 'trusted'),
  ('MK-FR-B3-4', 'MK', 'mk.fractions-decimals', 3, 'Divide: (7/8) ÷ (7/4)', '["1/2","2","49/32","1/4"]'::jsonb, 0, 'Dividing by a fraction means multiplying by its reciprocal. (7/8) ÷ (7/4) = (7/8) × (4/7) = 28/56 = 1/2. The 7s cancel and 4/8 reduces to 1/2. The choice 2 comes from flipping the wrong fraction, computing (8/7) × (7/4) = 8/4 = 2. The choice 49/32 multiplies straight across without flipping: 7×7 over 8×4. The choice 1/4 comes from cancelling the 7s but mishandling 4/8 as 1/4.', true, 'trusted'),
  ('MK-FR-B3-5', 'MK', 'mk.fractions-decimals', 4, 'A recipe calls for 2 2/3 cups of oats and 1 3/4 cups of flour. What is the combined total of these two ingredients?', '["4 1/12 cups","4 5/12 cups","4 7/12 cups","5 cups"]'::jsonb, 1, 'Find a common denominator of 12 for the fractional parts. 2 2/3 = 2 8/12 and 1 3/4 = 1 9/12. Add whole parts and fractional parts: 3 + 17/12 = 3 + 1 5/12 = 4 5/12 cups. The choice 4 1/12 cups misses the carry from 17/12, treating it as 12/12 plus 1/12. The choice 4 7/12 cups comes from carrying twice (3 + 1 + 7/12) or converting one fraction incorrectly. The choice 5 cups rounds both mixed numbers up before adding.', true, 'trusted'),
  ('MK-FR-B3-6', 'MK', 'mk.fractions-decimals', 4, 'Convert 3/16 to a decimal.', '["0.1875","0.1975","0.3125","0.1667"]'::jsonb, 0, 'Divide 3 by 16 directly: 3 ÷ 16 = 0.1875. A shortcut: 1/16 = 0.0625, so 3 × 0.0625 = 0.1875. The choice 0.1975 is a small arithmetic slip on the long division. The choice 0.3125 is 5/16, the result of reading the numerator wrong. The choice 0.1667 is 1/6, the result of confusing 16 with 6 in the denominator.', true, 'trusted'),
  ('MK-FR-B3-7', 'MK', 'mk.fractions-decimals', 4, 'Which of the following represents the greatest value?', '["0.6̄  (= 0.6666…)","5/7","7/11","0.63"]'::jsonb, 1, 'Convert each to a decimal. 0.666… from the repeating 6. 5/7 ≈ 0.7143. 7/11 ≈ 0.6364. 0.63 is already a decimal. The largest is 5/7 at about 0.7143. The choice 0.666… looks large with the repeating bar but is smaller than 5/7. The choice 7/11 sits below both 0.666 and 5/7. The choice 0.63 is the smallest of the four.', true, 'trusted'),
  ('MK-FR-B3-8', 'MK', 'mk.fractions-decimals', 5, 'A plank 7 1/2 feet long is cut into pieces each 5/8 foot long. How many complete pieces can be cut?', '["10","11","12","13"]'::jsonb, 2, 'Convert 7 1/2 to an improper fraction: 15/2 feet. Divide by 5/8 by multiplying by the reciprocal: (15/2) × (8/5) = 120/10 = 12. Twelve complete 5/8-foot pieces fit. The choice 10 comes from a rough estimate (about 7.5 ÷ 0.75 instead of ÷ 0.625). The choice 11 comes from rounding down too aggressively or dropping an extra piece. The choice 13 comes from rounding up to count a partial piece, which the question excludes by saying "complete pieces."', true, 'trusted'),
  ('MK-FR-B3-9', 'MK', 'mk.fractions-decimals', 4, 'A runner completed 3/5 of a 15-mile race before stopping. After resting, she runs 2/3 of the remaining distance. How many miles does she still have left to run?', '["1 mile","2 miles","3 miles","4 miles"]'::jsonb, 1, 'First leg: 3/5 × 15 = 9 miles, leaving 15 − 9 = 6 miles. After resting, she runs 2/3 × 6 = 4 of those 6 miles. Still remaining: 6 − 4 = 2 miles. The choice 1 mile comes from taking 2/3 of the whole 15 minus 9 and slipping a calculation. The choice 3 miles takes 1/2 of the remaining 6 instead of 2/3, leaving 3. The choice 4 miles returns the distance she just ran (2/3 of 6), not what is left.', true, 'trusted'),
  ('MK-FR-B3-10', 'MK', 'mk.fractions-decimals', 5, 'If 2/3 of a number equals 1/2 of another number, and the first number is 24, what is the second number?', '["16","28","32","36"]'::jsonb, 2, 'Compute 2/3 of the first number: 2/3 × 24 = 16. Set this equal to 1/2 of the second: (1/2) × N = 16, so N = 32. The choice 16 is the shared value, not the second number; students stop one step early. The choice 28 comes from adding 24 + 4 or another off-target arithmetic step. The choice 36 comes from multiplying 24 by 3/2 instead of solving the half-equation, getting a number related to the first fraction rather than the second.', true, 'trusted'),
  ('MK-FR-B3-11', 'MK', 'mk.fractions-decimals', 4, 'Which of the following is equal to 0.41̄6̄ (= 0.41666…)?', '["5/12","5/11","4/9","3/7"]'::jsonb, 0, 'Test each fraction by long division. 5 ÷ 12 = 0.41666…, where the 6 repeats indefinitely, matching the target exactly. The choice 5/11 = 0.4545… is a trap of confusing two different repeating patterns; the early digits look similar but 11 in the denominator gives a 45-block, not a single repeating 6. The choice 4/9 = 0.4444… is the trap of assuming any fraction with a 4 in the tenths place must repeat 4; the denominator 9 always yields a single-digit repeat. The choice 3/7 = 0.42857… repeats but with a six-digit cycle, not the single digit 6 specified.', true, 'trusted'),
  ('MK-FR-B3-12', 'MK', 'mk.fractions-decimals', 5, 'A worker earns $22.50 per hour and works 37.5 hours in one week. Her employer withholds 28% of gross pay for taxes and deductions. What is her net pay for the week?', '["$607.50","$618.00","$632.25","$843.75"]'::jsonb, 0, 'Gross pay = $22.50 × 37.5 = $843.75. Withholding = 28% × $843.75 = $236.25. Net pay = $843.75 − $236.25 = $607.50. The trap is selecting $843.75 (gross) or computing withholding on $22.50 alone.', true, 'trusted'),
  ('MK-EP-B3-1', 'MK', 'mk.exponents-polynomials', 3, 'What is 3² + 2³?', '["10","13","17","19"]'::jsonb, 2, 'Evaluate each power, then add. 3² = 9 and 2³ = 8. Sum: 9 + 8 = 17. The choice 10 comes from computing 3² as 3×2 = 6 and 2³ as 2×3 = 6, then approximating (or from 9 + 1 slip). The choice 13 comes from computing 3² as 6 (multiplying the base by the exponent) and adding 8: 6 + 8 = 14, rounded to 13 with a slip. The choice 19 comes from computing 2³ as 10 by counting one too many factors, then 9 + 10.', true, 'trusted'),
  ('MK-EP-B3-2', 'MK', 'mk.exponents-polynomials', 3, 'Simplify: 5⁴ ÷ 5²', '["5¹","5²","5⁶","25²"]'::jsonb, 1, 'When dividing powers with the same base, subtract the exponents: 5⁴ ÷ 5² = 5^(4−2) = 5² = 25. The choice 5¹ subtracts the wrong direction (2 − 4 then flipped). The choice 5⁶ adds the exponents instead of subtracting, using the multiplication rule by mistake. The choice 25² = 625 in value and uses the wrong base by squaring 5 first; the exponent simplification asked for is 5², which equals 25.', true, 'trusted'),
  ('MK-EP-B3-3', 'MK', 'mk.exponents-polynomials', 3, 'What is the value of 2⁰ + 3¹ + 4²?', '["16","18","20","22"]'::jsonb, 2, 'Apply each exponent rule. Anything to the zero power equals 1, so 2⁰ = 1. Any number to the first power is itself, so 3¹ = 3. And 4² = 16. Sum: 1 + 3 + 16 = 20. The choice 16 ignores both 2⁰ and 3¹, returning only 4². The choice 18 comes from 2⁰ = 0 (a common error) plus 3 plus 15 (a misread of 4²). The choice 22 comes from 2⁰ = 2 plus 4 plus 16.', true, 'trusted'),
  ('MK-EP-B3-4', 'MK', 'mk.exponents-polynomials', 3, 'What is 10⁻²?', '["−100","−20","0.001","0.01"]'::jsonb, 3, 'A negative exponent means take the reciprocal of the positive-power version. 10⁻² = 1/10² = 1/100 = 0.01. The choice −100 reads the negative exponent as a negative sign on the result, treating it as −(10²). The choice −20 reads the exponent as a multiplier: −2 × 10. The choice 0.001 is 10⁻³, off by one decimal place from a counting error.', true, 'trusted'),
  ('MK-EP-B3-5', 'MK', 'mk.exponents-polynomials', 4, 'Expand and simplify: (2x − 3)²', '["4x² − 9","4x² − 12x + 9","4x² + 12x + 9","4x² − 6x + 9"]'::jsonb, 1, '(2x − 3)² = (2x)² − 2(2x)(3) + 3² = 4x² − 12x + 9. The most common trap is squaring each term individually: (2x)² + (−3)² = 4x² + 9, forgetting the middle term.', true, 'trusted'),
  ('MK-EP-B3-6', 'MK', 'mk.exponents-polynomials', 4, 'Simplify: (3a²b)(4ab³)', '["7a²b³","12a²b³","12a³b⁴","7a³b⁴"]'::jsonb, 2, 'Multiply coefficients: 3 × 4 = 12. Add a-exponents: 2 + 1 = 3. Add b-exponents: 1 + 3 = 4. Result: 12a³b⁴. The trap is adding coefficients instead of multiplying: 3 + 4 = 7.', true, 'trusted'),
  ('MK-EP-B3-7', 'MK', 'mk.exponents-polynomials', 4, 'Add the polynomials: (3x² − 2x + 5) + (x² + 4x − 3)', '["4x² + 2x + 2","4x² + 2x − 2","4x² − 2x + 2","3x² + 2x + 2"]'::jsonb, 0, 'Combine like terms by adding coefficients. x² terms: 3 + 1 = 4, giving 4x². x terms: −2 + 4 = 2, giving +2x. Constants: 5 + (−3) = 2. Result: 4x² + 2x + 2. The choice 4x² + 2x − 2 sign-flips the constants when combining (5 − 3 read as −2 by error). The choice 4x² − 2x + 2 keeps the original −2x and ignores +4x. The choice 3x² + 2x + 2 forgets to add the x² coefficients, copying the first polynomial''s 3x².', true, 'trusted'),
  ('MK-EP-B3-8', 'MK', 'mk.exponents-polynomials', 4, 'Factor completely: 2x² − 8', '["2(x − 2)(x − 2)","2(x + 2)(x − 2)","(2x + 4)(x − 2)","(x + 2)(2x − 4)"]'::jsonb, 1, 'Pull out the common factor of 2 first: 2(x² − 4). Then apply difference of squares to x² − 4 = (x + 2)(x − 2). Final: 2(x + 2)(x − 2). The choice 2(x − 2)(x − 2) factors as a perfect square instead of a difference of squares, losing the +2 factor. The choices (2x + 4)(x − 2) and (x + 2)(2x − 4) multiply back to the right expression but are not fully factored because each contains a common factor of 2 still inside a binomial.', true, 'trusted'),
  ('MK-EP-B3-9', 'MK', 'mk.exponents-polynomials', 5, 'Simplify: (x³y²)² ÷ (x²y)', '["x²y","x⁴y³","x⁴y²","x²y³"]'::jsonb, 1, 'Apply the power-of-a-power rule to the numerator: (x³y²)² = x⁶y⁴. Then divide by x²y by subtracting exponents: x^(6−2) y^(4−1) = x⁴y³. The choice x²y comes from subtracting exponents before squaring, applying the rules in the wrong order. The choice x⁴y² forgets to square y² to y⁴ in the numerator. The choice x²y³ has the y right but treats x as (x³)² = x⁵ minus x³, slipping the arithmetic.', true, 'trusted'),
  ('MK-EP-B3-10', 'MK', 'mk.exponents-polynomials', 5, 'Expand: (x + 3)(x² − 3x + 9)', '["x³ − 27","x³ + 27","x³ − 9x + 27","x³ + 9x² − 27"]'::jsonb, 1, 'This matches the sum-of-cubes pattern (a + b)(a² − ab + b²) = a³ + b³ with a = x and b = 3, giving x³ + 27. Direct expansion confirms: x(x² − 3x + 9) + 3(x² − 3x + 9) = x³ − 3x² + 9x + 3x² − 9x + 27 = x³ + 27. The choice x³ − 27 flips the sign, confusing it with difference of cubes. The choice x³ − 9x + 27 keeps the cross terms uncancelled. The choice x³ + 9x² − 27 distributes carelessly and inverts the constant sign.', true, 'trusted'),
  ('MK-EP-B3-11', 'MK', 'mk.exponents-polynomials', 4, 'Subtract and simplify: (5x² + 3x − 2) − (2x² − x + 4)', '["3x² + 4x − 6","3x² + 4x + 2","3x² + 2x − 6","7x² + 2x − 6"]'::jsonb, 0, 'Distribute the negative sign: 5x² + 3x − 2 − 2x² + x − 4 = 3x² + 4x − 6. The trap is forgetting to distribute the negative to all terms: treating −(−x) as −x instead of +x.', true, 'trusted'),
  ('MK-EP-B3-12', 'MK', 'mk.exponents-polynomials', 5, 'If x² − 5x + 6 = 0, what are the solutions?', '["x = 1 and x = 6","x = 2 and x = 3","x = −2 and x = −3","x = −1 and x = 6"]'::jsonb, 1, 'Factor: (x − 2)(x − 3) = 0. Solutions: x = 2 and x = 3. Verify: 4 − 10 + 6 = 0 ✓; 9 − 15 + 6 = 0 ✓. The trap is choosing negative values (x = −2 and −3) by confusing factoring sign rules.', true, 'trusted'),
  ('MK-GE-B3-1', 'MK', 'mk.geometry', 2, 'What is the area of a triangle with base 10 cm and height 6 cm?', '["30 cm²","40 cm²","60 cm²","120 cm²"]'::jsonb, 0, 'Area = (1/2) × base × height = (1/2) × 10 × 6 = 30 cm². The trap is omitting the 1/2 factor, giving 60 cm².', true, 'trusted'),
  ('MK-GE-B3-3', 'MK', 'mk.geometry', 3, 'A square has a side length of 13 cm. What is its perimeter?', '["36 cm","48 cm","52 cm","64 cm"]'::jsonb, 2, 'A square has four equal sides, so perimeter = 4s. P = 4 × 13 = 52 cm. The choice 36 cm comes from computing 13 + 13 + 10 with a slip, or using only three sides. The choice 48 cm comes from using s = 12 by mistake (4 × 12). The choice 64 cm comes from using s = 16, perhaps reading a 6 as a 3 in 13.', true, 'trusted'),
  ('MK-GE-B3-4', 'MK', 'mk.geometry', 4, 'A circular park has a circumference of 62.8 meters. What is its area in square meters? (Use π ≈ 3.14)', '["157 m²","200 m²","314 m²","628 m²"]'::jsonb, 2, 'C = 2πr = 62.8 → r = 62.8 ÷ 6.28 = 10 m. Area = πr² = 3.14 × 100 = 314 m². The trap is using the circumference directly as the area (628/2 = 314 coincidentally matches but using r = C/π = 20 instead of r = C/(2π) = 10 gives 4× the correct area).', true, 'trusted'),
  ('MK-GE-B3-5', 'MK', 'mk.geometry', 4, 'A rectangular swimming pool is 25 m long, 12 m wide, and 2 m deep. What is the volume of water needed to fill it completely?', '["300 m³","450 m³","600 m³","750 m³"]'::jsonb, 2, 'Volume of a rectangular prism is length × width × height. V = 25 × 12 × 2 = 600 m³. The choice 300 m³ omits the depth or divides by 2 (computing only the floor area times 1). The choice 450 m³ comes from arithmetic slips such as 25 × 12 = 300 plus 12 × 12 stitched together. The choice 750 m³ multiplies by 2.5 instead of 2, perhaps misreading the depth.', true, 'trusted'),
  ('MK-GE-B3-6', 'MK', 'mk.geometry', 4, 'A trapezoid has parallel sides of 10 cm and 14 cm, and a height of 8 cm. What is its area?', '["88 cm²","92 cm²","96 cm²","100 cm²"]'::jsonb, 2, 'Trapezoid area uses A = (1/2)(b₁ + b₂)h. Plug in: A = (1/2)(10 + 14)(8) = (1/2)(24)(8) = 96 cm². The choice 88 cm² comes from using a smaller sum (10 + 12 instead of 10 + 14) or dropping a unit. The choice 92 cm² comes from (1/2)(11 + 12)(8) or another mid-step slip. The choice 100 cm² comes from averaging the bases as 12 and multiplying by something close to 8.3.', true, 'trusted'),
  ('MK-GE-B3-7', 'MK', 'mk.geometry', 5, 'A right triangle has a hypotenuse of 17 cm and one leg of 8 cm. What is the area of the triangle?', '["45 cm²","60 cm²","68 cm²","75 cm²"]'::jsonb, 1, 'Find the missing leg with the Pythagorean theorem. leg = √(17² − 8²) = √(289 − 64) = √225 = 15 cm. This is the 8-15-17 Pythagorean triple. Area = (1/2)(8)(15) = 60 cm². The choice 45 cm² comes from using leg = 11 or another wrong value, or (1/2)(8)(11.25). The choice 68 cm² multiplies leg × hypotenuse × 1/2 = (1/2)(8)(17), using the hypotenuse instead of the other leg. The choice 75 cm² comes from √(289 + 64) = √353 and a small slip thereafter.', true, 'trusted'),
  ('MK-GE-B3-8', 'MK', 'mk.geometry', 5, 'Two similar triangles have corresponding sides in a ratio of 3:5. The area of the smaller triangle is 27 cm². What is the area of the larger triangle?', '["45 cm²","60 cm²","75 cm²","135 cm²"]'::jsonb, 2, 'Areas scale as the square of the linear ratio. Scale factor² = (5/3)² = 25/9. Larger area = 27 × 25/9 = 75 cm². The trap is applying the linear ratio: 27 × (5/3) = 45 cm².', true, 'trusted'),
  ('MK-GE-B3-9', 'MK', 'mk.geometry', 4, 'A cone has a radius of 6 cm and a slant height of 10 cm. What is the total surface area of the cone? (Use π ≈ 3.14)', '["263.76 cm²","301.44 cm²","376.8 cm²","414.48 cm²"]'::jsonb, 1, 'Lateral area = πrl = 3.14 × 6 × 10 = 188.4 cm². Base area = πr² = 3.14 × 36 = 113.04 cm². Total = 188.4 + 113.04 = 301.44 cm². The trap is computing only the lateral area (188.4) or using the slant height as the height in a volume formula.', true, 'trusted'),
  ('MK-GE-B3-10', 'MK', 'mk.geometry', 4, 'A rectangular garden 20 m long and 15 m wide is surrounded by a 2 m wide path. What is the area of the path alone?', '["148 m²","152 m²","156 m²","164 m²"]'::jsonb, 2, 'Outer rectangle: (20 + 4) × (15 + 4) = 24 × 19 = 456 m². Garden area = 20 × 15 = 300 m². Path area = 456 − 300 = 156 m². The trap is adding 2 (not 4) to each dimension, giving 22 × 17 = 374; 374 − 300 = 74.', true, 'trusted'),
  ('MK-GE-B3-11', 'MK', 'mk.geometry', 5, 'A sphere has a radius of 6 cm. What is its volume to the nearest whole number? (Use π ≈ 3.14)', '["452 cm³","678 cm³","754 cm³","904 cm³"]'::jsonb, 3, 'Volume = (4/3)πr³ = (4/3) × 3.14 × 216 = 4.186… × 216 ≈ 904 cm³. The trap is using the surface area formula 4πr² = 4 × 3.14 × 36 ≈ 452 cm² instead.', true, 'trusted'),
  ('MK-GE-B3-12', 'MK', 'mk.geometry', 3, 'A rectangular room is 14 feet long and 10 feet wide. What is its area?', '["120 sq ft","130 sq ft","140 sq ft","150 sq ft"]'::jsonb, 2, 'Rectangle area is length × width. A = 14 × 10 = 140 sq ft. The choice 120 sq ft comes from using 12 × 10 (misreading length). The choice 130 sq ft comes from 13 × 10, off by one in the length. The choice 150 sq ft comes from 15 × 10, off by one in the other direction. Adjacent integer slips are the classic trap when the multiplication itself is easy.', true, 'trusted'),
  ('MK-NP-B3-1', 'MK', 'mk.number-properties', 2, 'Which of the following is NOT a factor of 60?', '["8","12","15","20"]'::jsonb, 0, '60 ÷ 8 = 7.5 — not a whole number, so 8 is not a factor. 60 ÷ 12 = 5; 60 ÷ 15 = 4; 60 ÷ 20 = 3 — all are factors.', true, 'trusted'),
  ('MK-NP-B3-2', 'MK', 'mk.number-properties', 3, 'What is the LCM (least common multiple) of 8 and 12?', '["16","20","24","32"]'::jsonb, 2, 'Use prime factorization. 8 = 2³ and 12 = 2² × 3. LCM takes the highest power of each prime: 2³ × 3 = 24. Verify by listing multiples: 8, 16, 24 and 12, 24. The choice 16 is a multiple of 8 but not of 12. The choice 20 is a multiple of neither. The choice 32 is a multiple of 8 but not of 12; it comes from doubling 16 or multiplying 8 × 4 by mistake.', true, 'trusted'),
  ('MK-NP-B3-3', 'MK', 'mk.number-properties', 3, 'What is the GCF (greatest common factor) of 54 and 72?', '["6","9","12","18"]'::jsonb, 3, 'Prime factorize. 54 = 2 × 3³ and 72 = 2³ × 3². GCF takes the lowest power of each shared prime: 2¹ × 3² = 2 × 9 = 18. The choice 6 takes 2 × 3, missing one factor of 3. The choice 9 takes 3² but ignores the shared factor of 2. The choice 12 = 2² × 3 mixes the higher power of 2 (which only 72 has) with a missing factor of 3, so it is not a factor of 54.', true, 'trusted'),
  ('MK-NP-B3-4', 'MK', 'mk.number-properties', 3, 'Which of the following numbers is divisible by both 3 and 4?', '["34","42","48","50"]'::jsonb, 2, 'A number divisible by both 3 and 4 must be divisible by 12. Test: 48 ÷ 12 = 4, so 48 qualifies. Confirm: 48 ÷ 3 = 16 and 48 ÷ 4 = 12. The choice 34 is not divisible by 3 (3 + 4 = 7) or by 4 (34/4 = 8.5). The choice 42 is divisible by 3 but not by 4 (42/4 = 10.5). The choice 50 is divisible by neither (50/3 ≈ 16.67, 50/4 = 12.5).', true, 'trusted'),
  ('MK-NP-B3-5', 'MK', 'mk.number-properties', 4, 'What is the absolute value expression |−14| − |6 − 19|?', '["−1","0","1","27"]'::jsonb, 2, 'Evaluate each absolute value first. |−14| = 14. Inside the second bars: 6 − 19 = −13, so |−13| = 13. Subtract: 14 − 13 = 1. The choice −1 reverses the subtraction order, giving 13 − 14. The choice 0 comes from forgetting one of the absolute values and computing 14 − 14 or 13 − 13. The choice 27 ignores the absolute values entirely and treats them as parentheses, computing 14 + 13 by sign error.', true, 'trusted'),
  ('MK-NP-B3-6', 'MK', 'mk.number-properties', 4, 'How many prime numbers are between 20 and 40?', '["3","4","5","6"]'::jsonb, 1, 'List the candidates and rule out composites. 23 (prime), 25 = 5², 27 = 3³, 29 (prime), 31 (prime), 33 = 3 × 11, 35 = 5 × 7, 37 (prime), 39 = 3 × 13. That gives four primes: 23, 29, 31, 37. The choice 3 misses one of the four, often 37. The choice 5 wrongly counts 21, 27, or 33 as prime by skipping the divisibility-by-3 check. The choice 6 adds two non-primes to the list.', true, 'trusted'),
  ('MK-NP-B3-7', 'MK', 'mk.number-properties', 4, 'A number N is divisible by 4, by 9, and by 5. What is the smallest positive value of N?', '["60","90","120","180"]'::jsonb, 3, 'LCM(4, 9, 5): 4 = 2², 9 = 3², 5 = 5. LCM = 2² × 3² × 5 = 180. The trap is choosing 60 (LCM of 4 and 5 only) or 90 (LCM of 9 and 5 only, which is not divisible by 4).', true, 'trusted'),
  ('MK-NP-B3-8', 'MK', 'mk.number-properties', 4, 'When a positive integer n is divided by 7, the remainder is 4. What is the remainder when 3n is divided by 7?', '["1","2","3","5"]'::jsonb, 3, 'Write n = 7k + 4 for some integer k. Then 3n = 21k + 12 = 7(3k + 1) + 5. The remainder when 3n is divided by 7 is 5. Shortcut: multiply the remainder by 3 and reduce mod 7. 3 × 4 = 12, and 12 − 7 = 5. The choice 1 comes from 12 mod 7 read as 12 − 11. The choice 2 comes from 3 + 4 − 5 or another mid-step error. The choice 3 comes from forgetting to multiply by 3 and just returning that coefficient.', true, 'trusted'),
  ('MK-NP-B3-9', 'MK', 'mk.number-properties', 5, 'The product of two integers is −36 and their sum is −5. What are the two integers?', '["4 and −9","−4 and 9","3 and −12","6 and −6"]'::jsonb, 0, 'Negative product means one positive and one negative integer. Negative sum means the negative one has the larger absolute value. Test 4 and −9: product = −36, sum = −5. Both conditions check. The choice −4 and 9 has product −36 but sum +5, the sign-flipped version. The choice 3 and −12 has product −36 but sum −9, not −5. The choice 6 and −6 sums to 0 and has product −36, failing the sum condition.', true, 'trusted'),
  ('MK-NP-B3-10', 'MK', 'mk.number-properties', 4, 'If n is an even integer, which of the following expressions must also be even?', '["n² + 1","n² − n + 1","n² + n","n³ + 1"]'::jsonb, 2, 'If n is even, n² is even and n itself is even, so n² + n = n(n + 1) is even × anything = even. The choice n² + 1 is even + 1 = odd. The choice n² − n + 1 is even − even + 1 = odd. The choice n³ + 1 is even + 1 = odd. The trap on each wrong choice is adding 1 to an even quantity, which always flips parity to odd. Only n² + n avoids that flip.', true, 'trusted'),
  ('MK-NP-B3-11', 'MK', 'mk.number-properties', 5, 'A set of 5 integers has a mean of 8 and a range of 10. The smallest integer is 3. Which of the following could be the set?', '["{3, 6, 8, 11, 13}","{3, 7, 8, 9, 13}","{3, 8, 9, 10, 13}","{3, 5, 8, 10, 13}"]'::jsonb, 1, 'Two constraints must both hold. Range = max − min = 10 with min = 3 forces max = 13. Mean = 8 with five integers forces sum = 40. Test choice B: 3 + 7 + 8 + 9 + 13 = 40 and max − min = 10. Both pass. Choice A sums to 41 (mean fails). Choice C sums to 43 (mean fails). Choice D sums to 39 (mean fails). Many test-takers stop after confirming the range and ignore the sum, picking the first set with 3 and 13 as endpoints.', true, 'trusted'),
  ('MK-NP-B3-12', 'MK', 'mk.number-properties', 4, 'Which statement is true about (−3)⁴?', '["It equals −81","It equals 81","It equals −12","It is undefined"]'::jsonb, 1, 'Parentheses include the negative sign in the base. (−3)⁴ = (−3)(−3)(−3)(−3). Pair up: (−3)(−3) = 9 and (−3)(−3) = 9, so 9 × 9 = 81. An even exponent on any real base produces a non-negative result. The choice −81 confuses (−3)⁴ with −(3⁴) = −81, leaving the negative outside the parentheses. The choice −12 reads the exponent as a multiplier (−3 × 4). The choice "undefined" treats negative bases with even exponents as invalid, which is incorrect for integer exponents.', true, 'trusted'),
  ('WK-SN-B4-1', 'WK', 'wk.synonyms', 1, 'BRAVE most nearly means:', '["cowardly","courageous","careless","clever"]'::jsonb, 1, 'Brave means ready to face danger or pain without showing fear, as in ''the brave firefighter ran into the burning house.'' Cowardly is the direct antonym, naming fear and avoidance. Careless is a register trap, since brave people may take risks, but bravery involves accepting fear deliberately while carelessness ignores risk through inattention. Clever names quick intelligence, a separate trait that does not require courage. Courageous is the dominant synonym, sharing the willingness to face fear directly in the service of action.', true, 'trusted'),
  ('WK-SN-B4-2', 'WK', 'wk.synonyms', 1, 'RAPID most nearly means:', '["slow","loud","fast","heavy"]'::jsonb, 2, 'Rapid means happening or moving quickly, as in ''the rapid current carried the raft downstream in minutes.'' Slow is the direct antonym. Loud names volume, an unrelated sensory dimension. Heavy is a register trap drawing on the force of fast-moving objects, but weight has no necessary connection to speed. Fast is the dominant synonym, sharing both the motion and the brief-time-frame senses of rapid. The two words are interchangeable in most contexts, which makes Fast the clearest match.', true, 'trusted'),
  ('WK-SN-B4-4', 'WK', 'wk.synonyms', 2, 'GREGARIOUS most nearly means:', '["shy","talkative and sociable","aggressive","hardworking"]'::jsonb, 1, 'Gregarious means fond of the company of others, as in ''the gregarious sergeant spent every weekend hosting cookouts for the platoon.'' The root GREG- means flock or herd (congregate, segregate). Shy is the direct antonym, naming social withdrawal. Aggressive is a register trap: gregarious people seek company but not conflict; aggression is about hostility, not affection for groups. Hardworking is unrelated to sociability and names a different dimension of personality. Only Talkative and sociable captures the core meaning of group-loving.', true, 'trusted'),
  ('WK-SN-B4-5', 'WK', 'wk.synonyms', 2, 'INDOLENT most nearly means:', '["energetic","rude","lazy","independent"]'::jsonb, 2, 'Indolent means habitually avoiding work, as in ''the indolent clerk left every task for the next shift.'' Energetic is the direct antonym. Rude is the spelling-confusion trap: indolent looks one letter off from insolent (disrespectful), but the two words differ by an N and have unrelated meanings. Independent is a register trap, since independent people choose to act on their own while indolent people simply do not act. Lazy is the dominant synonym, sharing the persistent avoidance of effort.', true, 'trusted'),
  ('WK-SN-B4-6', 'WK', 'wk.synonyms', 3, 'LACONIC most nearly means:', '["wordy","brief in speech","humorous","secretive"]'::jsonb, 1, 'Laconic means using very few words, as in ''his laconic ''roger that'' was the only acknowledgment we got.'' The word comes from Laconia (Sparta), whose soldiers were famous for terse replies. Wordy is the direct antonym. Humorous is a register trap: laconic speech can be dryly funny but humor is not part of the definition. Secretive is a partial-overlap trap, since terse people may seem to withhold, but laconic speech is short rather than evasive. Brief in speech is the dominant synonym.', false, 'draft'),
  ('WK-SN-B4-7', 'WK', 'wk.synonyms', 3, 'MITIGATE most nearly means:', '["worsen","lessen or reduce","eliminate","conceal"]'::jsonb, 1, 'Mitigate means to make something less severe or painful, as in ''sandbags mitigated the flood damage but did not stop it.'' Worsen is the direct antonym. Conceal names hiding, a different action that does not change severity. Eliminate is the closest distractor and the most important false friend: eliminate means to remove entirely, while mitigate means only to reduce. A test-taker picking Eliminate has overshot the strength of the word. Only Lessen or reduce captures the partial-reduction sense that defines mitigate.', true, 'trusted'),
  ('WK-SN-B4-8', 'WK', 'wk.synonyms', 3, 'OSTRACIZE most nearly means:', '["welcome","exclude from a group","punish physically","deceive"]'::jsonb, 1, 'Ostracize means to deliberately exclude someone from a group, as in ''the team ostracized the recruit who broke ranks.'' The word comes from ancient Athens, where citizens voted to banish individuals by writing names on shards (ostraka). Welcome is the direct antonym. Punish physically is a register trap, since ostracism is a social punishment, not a corporal one. Deceive is unrelated; exclusion is open, not hidden. Only Exclude from a group captures the deliberate social removal at the heart of the word.', true, 'trusted'),
  ('WK-SN-B4-9', 'WK', 'wk.synonyms', 4, 'ASSIDUOUS most nearly means:', '["negligent","diligent","gregarious","audacious"]'::jsonb, 1, 'Assiduous means showing constant and careful attention to a task, as in ''her assiduous note-taking filled three notebooks by midterm.'' The Latin root ASSID- (to sit at, attend to) gives the sense of sitting with the work until it is done. Negligent is the direct antonym, naming the lack of careful attention. Gregarious describes someone who enjoys the company of others, a personality trait unrelated to work habits. Audacious names a willingness to take bold risks, which speaks to an attitude toward danger rather than effort. Only diligent captures the steady, attentive effort that defines assiduous.', true, 'trusted'),
  ('WK-SN-B4-10', 'WK', 'wk.synonyms', 4, 'PROSAIC most nearly means:', '["poetic","dull and unimaginative","precise","aggressive"]'::jsonb, 1, 'Prosaic means commonplace and lacking imagination, as in ''his prosaic explanation drained the magic from the story.'' The word comes from prose (ordinary writing) as opposed to poetry. Poetic is essentially the antonym, naming the elevated and imaginative quality prosaic lacks. Precise is a register trap, since prosaic writing can be precise but lacks creative spark; precision is about accuracy, not imagination. Aggressive is unrelated to creativity or style. Only Dull and unimaginative captures the commonplace, uninspired quality at the heart of prosaic.', true, 'trusted'),
  ('WK-SN-B4-11', 'WK', 'wk.synonyms', 4, 'VENERATE most nearly means:', '["criticize","regard with deep respect","imitate","investigate"]'::jsonb, 1, 'Venerate means to regard with deep respect, often because of age, wisdom, or sacred status, as in ''the cadets venerated the retired general.'' From Latin venerari, to worship. Criticize is the direct antonym. Imitate is a partial-overlap trap, since respected figures are often imitated, but admiration and copying are separate acts. Investigate is a register trap, drawing on the careful attention venerate requires, but investigating implies skeptical inquiry, the opposite of reverence. Only Regard with deep respect captures the reverent quality of venerate.', true, 'trusted'),
  ('WK-SN-B4-12', 'WK', 'wk.synonyms', 5, 'ERSATZ most nearly means:', '["authentic","an inferior substitute","elaborate","traditional"]'::jsonb, 1, 'Ersatz means used as an inferior substitute, as in ''the ersatz coffee made from chicory was the only option during the shortage.'' From German Ersatz (replacement), applied to wartime stand-ins. Authentic is the direct antonym, naming the genuine article. Elaborate is a register trap, drawing on the sound of the word, but ersatz things are usually plain and basic, not ornate. Traditional names long-standing customs, a separate concept that does not imply inferiority or substitution. Only An inferior substitute carries both the replacement and the lower-quality senses.', true, 'trusted'),
  ('WK-SN-B4-13', 'WK', 'wk.synonyms', 5, 'FATUOUS most nearly means:', '["insightful","complacently stupid","cautious","withdrawn"]'::jsonb, 1, 'Fatuous means smugly foolish, as in ''his fatuous comment that war is easy made the veterans walk out.'' From Latin fatuus, silly. Insightful is the direct antonym, naming intelligent perception. Cautious is a register trap, since fatuous people are often unwisely bold, but caution is about risk-avoidance, not intelligence. Withdrawn describes social manner, not the foolish-self-satisfaction core of fatuous. The spelling-confusion trap with fatigued (tired) catches some test-takers, but the words share only the first two letters and come from different Latin roots. Only Complacently stupid fits.', true, 'trusted'),
  ('WK-CTX-B4-1', 'WK', 'wk.context-clues', 1, 'In the sentence ''The child was ELATED when she learned she had won the spelling bee,'' the word ELATED most nearly means:', '["frightened","very happy","surprised","tired"]'::jsonb, 1, 'Winning a spelling bee pins the meaning to strong positive emotion. Elated specifically labels intense joy. ''Frightened'' is the direct opposite of a celebratory reaction. ''Surprised'' is plausible vocabulary-wise, since unexpected wins do surprise, but the sentence frames the moment as celebratory rather than astonished. ''Tired'' could follow a long competition but does not match the focus on learning she won. Only Very happy matches the celebratory frame the spelling-bee win establishes.', true, 'trusted'),
  ('WK-CTX-B4-2', 'WK', 'wk.context-clues', 1, 'In the sentence ''The sun was SCORCHING, so we moved into the shade to cool down,'' the word SCORCHING most nearly means:', '["mild","extremely hot","cloudy","distant"]'::jsonb, 1, 'Moving into the shade specifically to cool down pins the meaning to extreme heat. Scorching specifically labels burning hot conditions. ''Mild'' is the direct opposite of the response the sentence describes. ''Cloudy'' addresses sky cover, not temperature, and the move to shade would not make sense under clouds. ''Distant'' is a register trap, since the sun is literally distant, but the sentence rates how the sun felt that day, not its astronomical position. Only Extremely hot matches the cool-down evidence.', true, 'trusted'),
  ('WK-CTX-B4-3', 'WK', 'wk.context-clues', 2, 'In the sentence ''She spoke with such CANDOR that even her critics respected her honesty,'' the word CANDOR most nearly means:', '["arrogance","frankness","caution","authority"]'::jsonb, 1, 'Candor means the quality of being open and honest. ''Respected her honesty'' is the direct context clue. Arrogance and authority might earn respect in other contexts, but the passage ties the respect explicitly to honesty.', true, 'trusted'),
  ('WK-CTX-B4-4', 'WK', 'wk.context-clues', 2, 'In the sentence ''The DILATORY contractor missed three deadlines, forcing the base commander to find a new vendor,'' the word DILATORY most nearly means:', '["expensive","slow to act or chronically late","dishonest","inexperienced"]'::jsonb, 1, 'Three missed deadlines forcing the commander to find a new vendor pins the meaning to chronic lateness. Dilatory specifically labels persistent delay. ''Expensive'' addresses cost, which the sentence never raises. ''Dishonest'' is plausible vocabulary-wise for a fired contractor, but the sentence faults schedule failures, not deception. ''Inexperienced'' could explain missed deadlines but names the cause rather than the behavior itself, and the sentence describes how the contractor acted. Only Slow to act or chronically late matches the missed-deadline evidence directly.', true, 'trusted'),
  ('WK-CTX-B4-6', 'WK', 'wk.context-clues', 3, 'In the sentence ''The recruit FLOUTED every regulation he disagreed with, earning himself extra duty each week,'' the word FLOUTED most nearly means:', '["followed carefully","openly disregarded","misunderstood","reported"]'::jsonb, 1, 'Earning extra duty each week by ignoring regulations he disagreed with pins the meaning to deliberate, open rule-breaking. Flouted specifically labels open contempt for rules. ''Followed carefully'' is the direct opposite. ''Misunderstood'' is plausible vocabulary-wise, but the consequence of extra duty repeating weekly signals intent, not error. ''Reported'' would describe turning others in, not breaking rules himself. The classic spelling-confusion trap is flout versus flaunt (to display showily), but the meanings are unrelated despite the similar sound. Only Openly disregarded matches.', true, 'trusted'),
  ('WK-CTX-B4-7', 'WK', 'wk.context-clues', 3, 'In the sentence ''The speaker''s TRENCHANT analysis cut through the confusion and identified the problem within minutes,'' the word TRENCHANT most nearly means:', '["lengthy and detailed","incisive and vigorous","calm and measured","unexpected"]'::jsonb, 1, 'The phrase ''cut through the confusion and identified the problem within minutes'' pins the meaning to sharp and effective analysis. Trenchant specifically labels vigorous, incisive thinking that cuts to the point. ''Lengthy and detailed'' is the opposite of the speed and decisiveness the sentence praises. ''Calm and measured'' addresses tone but trenchant carries force, not just composure. ''Unexpected'' is a register trap that draws on dramatic flair, but trenchant names the cutting quality itself, not surprise. Only Incisive and vigorous matches the cut-through-confusion image.', true, 'trusted'),
  ('WK-CTX-B4-8', 'WK', 'wk.context-clues', 4, 'In the sentence ''Her SAGACIOUS decision to stockpile medical supplies before the hurricane proved correct when the storm knocked out supply lines for two weeks,'' the word SAGACIOUS most nearly means:', '["lucky and fortunate","having keen practical wisdom","reckless and impulsive","conservative and reluctant"]'::jsonb, 1, 'Stockpiling supplies before the storm, then being vindicated by a two-week outage, pins the meaning to deliberate foresight. Sagacious specifically labels keen practical wisdom. ''Lucky and fortunate'' is the trickiest distractor since outcomes matched expectations, but the sentence emphasizes the decision was made beforehand, which signals planning rather than chance. ''Reckless and impulsive'' is the opposite of careful preparation. ''Conservative and reluctant'' describes hesitation, while the decision was decisive action. Only Having keen practical wisdom captures the prescient judgment shown.', true, 'trusted'),
  ('WK-CTX-B4-9', 'WK', 'wk.context-clues', 4, 'In the sentence ''The sergeant REPUDIATED the accusations against his unit, producing records that showed the team had followed every protocol,'' the word REPUDIATED most nearly means:', '["quietly accepted","firmly rejected","investigated","summarized"]'::jsonb, 1, 'Producing records to disprove accusations pins the meaning to firm, evidence-backed denial. Repudiated specifically labels formal, decisive rejection. ''Quietly accepted'' is the direct opposite of producing counter-evidence. ''Investigated'' is the trickiest distractor since gathering records can look like investigation, but the sentence describes presenting findings against the claims, not opening an inquiry. ''Summarized'' addresses condensing information rather than rejecting accusations. Only Firmly rejected matches the disprove-with-evidence behavior the sentence describes.', true, 'trusted'),
  ('WK-CTX-B4-10', 'WK', 'wk.context-clues', 4, 'In the sentence ''Despite owning a popular restaurant, the chef lived FRUGALLY, driving an old car and rarely buying new clothes,'' the word FRUGALLY most nearly means:', '["lavishly","in a thrifty manner","with great caution","in an isolated way"]'::jsonb, 1, 'Owning a popular restaurant yet driving an old car and rarely buying new clothes pins the meaning to deliberate thrift despite means. Frugally specifically labels careful, sparing spending. ''Lavishly'' is the direct opposite. ''With great caution'' is plausible (cautious spenders save), but caution focuses on risk avoidance while frugality focuses on minimizing expense regardless of risk. ''In an isolated way'' addresses social life, which the sentence never raises. Only In a thrifty manner captures the chosen modesty of consumption despite a popular business.', true, 'trusted'),
  ('WK-CTX-B4-11', 'WK', 'wk.context-clues', 5, 'In the sentence ''The diplomat''s LACONIC cable — three words where others would have written three pages — conveyed the mission''s outcome without ambiguity,'' the word LACONIC most nearly means:', '["cryptically coded","using very few words","overly detailed","formally worded"]'::jsonb, 1, 'The contrast ''three words where others would have written three pages'' pins the meaning to extreme brevity. Laconic specifically labels speech or writing of very few words. ''Cryptically coded'' is the trickiest distractor since a three-word cable sounds mysterious, but the sentence specifies the cable conveyed the outcome ''without ambiguity,'' ruling out obscurity. ''Overly detailed'' is the direct opposite. ''Formally worded'' addresses tone rather than length, and the sentence rewards length specifically. Only Using very few words matches the numerical contrast.', true, 'trusted'),
  ('WK-CTX-B4-12', 'WK', 'wk.context-clues', 5, 'In the sentence ''The documentary portrayed the era with UNFLINCHING candor, showing the poverty and discrimination that official histories had glossed over for decades,'' the word UNFLINCHING most nearly means:', '["sympathetic","refusing to shy away from difficult truths","politically motivated","technically accurate"]'::jsonb, 1, 'Unflinching means not showing fear or hesitation in the face of something difficult or distressing. ''Official histories had glossed over'' contrasts with the documentary''s refusal to avoid uncomfortable realities. Sympathetic describes feeling, not the courage to depict truth.', true, 'trusted'),
  ('WK-PFX-B4-1', 'WK', 'wk.prefixes-suffixes', 1, 'The prefix UN- means not. Based on this, UNHAPPY most nearly means:', '["very happy","not happy","somewhat happy","formerly happy"]'::jsonb, 1, 'UNHAPPY breaks down as UN- (not) plus HAPPY. The UN- prefix simply negates the base word, as in unfair (not fair), unclear (not clear), unkind (not kind). ''Very happy'' would require an intensifier like SUPER- or HYPER-, not UN-. ''Somewhat happy'' would require a diminisher like SEMI- or SUB-, not UN-, which is absolute negation. ''Formerly happy'' would require EX- (former, as in ex-soldier) or PRE- (before). Only Not happy tracks the simple negating function of UN-.', true, 'trusted'),
  ('WK-PFX-B4-2', 'WK', 'wk.prefixes-suffixes', 1, 'The suffix -FUL means full of or having. Based on this, CAREFUL most nearly means:', '["without care","full of care and attention","able to be cared for","beyond care"]'::jsonb, 1, 'CAREFUL breaks down as CARE plus -FUL (full of, characterized by). The -FUL suffix adds the meaning ''having a lot of,'' as in hopeful (full of hope), peaceful (full of peace), beautiful (full of beauty). ''Without care'' would require -LESS, the opposite suffix (careless). ''Able to be cared for'' would require -ABLE, which signals capability rather than abundance. ''Beyond care'' has no standard prefix or suffix for that meaning in English. Only Full of care and attention tracks the standard -FUL function.', true, 'trusted'),
  ('WK-PFX-B4-3', 'WK', 'wk.prefixes-suffixes', 2, 'The prefix PRE- means before. Based on this, PRECAUTION most nearly means:', '["an action taken after the fact","an action taken in advance to prevent harm","a warning given loudly","a rule set by authorities"]'::jsonb, 1, 'PRECAUTION breaks down as PRE- (before) plus CAUTION (carefulness), literally caution taken in advance. Compare preview (see before), predict (say before), prevent (come before to stop). ''An action taken after the fact'' would require POST- (after), the direct opposite prefix. ''A warning given loudly'' addresses volume and audience, which PRE- does not encode. ''A rule set by authorities'' addresses source, not timing, and would not require PRE-. Only An action taken in advance to prevent harm tracks PRE- correctly with CAUTION.', true, 'trusted'),
  ('WK-PFX-B4-4', 'WK', 'wk.prefixes-suffixes', 2, 'The suffix -LESS means without. Based on this, RECKLESS most nearly means:', '["very careful","without caution","full of energy","beyond control"]'::jsonb, 1, 'RECKLESS breaks down as RECK (old English for care or heed) plus -LESS (without). Compare careless (without care), helpless (without help), fearless (without fear). ''Very careful'' is the direct opposite of the meaning -LESS produces. ''Full of energy'' confuses -LESS with -FUL, the opposite suffix; reckless people may be energetic but the word itself names the absence of caution, not the presence of energy. ''Beyond control'' addresses degree rather than absence, and -LESS specifically encodes absence. Only Without caution tracks the morphology.', true, 'trusted'),
  ('WK-PFX-B4-5', 'WK', 'wk.prefixes-suffixes', 3, 'The prefix MIS- means wrongly or badly. The word MISCONSTRUE therefore most nearly means:', '["to build incorrectly","to interpret wrongly","to communicate clearly","to confuse deliberately"]'::jsonb, 1, 'MISCONSTRUE breaks down as MIS- (wrongly) plus CONSTRUE (to interpret). Compare misjudge (judge wrongly), misread (read wrongly), misunderstand (understand wrongly). ''To build incorrectly'' confuses CONSTRUE with CONSTRUCT. Both trace back to the same Latin verb construere (to put together), but in modern English construct kept the physical-assembly sense while construe shifted to mean parsing meaning, so misconstrue is about reading not building. ''To communicate clearly'' is the opposite of what MIS- produces. ''To confuse deliberately'' would require an intent prefix; MIS- only signals that the interpretation came out wrong, not that deception was intended.', true, 'trusted'),
  ('WK-PFX-B4-6', 'WK', 'wk.prefixes-suffixes', 3, 'The prefix INTER- means between or among. Based on this, INTERLUDE most nearly means:', '["a final performance","a period between two events","an opening ceremony","a conflict between parties"]'::jsonb, 1, 'INTERLUDE breaks down as INTER- (between) plus LUDE (from Latin ludere, to play), literally a small play or pause between two larger events. Compare international (between nations), intermission (pause between acts), interstate (between states). ''A final performance'' would require POST- (after) or FIN- (end), not INTER-. ''An opening ceremony'' would require PRE- (before) or INTRO- (into the start), not INTER-. ''A conflict between parties'' uses INTER- correctly but does not match LUDE (play); a conflict would be INTERVENE or INTERPLAY in a hostile sense. Only A period between two events fits.', true, 'trusted'),
  ('WK-PFX-B4-7', 'WK', 'wk.prefixes-suffixes', 3, 'The suffix -MENT turns a verb into a noun indicating result or process. DEPLOYMENT therefore most nearly means:', '["the ability to deploy","the act or result of deploying","one who deploys","worthy of being deployed"]'::jsonb, 1, 'DEPLOYMENT breaks down as DEPLOY (verb) plus -MENT (suffix forming a noun of action or result). Compare manage to management, develop to development, achieve to achievement. ''The ability to deploy'' would require -ABLE or -ITY (deployability), not -MENT. ''One who deploys'' would require -ER or -OR (deployer), the agent suffix. ''Worthy of being deployed'' would require -ABLE (deployable, worthy of deployment), the capability suffix. Only The act or result of deploying tracks the -MENT noun-forming function.', true, 'trusted'),
  ('WK-PFX-B4-8', 'WK', 'wk.prefixes-suffixes', 4, 'The prefix COUNTER- means against or in opposition to. Based on this, COUNTERINTUITIVE most nearly means:', '["supporting common sense","going against what one would naturally expect","requiring careful thought","relating to military counter-operations"]'::jsonb, 1, 'COUNTERINTUITIVE breaks down as COUNTER- (against, opposite) plus INTUITIVE (based on instinct). Compare counterclockwise (opposite of clockwise), counteract (act against), counterargument (argument against). ''Supporting common sense'' is the direct opposite. ''Requiring careful thought'' is a register trap, since counterintuitive ideas often demand careful thought to accept, but the word names the conflict with instinct, not the cognitive effort. ''Relating to military counter-operations'' reads COUNTER- as the military noun rather than the prefix, a category error. Only Going against what one would naturally expect fits.', true, 'trusted'),
  ('WK-PFX-B4-10', 'WK', 'wk.prefixes-suffixes', 4, 'The prefix SUB- means under or below. SUBVERT most nearly means:', '["to support from beneath","to secretly undermine or overthrow","to move below ground level","to speak quietly"]'::jsonb, 1, 'SUB- means under; VERT comes from Latin vertere (to turn). Subvert means to turn under — i.e., to undermine or overturn an established system from within. ''Support from beneath'' misreads sub- as physically supporting rather than undermining.', true, 'trusted'),
  ('WK-PFX-B4-11', 'WK', 'wk.prefixes-suffixes', 5, 'The prefix EPI- means upon or in addition to. EPILOGUE most nearly means:', '["an introduction written before the main text","a section added at the end of a literary work","a chapter inserted in the middle","an index of key terms"]'::jsonb, 1, 'EPI- means upon or after; -LOGUE means speech or writing. An epilogue is a section added after the main work. PRO-logue is the introduction; EPI- places the content after, not before. An index is a reference tool, not a narrative addition.', true, 'trusted'),
  ('WK-PFX-B4-12', 'WK', 'wk.prefixes-suffixes', 5, 'The suffix -CIDE means the act of killing. Based on this, HERBICIDE is best defined as:', '["a plant-based medicine","a substance that kills plants","a device for cutting vegetation","a chemical that promotes plant growth"]'::jsonb, 1, 'HERB means plant; -CIDE means act of killing. Herbicide is a substance used to kill plants (usually unwanted ones). Promoting growth would be the opposite. A cutting device would be a tool, not a chemical. The -CIDE suffix also appears in insecticide (kills insects) and germicide (kills germs).', true, 'trusted'),
  ('WK-ROOT-B4-1', 'WK', 'wk.root-words', 1, 'The root VIS appears in VISIBLE, VISION, and VISUAL. VIS most nearly means:', '["to move","to see","to speak","to know"]'::jsonb, 1, 'VIS comes from Latin videre, to see. Cognates include visible (able to be seen), vision (the sense or act of sight), visual (relating to sight), visit (originally, to go see), and television (seeing at a distance). ''To move'' would use MOV- or MOT- (motion, mobile), different roots. ''To speak'' would use DICT- (dictate) or LOQU- (eloquent), commonly confused with VIS- only by general association. ''To know'' would use SCI- (science) or COGN- (cognition, recognize). Only To see fits all the listed cognates.', true, 'trusted'),
  ('WK-ROOT-B4-2', 'WK', 'wk.root-words', 1, 'The root PORT appears in TRANSPORT, PORTABLE, and EXPORT. PORT most nearly means:', '["to make","to carry","to open","to place"]'::jsonb, 1, 'PORT comes from Latin portare, to carry. Portable means able to be carried; transport means to carry across; export means to carry out. Do not confuse with port (harbor) — the root is about carrying, not water.', true, 'trusted'),
  ('WK-ROOT-B4-3', 'WK', 'wk.root-words', 2, 'The root CRED appears in CREDIBLE, CREDIT, and INCREDULOUS. CRED most nearly means:', '["to judge","to believe","to know","to value"]'::jsonb, 1, 'CRED comes from Latin credere, to believe. Cognates include credible (believable), credit (trust extended), incredulous (unwilling to believe), creed (a statement of beliefs), and credentials (proof that warrants trust). ''To judge'' would use JUDIC- (judicial, prejudice), an adjacent legal root that test-takers sometimes mix with CRED- because both touch courtroom contexts. ''To know'' would use SCI- or COGN-, separate roots. ''To value'' would use VAL- (value, valor), also separate. Only To believe matches all the cognates.', true, 'trusted'),
  ('WK-ROOT-B4-4', 'WK', 'wk.root-words', 2, 'The root DICT appears in DICTATE, PREDICT, and CONTRADICT. DICT most nearly means:', '["to write","to say or speak","to lead","to order by force"]'::jsonb, 1, 'DICT comes from Latin dicere, to say. Cognates include dictate (say aloud for recording), predict (say before), contradict (say against), edict (an official saying), and dictionary (a book of word sayings). ''To write'' would use SCRIB or SCRIPT (scribble, manuscript, prescription), an easy confusion since saying and writing pair so often in school. ''To lead'' would use DUC (conduct, induce), a different root. ''To order by force'' would use IMPER- (imperative, emperor); a dictator orders but the DICT root names the saying, not the force. Only To say or speak fits.', true, 'trusted'),
  ('WK-ROOT-B4-5', 'WK', 'wk.root-words', 3, 'The root BENE appears in BENEFIT, BENEFACTOR, and BENEVOLENT. BENE most nearly means:', '["great","good or well","many","before"]'::jsonb, 1, 'BENE comes from Latin meaning good or well. Cognates include benefit (a good outcome), benefactor (one who does good), benevolent (well-wishing), benediction (a blessing or good saying), and benign (kind or harmless). ''Great'' would use MAGN- (magnificent, magnify), commonly confused since ''great'' and ''good'' overlap in casual praise. ''Many'' would use MULTI- (multiple, multitude), a separate root. ''Before'' would use PRE- or ANTE-, also separate. Only Good or well matches BENE- across the listed cognates.', true, 'trusted'),
  ('WK-ROOT-B4-6', 'WK', 'wk.root-words', 3, 'The root GREG appears in GREGARIOUS, CONGREGATE, and SEGREGATE. GREG most nearly means:', '["to speak","a flock or group","a leader","a law"]'::jsonb, 1, 'GREG comes from Latin grex/gregis, meaning flock or herd. Cognates include gregarious (fond of the flock, sociable), congregate (gather as a flock), segregate (separate from the flock), and egregious (originally, standing out from the flock, now negative). ''To speak'' would use DICT- or LOQU-, separate roots. ''A leader'' would use DUC- (duke, conduct) or PRINC- (prince), since a leader heads the flock but is not the flock itself. ''A law'' would use LEG- (legal, legislation). Only A flock or group matches GREG across cognates.', true, 'trusted'),
  ('WK-ROOT-B4-7', 'WK', 'wk.root-words', 3, 'The root PATH appears in EMPATHY, SYMPATHY, and PATHETIC. PATH most nearly means:', '["thought or reason","suffering or feeling","motion or movement","disease only"]'::jsonb, 1, 'PATH comes from Greek pathos, meaning suffering or feeling. Empathy is feeling into another''s experience; sympathy is feeling alongside someone; pathetic originally meant arousing pity. Disease is a modern narrowing of the medical use (pathology), but the root broadly means feeling.', true, 'trusted'),
  ('WK-ROOT-B4-8', 'WK', 'wk.root-words', 4, 'The root TRACT appears in EXTRACT, CONTRACT, and RETRACT. TRACT most nearly means:', '["to push","to pull or draw","to hold","to cut"]'::jsonb, 1, 'TRACT comes from Latin trahere, to pull or drag. Cognates include extract (pull out), retract (pull back), contract (pull together, draw closer), traction (the grip that allows pulling), and tractor (a pulling machine). ''To push'' would use PULS- or PEL- (propel, expel), the literal opposite root. ''To hold'' would use TEN- (tenacious, retain) or HABE- (habit, inhibit). ''To cut'' would use CIS- or SECT- (incision, dissect). Only To pull or draw fits the cognate set, with push as the most tempting wrong answer because it shares the directional-force frame.', true, 'trusted'),
  ('WK-ROOT-B4-9', 'WK', 'wk.root-words', 4, 'The root PEND appears in PENDING, SUSPEND, and APPENDIX. PEND most nearly means:', '["to send","to hang or be uncertain","to write","to add weight"]'::jsonb, 1, 'PEND comes from Latin pendere, to hang. Pending means hanging (unresolved); suspend means to hang up or halt; appendix hangs from the main body of text. ''Add weight'' is a trap — although appended items extend a document, the root captures the hanging quality.', true, 'trusted'),
  ('WK-ROOT-B4-10', 'WK', 'wk.root-words', 4, 'The root VOC appears in INVOKE, VOCALIZE, and IRREVOCABLE. VOCA/VOC most nearly means:', '["to see","to feel","to call or voice","to rule"]'::jsonb, 2, 'VOC comes from Latin vocare, to call. Cognates include invoke (call upon), vocalize (give voice to), irrevocable (unable to be called back), advocate (one who calls in support), provoke (call forth a reaction), and vocation (a calling). ''To see'' would use VIS- (vision, visible), a separate root that learners sometimes confuse with VOC- because both involve sensory output. ''To feel'' would use SENT or SENS (sentiment, sensory). ''To rule'' would use REG or RECT (regal, direct). Only To call or voice fits the cognates.', true, 'trusted'),
  ('WK-ROOT-B4-11', 'WK', 'wk.root-words', 5, 'The root CIDE appears in INCISION, DECIDE, and PRECISE. The root CIDE/CIS most nearly means:', '["to fall","to cut","to go","to bind"]'::jsonb, 1, 'CIS/CIDE comes from Latin caedere, to cut. Incision is a cut; decide means to cut off (other options); precise means cut off exactly. Do not confuse with -CIDE (killer) which derives from caedere in a different sense. To fall is CAD/CAS; to go is it; to bind is LIG.', true, 'trusted'),
  ('WK-ROOT-B4-12', 'WK', 'wk.root-words', 5, 'The root PLAC appears in PLACATE, COMPLACENT, and IMPLACABLE. PLAC most nearly means:', '["to please or calm","to place or position","to promise","to fill"]'::jsonb, 0, 'PLAC comes from Latin placare, to please or appease. Cognates include placate (calm someone down), complacent (self-satisfied, pleased with oneself to excess), implacable (impossible to appease), placid (calm), and placebo (literally ''I shall please''). ''To place or position'' is the most tempting wrong answer because of the visual similarity, but it comes from a different Latin root (ponere/positum), so PLACE and PLACATE only look related. ''To promise'' would use PROMIS- or SPONS-. ''To fill'' would use PLE- (replete, plenary). Only To please or calm fits.', true, 'trusted'),
  ('PC-MI-B4-1', 'PC', 'pc.main-idea', 1, 'Read the passage below and answer the question.

"Drinking enough water each day is important for good health. Water helps regulate body temperature, carries nutrients to cells, and removes waste from the body. Most adults should drink at least eight glasses of water per day."

